INSERT INTO public.exercises (id, name, muscle_group, tier, focus, cue, rationale, equipment, image) VALUES
  ('00000000-0000-0000-0000-000000000000', '3/4 Sit-Up', 'Core', 'S', 'Strength', 'Lie down on the floor and secure your feet. Your legs should be bent at the knees.', 'Place your hands behind or to the side of your head. You will begin with your back on the ground. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/3_4_Sit-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000001', '90/90 Hamstring', 'Legs', 'B', 'Stretching', 'Lie on your back, with one leg extended straight out.', 'With the other leg, bend the hip and knee to 90 degrees. You may brace your leg with your hands if necessary. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/90_90_Hamstring/0.jpg'),
  ('00000000-0000-0000-0000-000000000002', 'Ab Crunch Machine', 'Core', 'B', 'Strength', 'Select a light resistance and sit down on the ab machine placing your feet under the pads provided and grabbing the top handles. Your arms should be bent at a 90 degree angle as you rest the triceps on the pads provided. This will be your starting position.', 'At the same time, begin to lift the legs up as you crunch your upper torso. Breathe out as you perform this movement. Tip: Be sure to use a slow and controlled motion. Concentrate on using your abs to move the weight while relaxing your legs and feet.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ab_Crunch_Machine/0.jpg'),
  ('00000000-0000-0000-0000-000000000003', 'Ab Roller', 'Core', 'A', 'Strength', 'Hold the Ab Roller with both hands and kneel on the floor.', 'Now place the ab roller on the floor in front of you so that you are on all your hands and knees (as in a kneeling push up position). This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ab_Roller/0.jpg'),
  ('00000000-0000-0000-0000-000000000004', 'Adductor', 'Legs', 'B', 'Stretching', 'Lie face down with one leg on a foam roll.', 'Rotate the leg so that the foam roll contacts against your inner thigh. Shift as much weight onto the foam roll as can be tolerated.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Adductor/0.jpg'),
  ('00000000-0000-0000-0000-000000000005', 'Adductor/Groin', 'Legs', 'S', 'Stretching', 'Lie on your back with your feet raised towards the ceiling.', 'Have your partner hold your feet or ankles. Abduct your legs as far as you can. This will be your starting position.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Adductor_Groin/0.jpg'),
  ('00000000-0000-0000-0000-000000000006', 'Advanced Kettlebell Windmill', 'Core', 'A', 'Strength', 'Clean and press a kettlebell overhead with one arm.', 'Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Keep the non-working arm behind your back and turn your feet out at a forty-five degree angle from the arm with the kettlebell.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Advanced_Kettlebell_Windmill/0.jpg'),
  ('00000000-0000-0000-0000-000000000007', 'Air Bike', 'Core', 'B', 'Strength', 'Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put your hands beside your head. Be careful however to not strain with the neck as you perform it. Now lift your shoulders into the crunch position.', 'Bring knees up to where they are perpendicular to the floor, with your lower legs parallel to the floor. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Air_Bike/0.jpg'),
  ('00000000-0000-0000-0000-000000000008', 'All Fours Quad Stretch', 'Legs', 'B', 'Stretching', 'Start off on your hands and knees, then lift your leg off the floor and hold the foot with your hand.', 'Use your hand to hold the foot or ankle, keeping the knee fully flexed, stretching the quadriceps and hip flexors.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/All_Fours_Quad_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000009', 'Alternate Hammer Curl', 'Arms', 'A', 'Strength', 'Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.', 'The palms of the hands should be facing your torso. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Hammer_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000010', 'Alternate Heel Touchers', 'Core', 'S', 'Strength', 'Lie on the floor with the knees bent and the feet on the floor around 18-24 inches apart. Your arms should be extended by your side. This will be your starting position.', 'Crunch over your torso forward and up about 3-4 inches to the right side and touch your right heel as you hold the contraction for a second. Exhale while performing this movement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Heel_Touchers/0.jpg'),
  ('00000000-0000-0000-0000-000000000011', 'Alternate Incline Dumbbell Curl', 'Arms', 'B', 'Strength', 'Sit down on an incline bench with a dumbbell in each hand being held at arms length. Tip: Keep the elbows close to the torso.This will be your starting position.', 'While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. As you do so, rotate the hand so that the palm is facing up. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Incline_Dumbbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000012', 'Alternate Leg Diagonal Bound', 'Legs', 'A', 'Plyometrics', 'Assume a comfortable stance with one foot slightly in front of the other.', 'Begin by pushing off with the front leg, driving the opposite knee forward and as high as possible before landing. Attempt to cover as much distance to each side with each bound.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Leg_Diagonal_Bound/0.jpg'),
  ('00000000-0000-0000-0000-000000000013', 'Alternating Cable Shoulder Press', 'Shoulders', 'B', 'Strength', 'Move the cables to the bottom of the tower and select an appropriate weight.', 'Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Cable_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000014', 'Alternating Deltoid Raise', 'Shoulders', 'B', 'Strength', 'In a standing position, hold a pair of dumbbells at your side.', 'Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Deltoid_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000015', 'Alternating Floor Press', 'Chest', 'S', 'Strength', 'Lie on the floor with two kettlebells next to your shoulders.', 'Position one in place on your chest and then the other, gripping the kettlebells on the handle with the palms facing forward.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Floor_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000016', 'Alternating Hang Clean', 'Legs', 'B', 'Strength', 'Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.', 'Clean one kettlebell to your shoulder and hold on to the other kettlebell in a hanging position. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Hang_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000017', 'Alternating Kettlebell Press', 'Shoulders', 'B', 'Strength', 'Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so.', 'Press one directly overhead by extending through the elbow, turning it so the palm faces forward while holding the other kettlebell stationary .', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Kettlebell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000018', 'Alternating Kettlebell Row', 'Back', 'A', 'Strength', 'Place two kettlebells in front of your feet. Bend your knees slightly and push your butt out as much as possible. As you bend over to get into the starting position grab both kettlebells by the handles.', 'Pull one kettlebell off of the floor while holding on to the other kettlebell. Retract the shoulder blade of the working side, as you flex the elbow, drawing the kettlebell towards your stomach or rib cage.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Kettlebell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000019', 'Alternating Renegade Row', 'Back', 'B', 'Strength', 'Place two kettlebells on the floor about shoulder width apart. Position yourself on your toes and your hands as though you were doing a pushup, with the body straight and extended. Use the handles of the kettlebells to support your upper body. You may need to position your feet wide for support.', 'Push one kettlebell into the floor and row the other kettlebell, retracting the shoulder blade of the working side as you flex the elbow, pulling it to your side.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Renegade_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000020', 'Ankle Circles', 'Legs', 'S', 'Stretching', 'Use a sturdy object like a squat rack to hold yourself.', 'Lift the right leg in the air (just around 2 inches from the floor) and perform a circular motion with the big toe. Pretend that you are drawing a big circle with it. Tip: One circle equals 1 repetition. Breathe normally as you perform the movement.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ankle_Circles/0.jpg'),
  ('00000000-0000-0000-0000-000000000021', 'Ankle On The Knee', 'Legs', 'A', 'Stretching', 'From a lying position, bend your knees and keep your feet on the floor.', 'Place your ankle of one foot on your opposite knee.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ankle_On_The_Knee/0.jpg'),
  ('00000000-0000-0000-0000-000000000022', 'Anterior Tibialis-SMR', 'Legs', 'B', 'Stretching', 'Begin seated on the ground with your legs bent and your feet on the floor.', 'Using a Muscle Roller or a rolling pin, apply pressure to the muscles on the outside of your shins. Work from just below the knee to above the ankle, pausing at points of tension for 10-30 seconds. Repeat on the other leg.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Anterior_Tibialis-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000023', 'Anti-Gravity Press', 'Shoulders', 'B', 'Strength', 'Place a bar on the ground behind the head of an incline bench.', 'Lay on the bench face down. With a pronated grip, pick the barbell up from the floor. Flex the elbows, performing a reverse curl to bring the bar near your chest. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Anti-Gravity_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000024', 'Arm Circles', 'Shoulders', 'A', 'Stretching', 'Stand up and extend your arms straight out by the sides. The arms should be parallel to the floor and perpendicular (90-degree angle) to your torso. This will be your starting position.', 'Slowly start to make circles of about 1 foot in diameter with each outstretched arm. Breathe normally as you perform the movement.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Arm_Circles/0.jpg'),
  ('00000000-0000-0000-0000-000000000025', 'Arnold Dumbbell Press', 'Shoulders', 'S', 'Strength', 'Sit on an exercise bench with back support and hold two dumbbells in front of you at about upper chest level with your palms facing your body and your elbows bent. Tip: Your arms should be next to your torso. The starting position should look like the contracted portion of a dumbbell curl.', 'Now to perform the movement, raise the dumbbells as you rotate the palms of your hands until they are facing forward.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Arnold_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000026', 'Around The Worlds', 'Chest', 'B', 'Strength', 'Lay down on a flat bench holding a dumbbell in each hand with the palms of the hands facing towards the ceiling. Tip: Your arms should be parallel to the floor and next to your thighs. To avoid injury, make sure that you keep your elbows slightly bent. This will be your starting position.', 'Now move the dumbbells by creating a semi-circle as you displace them from the initial position to over the head. All of the movement should happen with the arms parallel to the floor at all times. Breathe in as you perform this portion of the movement.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Around_The_Worlds/0.jpg'),
  ('00000000-0000-0000-0000-000000000027', 'Atlas Stone Trainer', 'Back', 'A', 'Strongman', 'This trainer is effective for developing Atlas Stone strength for those who don''t have access to stones, and are typically made from bar ends or heavy pipe.', 'Begin by loading the desired weight onto the bar. Straddle the weight, wrapping your arms around the implement, bending at the hips.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Atlas_Stone_Trainer/0.jpg'),
  ('00000000-0000-0000-0000-000000000028', 'Atlas Stones', 'Back', 'B', 'Strongman', 'Begin with the atlas stone between your feet. Bend at the hips to wrap your arms vertically around the Atlas Stone, attempting to get your fingers underneath the stone. Many stones will have a small flat portion on the bottom, which will make the stone easier to hold.', 'Pulling the stone into your torso, drive through the back half of your feet to pull the stone from the ground.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Atlas_Stones/0.jpg'),
  ('00000000-0000-0000-0000-000000000029', 'Axle Deadlift', 'Back', 'B', 'Strongman', 'Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an over/under grip.', 'With your feet and your grip set, take a big breath and then lower your hips and flex the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Axle_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000030', 'Back Flyes - With Bands', 'Shoulders', 'S', 'Strength', 'Run a band around a stationary post like that of a squat rack.', 'Grab the band by the handles and stand back so that the tension in the band rises.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Back_Flyes_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000031', 'Backward Drag', 'Legs', 'B', 'Strongman', 'Load a sled with the desired weight, attaching a rope or straps to the sled that you can hold onto.', 'Begin the exercise by moving backwards for a given distance. Leaning back, extend through the legs for short steps to move as quickly as possible.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Backward_Drag/0.jpg'),
  ('00000000-0000-0000-0000-000000000032', 'Backward Medicine Ball Throw', 'Shoulders', 'B', 'Plyometrics', 'This exercise is best done with a partner. If you lack a partner, the ball can be thrown and retrieved or thrown against a wall.', 'Begin standing a few meters in front of your partner, both facing the same direction. Begin holding the ball between your legs.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Backward_Medicine_Ball_Throw/0.jpg'),
  ('00000000-0000-0000-0000-000000000033', 'Balance Board', 'Legs', 'A', 'Strength', 'Place a balance board in front of you.', 'Stand up on it and try to balance yourself.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Balance_Board/0.jpg'),
  ('00000000-0000-0000-0000-000000000034', 'Ball Leg Curl', 'Legs', 'B', 'Strength', 'Begin on the floor laying on your back with your feet on top of the ball.', 'Position the ball so that when your legs are extended your ankles are on top of the ball. This will be your starting position.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ball_Leg_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000035', 'Band Assisted Pull-Up', 'Back', 'S', 'Strength', 'Choke the band around the center of the pullup bar. You can use different bands to provide varying levels of assistance.', 'Pull the end of the band down, and place one bent knee into the loop, ensuring it won''t slip out. Take a medium to wide grip on the bar. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Assisted_Pull-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000036', 'Band Good Morning', 'Legs', 'A', 'Powerlifting', 'Using a 41 inch band, stand on one end, spreading your feet a small amount. Bend at the hips to loop the end of the band behind your neck. This will be your starting position.', 'Keeping your legs straight, extend through the hips to come to a near vertical position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Good_Morning/0.jpg'),
  ('00000000-0000-0000-0000-000000000037', 'Band Good Morning (Pull Through)', 'Legs', 'B', 'Powerlifting', 'Loop the band around a post. Standing a little ways away, loop the opposite end around the neck. Your hands can help hold the band in position.', 'Begin by bending at the hips, getting your butt back as far as possible. Keep your back flat and bend forward to about 90 degrees. Your knees should be only slightly bent.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Good_Morning_Pull_Through/0.jpg'),
  ('00000000-0000-0000-0000-000000000038', 'Band Hip Adductions', 'Legs', 'B', 'Strength', 'Anchor a band around a solid post or other object.', 'Stand with your left side to the post, and put your right foot through the band, getting it around the ankle.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Hip_Adductions/0.jpg'),
  ('00000000-0000-0000-0000-000000000039', 'Band Pull Apart', 'Shoulders', 'A', 'Strength', 'Begin with your arms extended straight out in front of you, holding the band with both hands.', 'Initiate the movement by performing a reverse fly motion, moving your hands out laterally to your sides.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Pull_Apart/0.jpg'),
  ('00000000-0000-0000-0000-000000000040', 'Band Skull Crusher', 'Arms', 'S', 'Strength', 'Secure a band to the base of a rack or the bench. Lay on the bench so that the band is lined up with your head.', 'Take hold of the band, raising your elbows so that the upper arm is perpendicular to the floor. With the elbow flexed, the band should be above your head. This will be your starting position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Band_Skull_Crusher/0.jpg'),
  ('00000000-0000-0000-0000-000000000041', 'Barbell Ab Rollout', 'Core', 'B', 'Strength', 'For this exercise you will need to get into a pushup position, but instead of having your hands of the floor, you will be grabbing on to an Olympic barbell (loaded with 5-10 lbs on each side) instead. This will be your starting position.', 'While keeping a slight arch on your back, lift your hips and roll the barbell towards your feet as you exhale. Tip: As you perform the movement, your glutes should be coming up, you should be keeping the abs tight and should maintain your back posture at all times. Also your arms should be staying perpendicular to the floor throughout the movement. If you don''t, you will work out your shoulders and back more than the abs.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Ab_Rollout/0.jpg'),
  ('00000000-0000-0000-0000-000000000042', 'Barbell Ab Rollout - On Knees', 'Core', 'A', 'Strength', 'Hold an Olympic barbell loaded with 5-10lbs on each side and kneel on the floor.', 'Now place the barbell on the floor in front of you so that you are on all your hands and knees (as in a kneeling push up position). This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Ab_Rollout_-_On_Knees/0.jpg'),
  ('00000000-0000-0000-0000-000000000043', 'Barbell Bench Press - Medium Grip', 'Chest', 'B', 'Strength', 'Lie back on a flat bench. Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.', 'From the starting position, breathe in and begin coming down slowly until the bar touches your middle chest.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Bench_Press_-_Medium_Grip/0.jpg'),
  ('00000000-0000-0000-0000-000000000044', 'Barbell Curl', 'Arms', 'B', 'Strength', 'Stand up with your torso upright while holding a barbell at a shoulder-width grip. The palm of your hands should be facing forward and the elbows should be close to the torso. This will be your starting position.', 'While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000045', 'Barbell Curls Lying Against An Incline', 'Arms', 'S', 'Strength', 'Lie against an incline bench, with your arms holding a barbell and hanging down in a horizontal line. This will be your starting position.', 'While keeping the upper arms stationary, curl the weight up as high as you can while squeezing the biceps. Breathe out as you perform this portion of the movement. Tip: Only the forearms should move. Do not swing the arms.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Curls_Lying_Against_An_Incline/0.jpg'),
  ('00000000-0000-0000-0000-000000000046', 'Barbell Deadlift', 'Back', 'B', 'Strength', 'Stand in front of a loaded barbell.', 'While keeping the back as straight as possible, bend your knees, bend forward and grasp the bar using a medium (shoulder width) overhand grip. This will be the starting position of the exercise. Tip: If it is difficult to hold on to the bar with this grip, alternate your grip or use wrist straps.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000047', 'Barbell Full Squat', 'Legs', 'B', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack just above shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Full_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000048', 'Barbell Glute Bridge', 'Legs', 'A', 'Powerlifting', 'Begin seated on the ground with a loaded barbell over your legs. Using a fat bar or having a pad on the bar can greatly reduce the discomfort caused by this exercise. Roll the bar so that it is directly above your hips, and lay down flat on the floor.', 'Begin the movement by driving through with your heels, extending your hips vertically through the bar. Your weight should be supported by your upper back and the heels of your feet.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Glute_Bridge/0.jpg'),
  ('00000000-0000-0000-0000-000000000049', 'Barbell Guillotine Bench Press', 'Chest', 'B', 'Strength', 'Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over your neck with your arms locked. This will be your starting position.', 'As you breathe in, bring the bar down slowly until it is about 1 inch from your neck.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Guillotine_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000050', 'Barbell Hack Squat', 'Legs', 'S', 'Strength', 'Stand up straight while holding a barbell behind you at arms length and your feet at shoulder width. Tip: A shoulder width grip is best with the palms of your hands facing back. You can use wrist wraps for this exercise for a better grip. This will be your starting position.', 'While keeping your head and eyes up and back straight, squat until your upper thighs are parallel to the floor. Breathe in as you slowly go down.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Hack_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000051', 'Barbell Hip Thrust', 'Legs', 'A', 'Powerlifting', 'Begin seated on the ground with a bench directly behind you. Have a loaded barbell over your legs. Using a fat bar or having a pad on the bar can greatly reduce the discomfort caused by this exercise.', 'Roll the bar so that it is directly above your hips, and lean back against the bench so that your shoulder blades are near the top of it.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Hip_Thrust/0.jpg'),
  ('00000000-0000-0000-0000-000000000052', 'Barbell Incline Bench Press - Medium Grip', 'Chest', 'B', 'Strength', 'Lie back on an incline bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on you upper chest.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Incline_Bench_Press_-_Medium_Grip/0.jpg'),
  ('00000000-0000-0000-0000-000000000053', 'Barbell Incline Shoulder Raise', 'Shoulders', 'B', 'Strength', 'Lie back on an Incline Bench. Using a medium width grip (a grip that is slightly wider than shoulder width), lift the bar from the rack and hold it straight over you with your arms straight. This will be your starting position.', 'While keeping the arms straight, lift the bar by protracting your shoulder blades, raising the shoulders from the bench as you breathe out.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Incline_Shoulder_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000054', 'Barbell Lunge', 'Legs', 'A', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack just below shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Lunge/0.jpg'),
  ('00000000-0000-0000-0000-000000000055', 'Barbell Rear Delt Row', 'Shoulders', 'S', 'Strength', 'Stand up straight while holding a barbell using a wide (higher than shoulder width) and overhand (palms facing your body) grip.', 'Bend knees slightly and bend over as you keep the natural arch of your back. Let the arms hang in front of you as they hold the bar. Once your torso is parallel to the floor, flare the elbows out and away from your body. Tip: Your torso and your arms should resemble the letter "T". Now you are ready to begin the exercise.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Rear_Delt_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000056', 'Barbell Rollout from Bench', 'Core', 'B', 'Strength', 'Place a loaded barbell on the ground, near the end of a bench. Kneel with both legs on the bench, and take a medium to narrow grip on the barbell. This will be your starting position.', 'To begin, extend through the hips to slowly roll the bar forward. As you roll out, flex the shoulder to roll the bar above your head. Ensure that your arms remain extended throughout the movement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Rollout_from_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000057', 'Barbell Seated Calf Raise', 'Legs', 'A', 'Strength', 'Place a block about 12 inches in front of a flat bench.', 'Sit on the bench and place the ball of your feet on the block.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Seated_Calf_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000058', 'Barbell Shoulder Press', 'Shoulders', 'B', 'Strength', 'Sit on a bench with back support in a squat rack. Position a barbell at a height that is just above your head. Grab the barbell with a pronated grip (palms facing forward).', 'Once you pick up the barbell with the correct grip width, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000059', 'Barbell Shrug', 'Other', 'B', 'Strength', 'Stand up straight with your feet at shoulder width as you hold a barbell with both hands in front of you using a pronated grip (palms facing the thighs). Tip: Your hands should be a little wider than shoulder width apart. You can use wrist wraps for this exercise for a better grip. This will be your starting position.', 'Raise your shoulders up as far as you can go as you breathe out and hold the contraction for a second. Tip: Refrain from trying to lift the barbell by using your biceps.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000060', 'Barbell Shrug Behind The Back', 'Other', 'S', 'Strength', 'Stand up straight with your feet at shoulder width as you hold a barbell with both hands behind your back using a pronated grip (palms facing back). Tip: Your hands should be a little wider than shoulder width apart. You can use wrist wraps for this exercise for better grip. This will be your starting position.', 'Raise your shoulders up as far as you can go as you breathe out and hold the contraction for a second. Tip: Refrain from trying to lift the barbell by using your biceps. The arms should remain stretched out at all times.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Shrug_Behind_The_Back/0.jpg'),
  ('00000000-0000-0000-0000-000000000061', 'Barbell Side Bend', 'Core', 'B', 'Strength', 'Stand up straight while holding a barbell placed on the back of your shoulders (slightly below the neck). Your feet should be shoulder width apart. This will be your starting position.', 'While keeping your back straight and your head up, bend only at the waist to the right as far as possible. Breathe in as you bend to the side. Then hold for a second and come back up to the starting position as you exhale. Tip: Keep the rest of the body stationary.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Side_Bend/0.jpg'),
  ('00000000-0000-0000-0000-000000000062', 'Barbell Side Split Squat', 'Legs', 'B', 'Strength', 'Stand up straight while holding a barbell placed on the back of your shoulders (slightly below the neck). Your feet should be placed wide apart with the foot of the lead leg angled out to the side. This will be your starting position.', 'Lower your body towards the side of your angled foot by bending the knee and hip of your lead leg and while keeping the opposite leg only slightly bent. Breathe in as you lower your body.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Side_Split_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000063', 'Barbell Squat', 'Legs', 'A', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack to just below shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000064', 'Barbell Squat To A Bench', 'Legs', 'B', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first place a flat bench or a box behind you. The flat bench is used to teach you to set your hips back and to hit depth.', 'Targets quadriceps.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Squat_To_A_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000065', 'Barbell Step Ups', 'Legs', 'S', 'Strength', 'Stand up straight while holding a barbell placed on the back of your shoulders (slightly below the neck) and stand upright behind an elevated platform (such as the one used for spotting behind a flat bench). This is your starting position.', 'Place the right foot on the elevated platform. Step on the platform by extending the hip and the knee of your right leg. Use the heel mainly to lift the rest of your body up and place the foot of the left leg on the platform as well. Breathe out as you execute the force required to come up.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Step_Ups/0.jpg'),
  ('00000000-0000-0000-0000-000000000066', 'Barbell Walking Lunge', 'Legs', 'A', 'Strength', 'Begin standing with your feet shoulder width apart and a barbell across your upper back.', 'Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Barbell_Walking_Lunge/0.jpg'),
  ('00000000-0000-0000-0000-000000000067', 'Battling Ropes', 'Shoulders', 'B', 'Strength', 'For this exercise you will need a heavy rope anchored at its center 15-20 feet away. Standing in front of the rope, take an end in each hand with your arms extended at your side. This will be your starting position.', 'Initiate the movement by rapidly raising one arm to shoulder level as quickly as you can.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Battling_Ropes/0.jpg'),
  ('00000000-0000-0000-0000-000000000068', 'Bear Crawl Sled Drags', 'Legs', 'B', 'Strongman', 'Wearing either a harness or a loose weight belt, attach the chain to the back so that you will be facing away from the sled. Bend down so that your hands are on the ground. Your back should be flat and knees bent. This is your starting position.', 'Begin by driving with legs, alternating left and right. Use your hands to maintain balance and to help pull. Try to keep your back flat as you move over a given distance.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bear_Crawl_Sled_Drags/0.jpg'),
  ('00000000-0000-0000-0000-000000000069', 'Behind Head Chest Stretch', 'Chest', 'A', 'Stretching', 'Sit upright on the floor with your partner behind you.', 'Place your hands behind your hand, and push your elbows back as far as you can. Your partner should hold your elbows. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Behind_Head_Chest_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000070', 'Bench Dips', 'Arms', 'S', 'Strength', 'For this exercise you will need to place a bench behind your back. With the bench perpendicular to your body, and while looking away from it, hold on to the bench on its edge with the hands fully extended, separated at shoulder width. The legs will be extended forward, bent at the waist and perpendicular to your torso. This will be your starting position.', 'Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Dips/0.jpg'),
  ('00000000-0000-0000-0000-000000000071', 'Bench Jump', 'Legs', 'B', 'Plyometrics', 'Begin with a box or bench 1-2 feet in front of you. Stand with your feet shoulder width apart. This will be your starting position.', 'Perform a short squat in preparation for the jump; swing your arms behind you.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000072', 'Bench Press - Powerlifting', 'Arms', 'A', 'Powerlifting', 'Begin by lying on the bench, getting your head beyond the bar if possible. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.', 'However wide your grip, it should cover the ring on the bar. Pull the bar out of the rack without protracting your shoulders. Focus on squeezing the bar and trying to pull it apart.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Press_-_Powerlifting/0.jpg'),
  ('00000000-0000-0000-0000-000000000073', 'Bench Press - With Bands', 'Chest', 'B', 'Strength', 'Using a flat bench secure a band under the leg of the bench that is nearest to your head.', 'Once the band is secure, grab it by both handles and lie down on the bench.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Press_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000074', 'Bench Press with Chains', 'Arms', 'B', 'Powerlifting', 'Adjust the leader chain, shortening it to the desired length.Place the chains on the sleeves of the bar.', 'Lying on the bench, get your head beyond the bar if possible. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement. However wide your grip, it should cover the ring on the bar.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Press_with_Chains/0.jpg'),
  ('00000000-0000-0000-0000-000000000075', 'Bench Sprint', 'Legs', 'S', 'Plyometrics', 'Stand on the ground with one foot resting on a bench or box with your heel close to the edge.', 'Push off with your foot on top of the bench, extending through the hip and knee.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bench_Sprint/0.jpg'),
  ('00000000-0000-0000-0000-000000000076', 'Bent-Arm Barbell Pullover', 'Back', 'B', 'Strength', 'Lie on a flat bench with a barbell using a shoulder grip width.', 'Hold the bar straight over your chest with a bend in your arms. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent-Arm_Barbell_Pullover/0.jpg'),
  ('00000000-0000-0000-0000-000000000077', 'Bent-Arm Dumbbell Pullover', 'Chest', 'B', 'Strength', 'Place a dumbbell standing up on a flat bench.', 'Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent-Arm_Dumbbell_Pullover/0.jpg'),
  ('00000000-0000-0000-0000-000000000078', 'Bent-Knee Hip Raise', 'Core', 'A', 'Strength', 'Lay flat on the floor with your arms next to your sides.', 'Now bend your knees at around a 75 degree angle and lift your feet off the floor by around 2 inches.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent-Knee_Hip_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000079', 'Bent Over Barbell Row', 'Back', 'B', 'Strength', 'Holding a barbell with a pronated grip (palms facing down), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.', 'Now, while keeping the torso stationary, breathe out and lift the barbell to you. Keep the elbows close to the body and only use the forearms to hold the weight. At the top contracted position, squeeze the back muscles and hold for a brief pause.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Barbell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000080', 'Bent Over Dumbbell Rear Delt Raise With Head On Bench', 'Shoulders', 'S', 'Strength', 'Stand up straight while holding a dumbbell in each hand and with an incline bench in front of you.', 'While keeping your back straight and maintaining the natural arch of your back, lean forward until your forehead touches the bench in front of you. Let the arms hang in front of you perpendicular to the ground. The palms of your hands should be facing each other and your torso should be parallel to the floor. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Dumbbell_Rear_Delt_Raise_With_Head_On_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000081', 'Bent Over Low-Pulley Side Lateral', 'Shoulders', 'A', 'Strength', 'Select a weight and hold the handle of the low pulley with your right hand.', 'Bend at the waist until your torso is nearly parallel to the floor. Your legs should be slightly bent with your left hand placed on your lower left thigh. Your right arm should be hanging from your shoulder in front of you and with a slight bend at the elbow. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Low-Pulley_Side_Lateral/0.jpg'),
  ('00000000-0000-0000-0000-000000000082', 'Bent Over One-Arm Long Bar Row', 'Back', 'B', 'Strength', 'Put weight on one of the ends of an Olympic barbell. Make sure that you either place the other end of the barbell in the corner of two walls; or put a heavy object on the ground so the barbell cannot slide backward.', 'Bend forward until your torso is as close to parallel with the floor as you can and keep your knees slightly bent.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_One-Arm_Long_Bar_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000083', 'Bent Over Two-Arm Long Bar Row', 'Back', 'B', 'Strength', 'Put weight on one of the ends of an Olympic barbell. Make sure that you either place the other end of the barbell in the corner of two walls; or put a heavy object on the ground so the barbell cannot slide backward.', 'Bend forward until your torso is as close to parallel with the floor as you can and keep your knees slightly bent.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Two-Arm_Long_Bar_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000084', 'Bent Over Two-Dumbbell Row', 'Back', 'A', 'Strength', 'With a dumbbell in each hand (palms facing your torso), bend your knees slightly and bring your torso forward by bending at the waist; as you bend make sure to keep your back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.', 'While keeping the torso stationary, lift the dumbbells to your side (as you breathe out), keeping the elbows close to the body (do not exert any force with the forearm other than holding the weights). On the top contracted position, squeeze the back muscles and hold for a second.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Two-Dumbbell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000085', 'Bent Over Two-Dumbbell Row With Palms In', 'Back', 'S', 'Strength', 'With a dumbbell in each hand (palms facing each other), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.', 'While keeping the torso stationary, lift the dumbbells to your side as you breathe out, squeezing your shoulder blades together. On the top contracted position, squeeze the back muscles and hold for a second.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Over_Two-Dumbbell_Row_With_Palms_In/0.jpg'),
  ('00000000-0000-0000-0000-000000000086', 'Bent Press', 'Core', 'B', 'Strength', 'Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so. This will be your starting position.', 'Begin my leaning to the side opposite the kettlebell, continuing until you are able to touch the ground with your free hand, keeping your eyes on the kettlebell. As you do so, press the weight vertically be extending through the elbow, keeping your arm perpendicular to the ground.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bent_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000087', 'Bicycling', 'Legs', 'A', 'Cardio', 'To begin, seat yourself on the bike and adjust the seat to your height.', 'Targets quadriceps.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bicycling/0.jpg'),
  ('00000000-0000-0000-0000-000000000088', 'Bicycling, Stationary', 'Legs', 'B', 'Cardio', 'To begin, seat yourself on the bike and adjust the seat to your height.', 'Select the desired option from the menu. You may have to start pedaling to turn it on. You can use the manual setting, or you can select a program to use. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. The level of resistance can be changed throughout the workout. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bicycling_Stationary/0.jpg'),
  ('00000000-0000-0000-0000-000000000089', 'Board Press', 'Arms', 'B', 'Powerlifting', 'Begin by lying on the bench, getting your head beyond the bar if possible. One to five boards, made out of 2x6''s, can be screwed together and held in place by a training partner, bands, or just tucked under your shirt.', 'Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Board_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000090', 'Body-Up', 'Arms', 'S', 'Strength', 'Assume a plank position on the ground. You should be supporting your bodyweight on your toes and forearms, keeping your torso straight. Your forearms should be shoulder-width apart. This will be your starting position.', 'Pressing your palms firmly into the ground, extend through the elbows to raise your body from the ground. Keep your torso rigid as you perform the movement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Body-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000091', 'Body Tricep Press', 'Arms', 'B', 'Strength', 'Position a bar in a rack at chest height.', 'Standing, take a shoulder width grip on the bar and step a yard or two back, feet together and arms extended so that you are leaning on the bar. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Body_Tricep_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000092', 'Bodyweight Flyes', 'Chest', 'B', 'Strength', 'Position two equally loaded EZ bars on the ground next to each other. Ensure they are able to roll.', 'Assume a push-up position over the bars, supporting your weight on your toes and hands with your arms extended and body straight.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Flyes/0.jpg'),
  ('00000000-0000-0000-0000-000000000093', 'Bodyweight Mid Row', 'Back', 'A', 'Strength', 'Begin by taking a medium to wide grip on a pull-up apparatus with your palms facing away from you. From a hanging position, tuck your knees to your chest, leaning back and getting your legs over your side of the pull-up apparatus. This will be your starting position.', 'Beginning with your arms straight, flex the elbows and retract the shoulder blades to raise your body up until your legs contact the pull-up apparatus.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Mid_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000094', 'Bodyweight Squat', 'Legs', 'B', 'Strength', 'Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position.', 'Begin the movement by flexing your knees and hips, sitting back with your hips.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000095', 'Bodyweight Walking Lunge', 'Legs', 'S', 'Strength', 'Begin standing with your feet shoulder width apart and your hands on your hips.', 'Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bodyweight_Walking_Lunge/0.jpg'),
  ('00000000-0000-0000-0000-000000000096', 'Bosu Ball Cable Crunch With Side Bends', 'Core', 'A', 'Strength', 'Connect a standard handle to each arm of a cable machine, and position them in the most downward position.', 'Grab a Bosu Ball and position it in front and center of the cable machine.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bosu_Ball_Cable_Crunch_With_Side_Bends/0.jpg'),
  ('00000000-0000-0000-0000-000000000097', 'Bottoms-Up Clean From The Hang Position', 'Arms', 'B', 'Strength', 'Initiate the exercise by standing upright with a kettlebell in one hand.', 'Swing the kettlebell back forcefully and then reverse the motion forcefully. Crush the kettlebell handle as hard as possible and raise the kettlebell to your shoulder.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bottoms-Up_Clean_From_The_Hang_Position/0.jpg'),
  ('00000000-0000-0000-0000-000000000098', 'Bottoms Up', 'Core', 'B', 'Strength', 'Begin by lying on your back on the ground. Your legs should be straight and your arms at your side. This will be your starting position.', 'To perform the movement, tuck the knees toward your chest by flexing the hips and knees. Following this, extend your legs directly above you so that they are perpendicular to the ground. Rotate and elevate your pelvis to raise your glutes from the floor.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bottoms_Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000099', 'Box Jump (Multiple Response)', 'Legs', 'A', 'Plyometrics', 'Assume a relaxed stance facing the box or platform approximately an arm''s length away. Arms should be down at the sides and legs slightly bent.', 'Using the arms to aid in the initial burst, jump upward and forward, landing with feet simultaneously on top of the box or platform.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Box_Jump_Multiple_Response/0.jpg'),
  ('00000000-0000-0000-0000-000000000100', 'Box Skip', 'Legs', 'S', 'Plyometrics', 'You will need several boxes lined up about 8 feet apart.', 'Begin facing the first box with one leg slightly behind the other.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Box_Skip/0.jpg'),
  ('00000000-0000-0000-0000-000000000101', 'Box Squat', 'Legs', 'B', 'Powerlifting', 'The box squat allows you to squat to desired depth and develop explosive strength in the squat movement. Begin in a power rack with a box at the appropriate height behind you. Typically, you would aim for a box height that brings you to a parallel squat, but you can train higher or lower if desired.', 'Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wider for more emphasis on the back, glutes, adductors, and hamstrings, or closer together for more quad development. Keep your head facing forward.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Box_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000102', 'Box Squat with Bands', 'Legs', 'A', 'Powerlifting', 'Begin in a power rack with a box at the appropriate height behind you. Set up the bands on the sleeves, secured to either band pegs, the rack, or dumbbells so that there is appropriate tension. If dumbbells are used, secure them so that they don''t move. Also, ensure that the dumbbells you are using are heavy enough for the bands that you are using. Additional plates can be used to hold the dumbbells down. If more tension is needed, you can either widen the base on the floor or choke the bands. Typically, you would aim for a box height that brings you to a parallel squat, but you can train higher or lower if desired.', 'Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wider for more emphasis on the back, glutes, adductors, and hamstrings, or closer together for more quad development. Keep your head facing forward.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Box_Squat_with_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000103', 'Box Squat with Chains', 'Legs', 'B', 'Strength', 'Begin in a power rack with a box at the appropriate height behind you. Typically, you would aim for a box height that brings you to a parallel squat, but you can train higher or lower if desired.', 'To set up the chains, begin by looping the leader chain over the sleeves of the bar. The heavy chain should be attached using a snap hook. Adjust the length of the lead chain so that a few links are still on the floor at the top of the movement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Box_Squat_with_Chains/0.jpg'),
  ('00000000-0000-0000-0000-000000000104', 'Brachialis-SMR', 'Arms', 'B', 'Stretching', 'Lie on your side, with your upper arm against the foam roller. The upper arm should be more or less aligned with your body, with the outside of the bicep pressed against the foam roller.', 'Raise your hips off of the floor, supporting your weight on your arm and on your feet. Hold for 10-30 seconds, and then switch sides.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Brachialis-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000105', 'Bradford/Rocky Presses', 'Shoulders', 'S', 'Strength', 'Sit on a Military Press Bench with a bar at shoulder level with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down. This is your starting position.', 'Once you pick up the barbell with the correct grip, lift the bar up over your head by locking your arms.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Bradford_Rocky_Presses/0.jpg'),
  ('00000000-0000-0000-0000-000000000106', 'Butt-Ups', 'Core', 'B', 'Strength', 'Begin a pushup position but with your elbows on the ground and resting on your forearms. Your arms should be bent at a 90 degree angle.', 'Arch your back slightly out rather than keeping your back completely straight.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Butt-Ups/0.jpg'),
  ('00000000-0000-0000-0000-000000000107', 'Butt Lift (Bridge)', 'Legs', 'B', 'Strength', 'Lie flat on the floor on your back with the hands by your side and your knees bent. Your feet should be placed around shoulder width. This will be your starting position.', 'Pushing mainly with your heels, lift your hips off the floor while keeping your back straight. Breathe out as you perform this part of the motion and hold at the top for a second.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Butt_Lift_Bridge/0.jpg'),
  ('00000000-0000-0000-0000-000000000108', 'Butterfly', 'Chest', 'A', 'Strength', 'Sit on the machine with your back flat on the pad.', 'Take hold of the handles. Tip: Your upper arms should be positioned parallel to the floor; adjust the machine accordingly. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Butterfly/0.jpg'),
  ('00000000-0000-0000-0000-000000000109', 'Cable Chest Press', 'Chest', 'B', 'Strength', 'Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 45 degrees to the body, with your head and chest up. The elbows should be bent to about 90 degrees. This will be your starting position.', 'Begin by extending through the elbow, pressing the handles together straight in front of you. Keep your shoulder blades retracted as you execute the movement.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Chest_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000110', 'Cable Crossover', 'Chest', 'S', 'Strength', 'To get yourself into the starting position, place the pulleys on a high position (above your head), select the resistance to be used and hold the pulleys in each hand.', 'Step forward in front of an imaginary straight line between both pulleys while pulling your arms together in front of you. Your torso should have a small forward bend from the waist. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Crossover/0.jpg'),
  ('00000000-0000-0000-0000-000000000111', 'Cable Crunch', 'Core', 'A', 'Strength', 'Kneel below a high pulley that contains a rope attachment.', 'Grasp cable rope attachment and lower the rope until your hands are placed next to your face.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000112', 'Cable Deadlifts', 'Legs', 'B', 'Strength', 'Move the cables to the bottom of the towers and select an appropriate weight. Stand directly in between the uprights.', 'To begin, squat down be flexing your hips and knees until you can reach the handles.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Deadlifts/0.jpg'),
  ('00000000-0000-0000-0000-000000000113', 'Cable Hammer Curls - Rope Attachment', 'Arms', 'B', 'Strength', 'Attach a rope attachment to a low pulley and stand facing the machine about 12 inches away from it.', 'Grasp the rope with a neutral (palms-in) grip and stand straight up keeping the natural arch of the back and your torso stationary.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Hammer_Curls_-_Rope_Attachment/0.jpg'),
  ('00000000-0000-0000-0000-000000000114', 'Cable Hip Adduction', 'Legs', 'A', 'Strength', 'Stand in front of a low pulley facing forward with one leg next to the pulley and the other one away.', 'Attach the ankle cuff to the cable and also to the ankle of the leg that is next to the pulley.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Hip_Adduction/0.jpg'),
  ('00000000-0000-0000-0000-000000000115', 'Cable Incline Pushdown', 'Back', 'S', 'Strength', 'Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it.', 'Grasp the straight bar attachment overhead with a pronated (overhand; palms down) shoulder width grip and extend your arms in front of you. The bar should be around 2 inches away from your upper thighs. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Incline_Pushdown/0.jpg'),
  ('00000000-0000-0000-0000-000000000116', 'Cable Incline Triceps Extension', 'Arms', 'B', 'Strength', 'Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it.', 'Grasp the straight bar attachment overhead with a pronated (overhand; palms down) narrow grip (less than shoulder width) and keep your elbows tucked in to your sides. Your upper arms should create around a 25 degree angle when measured from the floor.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Incline_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000117', 'Cable Internal Rotation', 'Shoulders', 'A', 'Strength', 'Sit next to a low pulley sideways (with legs stretched in front of you or crossed) and grasp the single hand cable attachment with the arm nearest to the cable. Tip: If you can adjust the pulley''s height, you can use a flat bench to sit on instead.', 'Position the elbow against your side with the elbow bent at 90° and the arm pointing towards the pulley. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Internal_Rotation/0.jpg'),
  ('00000000-0000-0000-0000-000000000118', 'Cable Iron Cross', 'Chest', 'B', 'Strength', 'Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand.', 'Stand directly between both pulleys with your arms extended out to your sides. Your head and chest should be up while your arms form a "T". This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Iron_Cross/0.jpg'),
  ('00000000-0000-0000-0000-000000000119', 'Cable Judo Flip', 'Core', 'B', 'Strength', 'Connect a rope attachment to a tower, and move the cable to the lowest pulley position. Stand with your side to the cable with a wide stance, and grab the rope with both hands.', 'Twist your body away from the pulley as you bring the rope over your shoulder like you''re performing a judo flip.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Judo_Flip/0.jpg'),
  ('00000000-0000-0000-0000-000000000120', 'Cable Lying Triceps Extension', 'Arms', 'S', 'Strength', 'Lie on a flat bench and grasp the straight bar attachment of a low pulley with a narrow overhand grip. Tip: The easiest way to do this is to have someone hand you the bar as you lay down.', 'With your arms extended, position the bar over your torso. Your arms and your torso should create a 90-degree angle. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Lying_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000121', 'Cable One Arm Tricep Extension', 'Arms', 'B', 'Strength', 'With your right hand, grasp a single handle attached to the high-cable pulley using a supinated (underhand; palms facing up) grip. You should be standing directly in front of the weight stack.', 'Now pull the handle down so that your upper arm and elbow are locked in to the side of your body. Your upper arm and forearm should form an acute angle (less than 90-degrees). You can keep the other arm by the waist and you can have one leg in front of you and the other one back for better balance. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_One_Arm_Tricep_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000122', 'Cable Preacher Curl', 'Arms', 'B', 'Strength', 'Place a preacher bench about 2 feet in front of a pulley machine.', 'Attach a straight bar to the low pulley.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Preacher_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000123', 'Cable Rear Delt Fly', 'Shoulders', 'A', 'Strength', 'Adjust the pulleys to the appropriate height and adjust the weight. The pulleys should be above your head.', 'Grab the left pulley with your right hand and the right pulley with your left hand, crossing them in front of you. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Rear_Delt_Fly/0.jpg'),
  ('00000000-0000-0000-0000-000000000124', 'Cable Reverse Crunch', 'Core', 'B', 'Strength', 'Connect an ankle strap attachment to a low pulley cable and position a mat on the floor in front of it.', 'Sit down with your feet toward the pulley and attach the cable to your ankles.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Reverse_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000125', 'Cable Rope Overhead Triceps Extension', 'Arms', 'S', 'Strength', 'Attach a rope to the bottom pulley of the pulley machine.', 'Grasping the rope with both hands, extend your arms with your hands directly above your head using a neutral grip (palms facing each other). Your elbows should be in close to your head and the arms should be perpendicular to the floor with the knuckles aimed at the ceiling. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Rope_Overhead_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000126', 'Cable Rope Rear-Delt Rows', 'Shoulders', 'A', 'Strength', 'Sit in the same position on a low pulley row station as you would if you were doing seated cable rows for the back.', 'Attach a rope to the pulley and grasp it with an overhand grip. Your arms should be extended and parallel to the floor with the elbows flared out.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Rope_Rear-Delt_Rows/0.jpg'),
  ('00000000-0000-0000-0000-000000000127', 'Cable Russian Twists', 'Core', 'B', 'Strength', 'Connect a standard handle attachment, and position the cable to a middle pulley position.', 'Lie on a stability ball perpendicular to the cable and grab the handle with one hand. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Russian_Twists/0.jpg'),
  ('00000000-0000-0000-0000-000000000128', 'Cable Seated Crunch', 'Core', 'B', 'Strength', 'Seat on a flat bench with your back facing a high pulley.', 'Grasp the cable rope attachment with both hands (with the palms of the hands facing each other) and place your hands securely over both shoulders. Tip: Allow the weight to hyperextend the lower back slightly. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Seated_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000129', 'Cable Seated Lateral Raise', 'Shoulders', 'A', 'Strength', 'Stand in the middle of two low pulleys that are opposite to each other and place a flat bench right behind you (in perpendicular fashion to you; the narrow edge of the bench should be the one behind you). Select the weight to be used on each pulley.', 'Now sit at the edge of the flat bench behind you with your feet placed in front of your knees.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Seated_Lateral_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000130', 'Cable Shoulder Press', 'Shoulders', 'S', 'Strength', 'Move the cables to the bottom of the towers and select an appropriate weight.', 'Stand directly in between the uprights. Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000131', 'Cable Shrugs', 'Other', 'B', 'Strength', 'Grasp a cable bar attachment that is attached to a low pulley with a shoulder width or slightly wider overhand (palms facing down) grip.', 'Stand erect close to the pulley with your arms extended in front of you holding the bar. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Shrugs/0.jpg'),
  ('00000000-0000-0000-0000-000000000132', 'Cable Wrist Curl', 'Arms', 'A', 'Strength', 'Start out by placing a flat bench in front of a low pulley cable that has a straight bar attachment.', 'Use your arms to grab the cable bar with a narrow to shoulder width supinated grip (palms up) and bring them up so that your forearms are resting against the top of your thighs. Your wrists should be hanging just beyond your knees.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cable_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000133', 'Calf-Machine Shoulder Shrug', 'Other', 'B', 'Strength', 'Position yourself on the calf machine so that the shoulder pads are above your shoulders. Your torso should be straight with the arms extended normally by your side. This will be your starting position.', 'Raise your shoulders up towards your ears as you exhale and hold the contraction for a full second.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf-Machine_Shoulder_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000134', 'Calf Press', 'Legs', 'B', 'Strength', 'Adjust the seat so that your legs are only slightly bent in the start position. The balls of your feet should be firmly on the platform.', 'Select an appropriate weight, and grasp the handles. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000135', 'Calf Press On The Leg Press Machine', 'Legs', 'S', 'Strength', 'Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance.', 'Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you without locking your knees. (Note: In some leg press units you can leave the safety bars on for increased safety. If your leg press unit allows for this, then this is the preferred method of performing the exercise.) Your torso and the legs should make perfect 90-degree angle. Now carefully place your toes and balls of your feet on the lower portion of the platform with the heels extending off. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf_Press_On_The_Leg_Press_Machine/0.jpg'),
  ('00000000-0000-0000-0000-000000000136', 'Calf Raise On A Dumbbell', 'Legs', 'B', 'Strength', 'Hang on to a sturdy object for balance and stand on a dumbbell handle, preferably one with round plates so that it rolls as in this manner you have to work harder to stabilize yourself; thus increasing the effectiveness of the exercise.', 'Now roll your foot slightly forward so that you can get a nice stretch of the calf. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf_Raise_On_A_Dumbbell/0.jpg'),
  ('00000000-0000-0000-0000-000000000137', 'Calf Raises - With Bands', 'Legs', 'B', 'Strength', 'Grab an exercise band and stand on it with your toes making sure that the length of the band between the foot and the arms is the same for both sides.', 'While holding the handles of the band, raise the arms to the side of your head as if you were getting ready to perform a shoulder press. The palms should be facing forward with the elbows bent and to the sides. This movement will create tension on the band. This will be your starting position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf_Raises_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000138', 'Calf Stretch Elbows Against Wall', 'Legs', 'A', 'Stretching', 'Stand facing a wall from a couple feet away.', 'Lean against the wall, placing your weight on your forearms.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf_Stretch_Elbows_Against_Wall/0.jpg'),
  ('00000000-0000-0000-0000-000000000139', 'Calf Stretch Hands Against Wall', 'Legs', 'B', 'Stretching', 'Stand facing a wall from several feet away. Stagger your stance, placing one foot forward.', 'Lean forward and rest your hands on the wall, keeping your heel, hip and head in a straight line.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calf_Stretch_Hands_Against_Wall/0.jpg'),
  ('00000000-0000-0000-0000-000000000140', 'Calves-SMR', 'Legs', 'S', 'Stretching', 'Begin seated on the floor. Place a foam roller underneath your lower leg. Your other leg can either be crossed over the opposite or be placed on the floor, supporting some of your weight. This will be your starting position.', 'Place your hands to your side or just behind you, and press down to raise your hips off of the floor, placing much of your weight against your calf muscle. Roll from below the knee to above the ankle, pausing at points of tension for 10-30 seconds. Repeat for the other leg.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Calves-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000141', 'Car Deadlift', 'Legs', 'A', 'Strongman', 'This event apparatus typically has neutral grip handles, however some have a straight bar that you can approach like a normal deadlift. The apparatus can be loaded with a vehicle or other heavy objects such as tractor tires or kegs.', 'Center yourself between the handles if you are a strong squatter, or back a couple inches if you are a strong deadlifter. You feet should be about hip width apart. Bend at the hip to grip the handles. With your feet and your grip set, take a big breath and then lower your hips and flex the knees.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Car_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000142', 'Car Drivers', 'Shoulders', 'B', 'Strength', 'While standing upright, hold a barbell plate in both hands at the 3 and 9 o''clock positions. Your palms should be facing each other and your arms should be extended straight out in front of you. This will be your starting position.', 'Initiate the movement by rotating the plate as far to one side as possible. Use the same type of movement you would use to turn a steering wheel to one side.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Car_Drivers/0.jpg'),
  ('00000000-0000-0000-0000-000000000143', 'Carioca Quick Step', 'Legs', 'B', 'Plyometrics', 'Begin with your feet a few inches apart and your left arm up in a relaxed, athletic position.', 'With your right foot, quick step behind and pull the knee up.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Carioca_Quick_Step/0.jpg'),
  ('00000000-0000-0000-0000-000000000144', 'Cat Stretch', 'Back', 'A', 'Stretching', 'Position yourself on the floor on your hands and knees.', 'Pull your belly in and round your spine, lower back, shoulders, and neck, letting your head drop.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cat_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000145', 'Catch and Overhead Throw', 'Back', 'S', 'Plyometrics', 'Begin standing while facing a wall or a partner.', 'Using both hands, position the ball behind your head, stretching as much as possible, and forcefully throw the ball forward.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Catch_and_Overhead_Throw/0.jpg'),
  ('00000000-0000-0000-0000-000000000146', 'Chain Handle Extension', 'Arms', 'B', 'Powerlifting', 'You will need two cable handle attachments and a flat bench, as well as chains, for this exercise. Clip the middle of the chains to the handles, and position yourself on the flat bench. Your elbows should be pointing straight up.', 'Begin by extending through the elbow, keeping your upper arm still, with your wrists pronated.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chain_Handle_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000147', 'Chain Press', 'Chest', 'A', 'Powerlifting', 'Begin by connecting the chains to the cable handle attachments. Position yourself on the flat bench in the same position as for a dumbbell press. Your wrists should be pronated and arms perpendicular to the floor. This will be your starting position.', 'Lower the chains by flexing the elbows, unloading some of the chain onto the floor.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chain_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000148', 'Chair Leg Extended Stretch', 'Legs', 'B', 'Stretching', 'Sit upright in a chair and grip the seat on the sides.', 'Raise one leg, extending the knee, flexing the ankle as you do so.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Leg_Extended_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000149', 'Chair Lower Back Stretch', 'Back', 'B', 'Stretching', 'Sit upright on a chair.', 'Bend to one side with your arm over your head. You can hold onto the chair with your free hand.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Lower_Back_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000150', 'Chair Squat', 'Legs', 'S', 'Strength', 'To begin, first set the bar to a position that best matches your height. Once the bar is loaded, step under it and position it across the back of your shoulders.', 'Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000151', 'Chair Upper Body Stretch', 'Shoulders', 'B', 'Stretching', 'Sit on the edge of a chair, gripping the back of it.', 'Straighten your arms, keeping your back straight, and pull your upper body forward so you feel a stretch. Hold for 20-30 seconds.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chair_Upper_Body_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000152', 'Chest And Front Of Shoulder Stretch', 'Chest', 'B', 'Stretching', 'Start off by standing with your legs together, holding a bodybar or a broomstick.', 'Take a slightly wider than shoulder width grip on the pole and hold it in front of you with your palms facing down.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_And_Front_Of_Shoulder_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000153', 'Chest Push from 3 point stance', 'Chest', 'A', 'Plyometrics', 'Begin in a three point stance, squatted down with your back flat and one hand on the ground. Place the medicine ball directly in front of you.', 'To begin, take your first step as you pull the ball to your chest, positioning both hands to prepare for the throw.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_from_3_point_stance/0.jpg'),
  ('00000000-0000-0000-0000-000000000154', 'Chest Push (multiple response)', 'Chest', 'B', 'Plyometrics', 'Begin in a kneeling position facing a wall or utilize a partner. Hold the ball with both hands tight into the chest.', 'Execute the pass by exploding forward and outward with the hips while pushing the ball as hard as possible.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_multiple_response/0.jpg'),
  ('00000000-0000-0000-0000-000000000155', 'Chest Push (single response)', 'Chest', 'S', 'Plyometrics', 'Begin in a kneeling position holding the medicine ball with both hands tightly into the chest.', 'Execute the pass by exploding forward and outward with the hips while pushing the ball as far as possible.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_single_response/0.jpg'),
  ('00000000-0000-0000-0000-000000000156', 'Chest Push with Run Release', 'Chest', 'A', 'Plyometrics', 'Begin in an athletic stance with the knees bent, hips back, and back flat. Hold the medicine ball near your legs. This will be your starting position.', 'While taking your first step draw the medicine ball into your chest.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Push_with_Run_Release/0.jpg'),
  ('00000000-0000-0000-0000-000000000157', 'Chest Stretch on Stability Ball', 'Chest', 'B', 'Stretching', 'Get on your hands and knees next to an exercise ball.', 'Place your elbows on top of the ball, keeping your arm out to your side. This will be your starting position.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chest_Stretch_on_Stability_Ball/0.jpg'),
  ('00000000-0000-0000-0000-000000000158', 'Child''s Pose', 'Back', 'B', 'Stretching', 'Get on your hands and knees, walk your hands in front of you.', 'Lower your buttocks down to sit on your heels. Let your arms drag along the floor as you sit back to stretch your entire spine.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Childs_Pose/0.jpg'),
  ('00000000-0000-0000-0000-000000000159', 'Chin-Up', 'Back', 'A', 'Strength', 'Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.', 'As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chin-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000160', 'Chin To Chest Stretch', 'Neck', 'S', 'Stretching', 'Get into a seated position on the floor.', 'Place both hands at the rear of your head, fingers interlocked, thumbs pointing down and elbows pointing straight ahead. Slowly pull your head down to your chest. Hold for 20-30 seconds.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Chin_To_Chest_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000161', 'Circus Bell', 'Shoulders', 'B', 'Strongman', 'The circus bell is an oversized dumbbell with a thick handle. Begin with the dumbbell between your feet, and grip the handle with both hands.', 'Clean the dumbbell by extending through your hips and knees to deliver the implement to the desired shoulder, letting go with the extra hand.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Circus_Bell/0.jpg'),
  ('00000000-0000-0000-0000-000000000162', 'Clean', 'Legs', 'A', 'Olympic weightlifting', 'With a barbell on the floor close to the shins, take an overhand (or hook) grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.', 'Targets hamstrings.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000163', 'Clean Deadlift', 'Legs', 'B', 'Olympic weightlifting', 'Begin standing with a barbell close to your shins. Your feet should be directly under your hips with your feet turned out slightly. Grip the bar with a double overhand grip or hook grip, about shoulder width apart. Squat down to the bar. Your spine should be in full extension, with a back angle that places your shoulders in front of the bar and your back as vertical as possible.', 'Begin by driving through the floor through the front of your heels. As the bar travels upward, maintain a constant back angle. Flare your knees out to the side to help keep them out of the bar''s path.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clean_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000164', 'Clean Pull', 'Legs', 'B', 'Olympic weightlifting', 'With a barbell on the floor close to the shins, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.', 'Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight and elbows out. Move the weight with control as you continue to above the knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clean_Pull/0.jpg'),
  ('00000000-0000-0000-0000-000000000165', 'Clean Shrug', 'Other', 'S', 'Olympic weightlifting', 'Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.', 'Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a clean, avoid overloading to the point that the execution slows down.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clean_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000166', 'Clean and Jerk', 'Shoulders', 'B', 'Olympic weightlifting', 'With a barbell on the floor close to the shins, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.', 'Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clean_and_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000167', 'Clean and Press', 'Shoulders', 'B', 'Strength', 'Assume a shoulder-width stance, with knees inside the arms. Now while keeping the back flat, bend at the knees and hips so that you can grab the bar with the arms fully extended and a pronated grip that is slightly wider than shoulder width. Point the elbows out to sides. The bar should be close to the shins. Position the shoulders over or slightly ahead of the bar. Establish a flat back posture. This will be your starting position.', 'Begin to pull the bar by extending the knees. Move your hips forward and raise the shoulders at the same rate while keeping the angle of the back constant; continue to lift the bar straight up while keeping it close to your body.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clean_and_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000168', 'Clean from Blocks', 'Legs', 'A', 'Olympic weightlifting', 'With a barbell on boxes or stands of the desired height, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.', 'Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight with the elbows pointed out.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clean_from_Blocks/0.jpg'),
  ('00000000-0000-0000-0000-000000000169', 'Clock Push-Up', 'Chest', 'B', 'Strength', 'Move into a prone position on the floor, supporting your weight on your hands and toes.', 'Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Clock_Push-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000170', 'Close-Grip Barbell Bench Press', 'Arms', 'S', 'Strength', 'Lie back on a flat bench. Using a close grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that - as opposed to a regular bench press - you keep the elbows close to the torso at all times in order to maximize triceps involvement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_Barbell_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000171', 'Close-Grip Dumbbell Press', 'Arms', 'A', 'Strength', 'Place a dumbbell standing up on a flat bench.', 'Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench with only your shoulders lying on the surface. Hips should be below the bench and your legs bent with your feet firmly on the floor.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000172', 'Close-Grip EZ-Bar Curl with Band', 'Arms', 'B', 'Strength', 'Attach a band to each end of the bar. Take the bar, placing a foot on the middle of the band. Stand upright with a narrow, supinated grip on the EZ bar. The elbows should be close to the torso. This will be your starting position.', 'While keeping the upper arms in place, flex the elbows to execute the curl. Exhale as the weight is lifted.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_EZ-Bar_Curl_with_Band/0.jpg'),
  ('00000000-0000-0000-0000-000000000173', 'Close-Grip EZ-Bar Press', 'Arms', 'B', 'Strength', 'Lie on a flat bench with an EZ bar loaded to an appropriate weight.', 'Using a narrow grip lift the bar and hold it straight over your torso with your elbows in. The arms should be perpendicular to the floor. This will be your starting position.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_EZ-Bar_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000174', 'Close-Grip EZ Bar Curl', 'Arms', 'A', 'Strength', 'Stand up with your torso upright while holding an E-Z Curl Bar at the closer inner handle. The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar. The elbows should be close to the torso. This will be your starting position.', 'While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_EZ_Bar_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000175', 'Close-Grip Front Lat Pulldown', 'Back', 'S', 'Strength', 'Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.', 'Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_Front_Lat_Pulldown/0.jpg'),
  ('00000000-0000-0000-0000-000000000176', 'Close-Grip Push-Up off of a Dumbbell', 'Arms', 'B', 'Strength', 'Lie on the floor and place your hands on an upright dumbbell. Supporting your weight on your toes and hands, keep your torso rigid and your elbows in with your arms straight. This will be your starting position.', 'Lower your body, allowing the elbows to flex while you inhale. Keep your body straight, not allowing your hips to rise or sag.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_Push-Up_off_of_a_Dumbbell/0.jpg'),
  ('00000000-0000-0000-0000-000000000177', 'Close-Grip Standing Barbell Curl', 'Arms', 'A', 'Strength', 'Hold a barbell with both hands, palms up and a few inches apart.', 'Stand with your torso straight and your head up. Your feet should be about shoulder width and your elbows close to your torso. This will be your starting position. Tip: You will keep your upper arms and elbows stationary throughout the movement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Close-Grip_Standing_Barbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000178', 'Cocoons', 'Core', 'B', 'Strength', 'Begin by lying on your back on the ground. Your legs should be straight and your arms extended behind your head. This will be your starting position.', 'To perform the movement, tuck the knees toward your chest, rotating your pelvis to lift your glutes from the floor. As you do so, flex the spine, bringing your arms back over your head to perform a simultaneous crunch motion.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cocoons/0.jpg'),
  ('00000000-0000-0000-0000-000000000179', 'Conan''s Wheel', 'Legs', 'B', 'Strongman', 'With the weight loaded, take a zurcher hold on the end of the implement. Place the bar in the crook of the elbow and hold onto your wrist. Try to keep the weight off of the forearms.', 'Begin by lifting the weight from the ground. Keep a tight, upright posture as you being to walk, taking short, fast steps. Look up and away as you turn in a circle. Do not hold your breath during the event. Continue walking until you complete one or more complete turns.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Conans_Wheel/0.jpg'),
  ('00000000-0000-0000-0000-000000000180', 'Concentration Curls', 'Arms', 'S', 'Strength', 'Sit down on a flat bench with one dumbbell in front of you between your legs. Your legs should be spread with your knees bent and feet on the floor.', 'Use your right arm to pick the dumbbell up. Place the back of your right upper arm on the top of your inner right thigh. Rotate the palm of your hand until it is facing forward away from your thigh. Tip: Your arm should be extended and the dumbbell should be above the floor. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Concentration_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000181', 'Cross-Body Crunch', 'Core', 'B', 'Strength', 'Lie flat on your back and bend your knees about 60 degrees.', 'Keep your feet flat on the floor and place your hands loosely behind your head. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cross-Body_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000182', 'Cross Body Hammer Curl', 'Arms', 'B', 'Strength', 'Stand up straight with a dumbbell in each hand. Your hands should be down at your side with your palms facing in.', 'While keeping your palms facing in and without twisting your arm, curl the dumbbell of the right arm up towards your left shoulder as you exhale. Touch the top of the dumbbell to your shoulder and hold the contraction for a second.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cross_Body_Hammer_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000183', 'Cross Over - With Bands', 'Chest', 'A', 'Strength', 'Secure an exercise band around a stationary post.', 'While facing away from the post, grab the handles on both ends of the band and step forward enough to create tension on the band.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cross_Over_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000184', 'Crossover Reverse Lunge', 'Back', 'B', 'Stretching', 'Stand with your feet shoulder width apart. This will be your starting position.', 'Perform a rear lunge by stepping back with one foot and flexing the hips and front knee. As you do so, rotate your torso across the front leg.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Crossover_Reverse_Lunge/0.jpg'),
  ('00000000-0000-0000-0000-000000000185', 'Crucifix', 'Shoulders', 'S', 'Strongman', 'In the crucifix, you statically hold weights out to the side for time. While the event can be practiced using dumbbells, it is best to practice with one of the various implements used, such as axes and hammers, as it feels different.', 'Begin standing, and raise your arms out to the side holding the implements. Your arms should be parallel to the ground. In competition, judges or sensors are used to let you know when you break parallel. Hold for as long as you can. Typically, the weights should be heavy enough that you fail in 30-60 seconds.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Crucifix/0.jpg'),
  ('00000000-0000-0000-0000-000000000186', 'Crunch - Hands Overhead', 'Core', 'A', 'Strength', 'Lie on the floor with your back flat and knees bent with around a 60-degree angle between the hamstrings and the calves.', 'Keep your feet flat on the floor and stretch your arms overhead with your palms crossed. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Crunch_-_Hands_Overhead/0.jpg'),
  ('00000000-0000-0000-0000-000000000187', 'Crunch - Legs On Exercise Ball', 'Core', 'B', 'Strength', 'Lie flat on your back with your feet resting on an exercise ball and your knees bent at a 90 degree angle.', 'Place your feet three to four inches apart and point your toes inward so they touch.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Crunch_-_Legs_On_Exercise_Ball/0.jpg'),
  ('00000000-0000-0000-0000-000000000188', 'Crunches', 'Core', 'B', 'Strength', 'Lie flat on your back with your feet flat on the ground, or resting on a bench with your knees bent at a 90 degree angle. If you are resting your feet on a bench, place them three to four inches apart and point your toes inward so they touch.', 'Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don''t lock your fingers behind your head.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Crunches/0.jpg'),
  ('00000000-0000-0000-0000-000000000189', 'Cuban Press', 'Shoulders', 'A', 'Strength', 'Take a dumbbell in each hand with a pronated grip in a standing position. Raise your upper arms so that they are parallel to the floor, allowing your lower arms to hang in the "scarecrow" position. This will be your starting position.', 'To initiate the movement, externally rotate the shoulders to move the upper arm 180 degrees. Keep the upper arms in place, rotating the upper arms until the wrists are directly above the elbows, the forearms perpendicular to the floor.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Cuban_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000190', 'Dancer''s Stretch', 'Back', 'S', 'Stretching', 'Sit up on the floor.', 'Cross your right leg over your left, keeping the knee bent. Your left leg is straight and down on the floor.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dancers_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000191', 'Dead Bug', 'Core', 'B', 'Strength', 'Begin lying on your back with your hands extended above you toward the ceiling.', 'Bring your feet, knees, and hips up to 90 degrees.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dead_Bug/0.jpg'),
  ('00000000-0000-0000-0000-000000000192', 'Deadlift with Bands', 'Back', 'A', 'Powerlifting', 'To deadlift with short bands, simply loop them over the bar before you start, and step into them to set up. For long bands, they will need to be anchored to a secure base, such as heavy dumbbells or a rack.', 'With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Deadlift_with_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000193', 'Deadlift with Chains', 'Back', 'B', 'Powerlifting', 'You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift.', 'Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets. With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Deadlift_with_Chains/0.jpg'),
  ('00000000-0000-0000-0000-000000000194', 'Decline Barbell Bench Press', 'Chest', 'B', 'Strength', 'Secure your legs at the end of the decline bench and slowly lay down on the bench.', 'Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Barbell_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000195', 'Decline Close-Grip Bench To Skull Crusher', 'Arms', 'S', 'Strength', 'Secure your legs at the end of the decline bench and slowly lay down on the bench.', 'Using a close grip (a grip that is slightly less than shoulder width), lift the bar from the rack and hold it straight over you with your arms locked and elbows in. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Close-Grip_Bench_To_Skull_Crusher/0.jpg'),
  ('00000000-0000-0000-0000-000000000196', 'Decline Crunch', 'Core', 'B', 'Strength', 'Secure your legs at the end of the decline bench and lie down.', 'Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don''t lock your fingers behind your head.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000197', 'Decline Dumbbell Bench Press', 'Chest', 'B', 'Strength', 'Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.', 'Once you are laying down, move the dumbbells in front of you at shoulder width.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Dumbbell_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000198', 'Decline Dumbbell Flyes', 'Chest', 'A', 'Strength', 'Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.', 'Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Dumbbell_Flyes/0.jpg'),
  ('00000000-0000-0000-0000-000000000199', 'Decline Dumbbell Triceps Extension', 'Arms', 'B', 'Strength', 'Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.', 'Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000200', 'Decline EZ Bar Triceps Extension', 'Arms', 'S', 'Strength', 'Secure your legs at the end of the decline bench and slowly lay down on the bench.', 'Using a close grip (a grip that is slightly less than shoulder width), lift the EZ bar from the rack and hold it straight over you with your arms locked and elbows in. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_EZ_Bar_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000201', 'Decline Oblique Crunch', 'Core', 'A', 'Strength', 'Secure your legs at the end of the decline bench and slowly lay down on the bench.', 'Raise your upper body off the bench until your torso is about 35-45 degrees if measured from the floor.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Oblique_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000202', 'Decline Push-Up', 'Chest', 'B', 'Strength', 'Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length. Move your feet up to a box or bench. This will be your starting position.', 'Next, lower yourself downward until your chest almost touches the floor as you inhale.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Push-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000203', 'Decline Reverse Crunch', 'Core', 'B', 'Strength', 'Lie on your back on a decline bench and hold on to the top of the bench with both hands. Don''t let your body slip down from this position.', 'Hold your legs parallel to the floor using your abs to hold them there while keeping your knees and feet together. Tip: Your legs should be fully extended with a slight bend on the knee. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Reverse_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000204', 'Decline Smith Press', 'Chest', 'A', 'Strength', 'Place a decline bench underneath the Smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms extended. This will be your starting position.', 'As you inhale, lower the bar under control by allowing the elbows to flex, lightly contacting the torso.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Smith_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000205', 'Deficit Deadlift', 'Back', 'S', 'Powerlifting', 'Begin by having a platform or weight plates that you can stand on, usually 1-3 inches in height. Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets.', 'With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Deficit_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000206', 'Depth Jump Leap', 'Legs', 'B', 'Plyometrics', 'For this drill you will need two boxes or benches, one 12 to 16 inches high and the other 22 to 26 inches high.', 'Stand on one of the two boxes with arms at the sides; feet should be together and slightly off the edge as in the depth jump. Place the other box approximately two or three feet in front of and facing the performer.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Depth_Jump_Leap/0.jpg'),
  ('00000000-0000-0000-0000-000000000207', 'Dip Machine', 'Arms', 'A', 'Strength', 'Sit securely in a dip machine, select the weight and firmly grasp the handles.', 'Now keep your elbows in at your sides in order to place emphasis on the triceps. The elbows should be bent at a 90 degree angle.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dip_Machine/0.jpg'),
  ('00000000-0000-0000-0000-000000000208', 'Dips - Chest Version', 'Chest', 'B', 'Strength', 'For this exercise you will need access to parallel bars. To get yourself into the starting position, hold your body at arms length (arms locked) above the bars.', 'While breathing in, lower yourself slowly with your torso leaning forward around 30 degrees or so and your elbows flared out slightly until you feel a slight stretch in the chest.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dips_-_Chest_Version/0.jpg'),
  ('00000000-0000-0000-0000-000000000209', 'Dips - Triceps Version', 'Arms', 'B', 'Strength', 'To get into the starting position, hold your body at arm''s length with your arms nearly locked above the bars.', 'Now, inhale and slowly lower yourself downward. Your torso should remain upright and your elbows should stay close to your body. This helps to better focus on tricep involvement. Lower yourself until there is a 90 degree angle formed between the upper arm and forearm.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dips_-_Triceps_Version/0.jpg'),
  ('00000000-0000-0000-0000-000000000210', 'Donkey Calf Raises', 'Legs', 'S', 'Strength', 'For this exercise you will need access to a donkey calf raise machine. Start by positioning your lower back and hips under the padded lever provided. The tailbone area should be the one making contact with the pad.', 'Place both of your arms on the side handles and place the balls of your feet on the calf block with the heels extending off. Align the toes forward, inward or outward, depending on the area you wish to target, and straighten the knees without locking them. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Donkey_Calf_Raises/0.jpg'),
  ('00000000-0000-0000-0000-000000000211', 'Double Kettlebell Alternating Hang Clean', 'Legs', 'B', 'Strength', 'Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.', 'Clean one kettlebell to your shoulder and hold on to the other kettlebell.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Alternating_Hang_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000212', 'Double Kettlebell Jerk', 'Shoulders', 'B', 'Strength', 'Hold a kettlebell by the handle in each hand.', 'Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. This will be your starting position.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000213', 'Double Kettlebell Push Press', 'Shoulders', 'A', 'Strength', 'Clean two kettlebells to your shoulders.', 'Squat down a few inches and reverse the motion rapidly. Use the momentum from the legs to drive the kettlebells overhead.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Push_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000214', 'Double Kettlebell Snatch', 'Shoulders', 'B', 'Strength', 'Place two kettlebells behind your feet. Bend your knees and sit back to pick up the kettlebells.', 'Swing the kettlebells between your legs forcefully and reverse the direction.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000215', 'Double Kettlebell Windmill', 'Core', 'S', 'Strength', 'Place a kettlebell in front of your front foot and clean and press a kettlebell overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward.', 'Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Kettlebell_Windmill/0.jpg'),
  ('00000000-0000-0000-0000-000000000216', 'Double Leg Butt Kick', 'Legs', 'A', 'Plyometrics', 'Begin standing with your knees slightly bent.', 'Quickly squat a short distance, flexing the hips and knees, and immediately extend to jump for maximum vertical height.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Double_Leg_Butt_Kick/0.jpg'),
  ('00000000-0000-0000-0000-000000000217', 'Downward Facing Balance', 'Legs', 'B', 'Strength', 'Lie facedown on top of an exercise ball.', 'While resting on your stomach on the ball, walk your hands forward along the floor and lift your legs, extending your elbows and knees.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Downward_Facing_Balance/0.jpg'),
  ('00000000-0000-0000-0000-000000000218', 'Drag Curl', 'Arms', 'B', 'Strength', 'Grab a barbell with a supinated grip (palms facing forward) and get your elbows close to your torso and back. This will be your starting position.', 'As you exhale, curl the bar up while keeping the elbows to the back as you "Drag" the bar up by keeping it in contact with your torso. Tip: As you can see, you will not be keeping the elbows pinned to your sides, but instead you will be bringing them back. Also, do not lift your shoulders.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Drag_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000219', 'Drop Push', 'Chest', 'A', 'Plyometrics', 'Position low boxes or other platforms 2-3 feet apart.', 'Move to a pushup position between them, supporting yourself by placing your hands on the boxes.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Drop_Push/0.jpg'),
  ('00000000-0000-0000-0000-000000000220', 'Dumbbell Alternate Bicep Curl', 'Arms', 'S', 'Strength', 'Stand (torso upright) with a dumbbell in each hand held at arms length. The elbows should be close to the torso and the palms of your hand should be facing your thighs.', 'While holding the upper arm stationary, curl the right weight as you rotate the palm of the hands until they are facing forward. At this point continue contracting the biceps as you breathe out until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Alternate_Bicep_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000221', 'Dumbbell Bench Press', 'Chest', 'B', 'Strength', 'Lie down on a flat bench with a dumbbell in each hand resting on top of your thighs. The palms of your hands will be facing each other.', 'Then, using your thighs to help raise the dumbbells up, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000222', 'Dumbbell Bench Press with Neutral Grip', 'Chest', 'A', 'Strength', 'Take a dumbbell in each hand and lay back onto a flat bench. Your feet should be flat on the floor and your shoulder blades retracted.', 'Maintaining a neutral grip, palms facing each other, begin with your arms extended directly above you, perpendicular to the floor. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Bench_Press_with_Neutral_Grip/0.jpg'),
  ('00000000-0000-0000-0000-000000000223', 'Dumbbell Bicep Curl', 'Arms', 'B', 'Strength', 'Stand up straight with a dumbbell in each hand at arm''s length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.', 'Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Bicep_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000224', 'Dumbbell Clean', 'Legs', 'B', 'Strength', 'Begin standing with a dumbbell in each hand with your feet shoulder width apart.', 'Lower the weights to the floor by flexing at the hips and knees, pushing your hips back until the dumbbells reach the floor. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000225', 'Dumbbell Floor Press', 'Arms', 'S', 'Powerlifting', 'Lay on the floor holding dumbbells in your hands. Your knees can be bent. Begin with the weights fully extended above you.', 'Lower the weights until your upper arm comes in contact with the floor. You can tuck your elbows to emphasize triceps size and strength, or to focus on your chest angle your arms to the side.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Floor_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000226', 'Dumbbell Flyes', 'Chest', 'B', 'Strength', 'Lie down on a flat bench with a dumbbell on each hand resting on top of your thighs. The palms of your hand will be facing each other.', 'Then using your thighs to help raise the dumbbells, lift the dumbbells one at a time so you can hold them in front of you at shoulder width with the palms of your hands facing each other. Raise the dumbbells up like you''re pressing them, but stop and hold just before you lock out. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Flyes/0.jpg'),
  ('00000000-0000-0000-0000-000000000227', 'Dumbbell Incline Row', 'Back', 'B', 'Strength', 'Using a neutral grip, lean into an incline bench.', 'Take a dumbbell in each hand with a neutral grip, beginning with the arms straight. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Incline_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000228', 'Dumbbell Incline Shoulder Raise', 'Shoulders', 'A', 'Strength', 'Sit on an Incline Bench while holding a dumbbell on each hand on top of your thighs.', 'Lift your legs up to kick the weights to your shoulders and lean back. Position the dumbbells above your shoulders with your arms extended. The arms should be perpendicular to the floor with your palms facing forward and knuckles pointing towards the ceiling. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Incline_Shoulder_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000229', 'Dumbbell Lunges', 'Legs', 'B', 'Strength', 'Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.', 'Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lunges/0.jpg'),
  ('00000000-0000-0000-0000-000000000230', 'Dumbbell Lying One-Arm Rear Lateral Raise', 'Shoulders', 'S', 'Strength', 'While holding a dumbbell in one hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench. The other hand can be used to hold to the leg of the bench for stability.', 'Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000231', 'Dumbbell Lying Pronation', 'Arms', 'A', 'Strength', 'Lie on a flat bench face down with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.', 'Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lying_Pronation/0.jpg'),
  ('00000000-0000-0000-0000-000000000232', 'Dumbbell Lying Rear Lateral Raise', 'Shoulders', 'B', 'Strength', 'While holding a dumbbell in each hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench.', 'Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lying_Rear_Lateral_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000233', 'Dumbbell Lying Supination', 'Arms', 'B', 'Strength', 'Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.', 'Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lying_Supination/0.jpg'),
  ('00000000-0000-0000-0000-000000000234', 'Dumbbell One-Arm Shoulder Press', 'Shoulders', 'A', 'Strength', 'Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.', 'Clean the dumbbell up to bring it to shoulder height. The other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_One-Arm_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000235', 'Dumbbell One-Arm Triceps Extension', 'Arms', 'S', 'Strength', 'Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.', 'Clean the dumbbell up to bring it to shoulder height and then extend the arm over your head so that the whole arm is perpendicular to the floor and next to your head. The dumbbell should be on top of you. The other hand can be kept fully extended to the side, by the waist, supporting the upper arm that has the dumbbell or grabbing a fixed surface.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_One-Arm_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000236', 'Dumbbell One-Arm Upright Row', 'Shoulders', 'B', 'Strength', 'Grab a dumbbell and stand up straight with your arm extended in front of you with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be resting on top of your thigh with the palm of your hands facing your thighs.', 'Keep the other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_One-Arm_Upright_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000237', 'Dumbbell Prone Incline Curl', 'Arms', 'A', 'Strength', 'Grab a dumbbell on each hand and lie face down on an incline bench with your shoulders near top of the incline. Your knees can rest on the seat or your legs can be straddled to the sides (my preferred way).', 'Let your arms extend and hang naturally in front of you so that they are perpendicular to the floor.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Prone_Incline_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000238', 'Dumbbell Raise', 'Shoulders', 'B', 'Strength', 'Grab a dumbbell in each arm and stand up straight with your arms extended by your sides with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be next to your thighs with the palm of your hands facing back.', 'Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be to the side of the body as you move them up. Continue to lift it until the dumbbells are nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000239', 'Dumbbell Rear Lunge', 'Legs', 'B', 'Strength', 'Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.', 'Step backward with your right leg around two feet or so from the left foot and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Tip: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground. Keep the torso upright during the lunge; flexible hip flexors are important. A long lunge emphasizes the Gluteus Maximus; a short lunge emphasizes Quadriceps.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Rear_Lunge/0.jpg'),
  ('00000000-0000-0000-0000-000000000240', 'Dumbbell Scaption', 'Shoulders', 'S', 'Strength', 'This corrective exercise strengthens the muscles that stabilize your shoulder blade. Hold a light weight in each hand, hanging at your sides. Your thumbs should pointing up.', 'Begin the movement raising your arms out in front of you, about 30 degrees off center. Your arms should be fully extended as you perform the movement.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Scaption/0.jpg'),
  ('00000000-0000-0000-0000-000000000241', 'Dumbbell Seated Box Jump', 'Legs', 'B', 'Plyometrics', 'Position a box a couple feet to the side of a bench. Hold a dumbbell to your chest with both hands and seat yourself on the bench facing the box. This will be your starting position.', 'Plant your feet firmly on the ground as you lean forward, extending through the hips and knees to jump up and forward.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Seated_Box_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000242', 'Dumbbell Seated One-Leg Calf Raise', 'Legs', 'B', 'Strength', 'Place a block on the floor about 12 inches from a flat bench.', 'Sit on a flat bench and place a dumbbell on your upper left thigh about 3 inches above your knee.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Seated_One-Leg_Calf_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000243', 'Dumbbell Shoulder Press', 'Shoulders', 'A', 'Strength', 'While holding a dumbbell in each hand, sit on a military press bench or utility bench that has back support. Place the dumbbells upright on top of your thighs.', 'Now raise the dumbbells to shoulder height one at a time using your thighs to help propel them up into position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000244', 'Dumbbell Shrug', 'Other', 'B', 'Strength', 'Stand erect with a dumbbell on each hand (palms facing your torso), arms extended on the sides.', 'Lift the dumbbells by elevating the shoulders as high as possible while you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the dumbbells. Only the shoulders should be moving up and down.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000245', 'Dumbbell Side Bend', 'Core', 'S', 'Strength', 'Stand up straight while holding a dumbbell on the left hand (palms facing the torso) as you have the right hand holding your waist. Your feet should be placed at shoulder width. This will be your starting position.', 'While keeping your back straight and your head up, bend only at the waist to the right as far as possible. Breathe in as you bend to the side. Then hold for a second and come back up to the starting position as you exhale. Tip: Keep the rest of the body stationary.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Side_Bend/0.jpg'),
  ('00000000-0000-0000-0000-000000000246', 'Dumbbell Squat', 'Legs', 'A', 'Strength', 'Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).', 'Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000247', 'Dumbbell Squat To A Bench', 'Legs', 'B', 'Strength', 'Stand up straight with a flat bench behind you while holding a dumbbell on each hand (palms facing the side of your legs).', 'Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Squat_To_A_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000248', 'Dumbbell Step Ups', 'Legs', 'B', 'Strength', 'Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).', 'Place the right foot on the elevated platform. Step on the platform by extending the hip and the knee of your right leg. Use the heel mainly to lift the rest of your body up and place the foot of the left leg on the platform as well. Breathe out as you execute the force required to come up.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Step_Ups/0.jpg'),
  ('00000000-0000-0000-0000-000000000249', 'Dumbbell Tricep Extension -Pronated Grip', 'Arms', 'A', 'Strength', 'Lie down on a flat bench holding two dumbbells directly above your shoulders. Your arms should be fully extended and form a 90 degree angle from your torso and the floor.', 'The palms of your hands should be facing forward, and your elbows should be tucked in. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Tricep_Extension_-Pronated_Grip/0.jpg'),
  ('00000000-0000-0000-0000-000000000250', 'Dynamic Back Stretch', 'Back', 'S', 'Stretching', 'Stand with your feet shoulder width apart. This will be your starting position.', 'Keeping your arms straight, swing them straight up in front of you 5-10 times, increasing the range of motion each time until your arms are above your head.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dynamic_Back_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000251', 'Dynamic Chest Stretch', 'Chest', 'B', 'Stretching', 'Stand with your hands together, arms extended directly in front of you. This will be your starting position.', 'Keeping your arms straight, quickly move your arms back as far as possible and back in again, similar to an exaggerated clapping motion. Repeat 5-10 times, increasing speed as you do so.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dynamic_Chest_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000252', 'EZ-Bar Curl', 'Arms', 'A', 'Strength', 'Stand up straight while holding an EZ curl bar at the wide outer handle. The palms of your hands should be facing forward and slightly tilted inward due to the shape of the bar. Keep your elbows close to your torso. This will be your starting position.', 'Now, while keeping your upper arms stationary, exhale and curl the weights forward while contracting the biceps. Focus on only moving your forearms.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/EZ-Bar_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000253', 'EZ-Bar Skullcrusher', 'Arms', 'B', 'Strength', 'Using a close grip, lift the EZ bar and hold it with your elbows in as you lie on the bench. Your arms should be perpendicular to the floor. This will be your starting position.', 'Keeping the upper arms stationary, lower the bar by allowing the elbows to flex. Inhale as you perform this portion of the movement. Pause once the bar is directly above the forehead.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/EZ-Bar_Skullcrusher/0.jpg'),
  ('00000000-0000-0000-0000-000000000254', 'Elbow Circles', 'Shoulders', 'B', 'Stretching', 'Sit or stand with your feet slightly apart.', 'Place your hands on your shoulders with your elbows at shoulder level and pointing out.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elbow_Circles/0.jpg'),
  ('00000000-0000-0000-0000-000000000255', 'Elbow to Knee', 'Core', 'S', 'Strength', 'Lie on the floor, crossing your right leg across your bent left knee. Clasp your hands behind your head, beginning with your shoulder blades on the ground. This will be your starting position.', 'Perform the motion by flexing the spine and rotating your torso to bring the left elbow to the right knee.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elbow_to_Knee/0.jpg'),
  ('00000000-0000-0000-0000-000000000256', 'Elbows Back', 'Chest', 'B', 'Stretching', 'Stand up straight.', 'Place both hands on your lower back, fingers pointing downward and elbows out.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elbows_Back/0.jpg'),
  ('00000000-0000-0000-0000-000000000257', 'Elevated Back Lunge', 'Legs', 'B', 'Strength', 'Position a bar onto a rack at shoulder height loaded to an appropriate weight. Place a short, raised platform behind you.', 'Rack the bar onto your upper back, keeping your back arched and tight. Step onto your raised platform with both feet. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elevated_Back_Lunge/0.jpg'),
  ('00000000-0000-0000-0000-000000000258', 'Elevated Cable Rows', 'Back', 'A', 'Strength', 'Get a platform of some sort (it can be an aerobics or calf raise platform) that is around 4-6 inches in height.', 'Place it on the seat of the cable row machine.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elevated_Cable_Rows/0.jpg'),
  ('00000000-0000-0000-0000-000000000259', 'Elliptical Trainer', 'Legs', 'B', 'Cardio', 'To begin, step onto the elliptical and select the desired option from the menu. Most ellipticals have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.', 'The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Elliptical_Trainer/0.jpg'),
  ('00000000-0000-0000-0000-000000000260', 'Exercise Ball Crunch', 'Core', 'S', 'Strength', 'Lie on an exercise ball with your lower back curvature pressed against the spherical surface of the ball. Your feet should be bent at the knee and pressed firmly against the floor. The upper torso should be hanging off the top of the ball. The arms should either be kept alongside the body or crossed on top of your chest as these positions avoid neck strains (as opposed to the hands behind the back of the head position).', 'Lower your torso into a stretch position keeping the neck stationary at all times. This will be your starting position.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Exercise_Ball_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000261', 'Exercise Ball Pull-In', 'Core', 'A', 'Strength', 'Place an exercise ball nearby and lay on the floor in front of it with your hands on the floor shoulder width apart in a push-up position.', 'Now place your lower shins on top of an exercise ball. Tip: At this point your legs should be fully extended with the shins on top of the ball and the upper body should be in a push-up type of position being supported by your two extended arms in front of you. This will be your starting position.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Exercise_Ball_Pull-In/0.jpg'),
  ('00000000-0000-0000-0000-000000000262', 'Extended Range One-Arm Kettlebell Floor Press', 'Chest', 'B', 'Strength', 'Lie on the floor and position a kettlebell for one arm to press. The kettlebell should be held by the handle. The leg on the same side that you are pressing should be bent, with the knee crossing over the midline of the body.', 'Press the kettlebell by extending the elbow and adducting the arm, pressing it above your body. Return to the starting position.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Extended_Range_One-Arm_Kettlebell_Floor_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000263', 'External Rotation', 'Shoulders', 'B', 'Strength', 'Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.', 'Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm. Tip: Keep the arm parallel to your torso.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/External_Rotation/0.jpg'),
  ('00000000-0000-0000-0000-000000000264', 'External Rotation with Band', 'Shoulders', 'A', 'Strength', 'Choke the band around a post. The band should be at the same height as your elbow. Stand with your left side to the band a couple of feet away.', 'Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/External_Rotation_with_Band/0.jpg'),
  ('00000000-0000-0000-0000-000000000265', 'External Rotation with Cable', 'Shoulders', 'S', 'Strength', 'Adjust the cable to the same height as your elbow. Stand with your left side to the band a couple of feet away.', 'Grasp the handle with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/External_Rotation_with_Cable/0.jpg'),
  ('00000000-0000-0000-0000-000000000266', 'Face Pull', 'Shoulders', 'B', 'Strength', 'Facing a high pulley with a rope or dual handles attached, pull the weight directly towards your face, separating your hands as you do so. Keep your upper arms parallel to the ground.', 'Targets shoulders.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Face_Pull/0.jpg'),
  ('00000000-0000-0000-0000-000000000267', 'Farmer''s Walk', 'Arms', 'A', 'Strongman', 'There are various implements that can be used for the farmers walk. These can also be performed with heavy dumbbells or short bars if these implements aren''t available. Begin by standing between the implements.', 'After gripping the handles, lift them up by driving through your heels, keeping your back straight and your head up.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Farmers_Walk/0.jpg'),
  ('00000000-0000-0000-0000-000000000268', 'Fast Skipping', 'Legs', 'B', 'Plyometrics', 'Start in a relaxed position with one leg slightly forward. This will be your starting position.', 'Skip by executing a step-hop pattern of right-right-step to left-left-step, and so on, alternating back and forth.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Fast_Skipping/0.jpg'),
  ('00000000-0000-0000-0000-000000000269', 'Finger Curls', 'Arms', 'B', 'Strength', 'Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.', 'Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Finger_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000270', 'Flat Bench Cable Flyes', 'Chest', 'S', 'Strength', 'Position a flat bench between two low pulleys so that when you are laying on it, your chest will be lined up with the cable pulleys.', 'Lay flat on the bench and keep your feet on the ground.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Flat_Bench_Cable_Flyes/0.jpg'),
  ('00000000-0000-0000-0000-000000000271', 'Flat Bench Leg Pull-In', 'Core', 'B', 'Strength', 'Lie on an exercise mat or a flat bench with your legs off the end.', 'Place your hands either under your glutes with your palms down or by the sides holding on to the bench (or with palms down by the side on an exercise mat). Also extend your legs straight out. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Flat_Bench_Leg_Pull-In/0.jpg'),
  ('00000000-0000-0000-0000-000000000272', 'Flat Bench Lying Leg Raise', 'Core', 'B', 'Strength', 'Lie with your back flat on a bench and your legs extended in front of you off the end.', 'Place your hands either under your glutes with your palms down or by the sides holding on to the bench. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Flat_Bench_Lying_Leg_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000273', 'Flexor Incline Dumbbell Curls', 'Arms', 'A', 'Strength', 'Hold the dumbbell towards the side farther from you so that you have more weight on the side closest to you. (This can be done for a good effect on all bicep dumbbell exercises). Now do a normal incline dumbbell curl, but keep your wrists as far back as possible so as to neutralize any stress that is placed on them.', 'Sit on an incline bench that is angled at 45-degrees while holding a dumbbell on each hand.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Flexor_Incline_Dumbbell_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000274', 'Floor Glute-Ham Raise', 'Legs', 'B', 'Strength', 'You can use a partner for this exercise or brace your feet under something stable.', 'Begin on your knees with your upper legs and torso upright. If using a partner, they will firmly hold your feet to keep you in position. This will be your starting position.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Floor_Glute-Ham_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000275', 'Floor Press', 'Arms', 'S', 'Powerlifting', 'Adjust the j-hooks so they are at the appropriate height to rack the bar. Begin lying on the floor with your head near the end of a power rack. Keeping your shoulder blades pulled together; pull the bar off of the hooks.', 'Lower the bar towards the bottom of your chest or upper stomach, squeezing the bar and attempting to pull it apart as you do so. Ensure that you tuck your elbows throughout the movement. Lower the bar until your upper arm contacts the ground and pause, preventing any slamming or bouncing of the weight.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Floor_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000276', 'Floor Press with Chains', 'Arms', 'A', 'Powerlifting', 'Adjust the j-hooks so they are at the appropriate height to rack the bar. For this exercise, drape the chains directly over the end of the bar, trying to keep the ends away from the plates.', 'Begin lying on the floor with your head near the end of a power rack. Keeping your shoulder blades pulled together, pull the bar off of the hooks.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Floor_Press_with_Chains/0.jpg'),
  ('00000000-0000-0000-0000-000000000277', 'Flutter Kicks', 'Legs', 'B', 'Strength', 'On a flat bench lie facedown with the hips on the edge of the bench, the legs straight with toes high off the floor and with the arms on top of the bench holding on to the front edge.', 'Squeeze your glutes and hamstrings and straighten the legs until they are level with the hips. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Flutter_Kicks/0.jpg'),
  ('00000000-0000-0000-0000-000000000278', 'Foot-SMR', 'Legs', 'B', 'Stretching', 'This exercise stretches the fascia of the muscles in the feet. Start off seated with your shoes removed. Using a foot roller or a similar object, such as a small section of pvc pipe, place your foot against the roller across the arch of your foot. This will be your starting position.', 'Press down firmly, rolling across the arch of your foot. Hold for 10-30 seconds, and then switch feet.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Foot-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000279', 'Forward Drag with Press', 'Chest', 'A', 'Strongman', 'Attach a dual handled chain or rope attachment to the sled. You should be facing away from the sled, holding a handle in each hand.', 'Begin the movement by moving forward for one step. Leaning forward, extend through the legs and hips to move, pausing with each step to extend through the elbows, pressing your hands forward. Step forward until you return to the start position prepared to press.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Forward_Drag_with_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000280', 'Frankenstein Squat', 'Legs', 'S', 'Olympic weightlifting', 'This drill teaches you the proper positioning of both the bar and your body during the clean and front squat.', 'Place the barbell on the front of the shoulders, releasing your grip and extending your arms out in front of you. The shoulders should be pushed forward to create a shelf, and the bar should be in contact with the throat. Ensure that you only move your shoulder blades forward; don''t round the thoracic spine.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Frankenstein_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000281', 'Freehand Jump Squat', 'Legs', 'B', 'Strength', 'Cross your arms over your chest.', 'With your head up and your back straight, position your feet at shoulder width.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Freehand_Jump_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000282', 'Frog Hops', 'Legs', 'A', 'Stretching', 'Stand with your hands behind your head, and squat down keeping your torso upright and your head up. This will be your starting position.', 'Jump forward several feet, avoiding jumping unnecessarily high. As your feet contact the ground, absorb the impact through your legs, and jump again. Repeat this action 5-10 times.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Frog_Hops/0.jpg'),
  ('00000000-0000-0000-0000-000000000283', 'Frog Sit-Ups', 'Core', 'B', 'Strength', 'Lie with your back flat on the floor (or exercise mat) and your legs extended in front of you.', 'Now bend at the knees and place your outer thighs by the floor (or mat) as you make the soles of your feet touch each other.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Frog_Sit-Ups/0.jpg'),
  ('00000000-0000-0000-0000-000000000284', 'Front Barbell Squat', 'Legs', 'B', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, bring your arms up under the bar while keeping the elbows high and the upper arm slightly above parallel to the floor. Rest the bar on top of the deltoids and cross your arms while grasping the bar for total control.', 'Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Barbell_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000285', 'Front Barbell Squat To A Bench', 'Legs', 'S', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set a flat bench behind you and set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, bring your arms up under the bar while keeping the elbows high and the upper arm slightly above parallel to the floor. Rest the bar on top of the deltoids and cross your arms while grasping the bar for total control.', 'Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Barbell_Squat_To_A_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000286', 'Front Box Jump', 'Legs', 'B', 'Plyometrics', 'Begin with a box of an appropriate height 1-2 feet in front of you. Stand with your feet should width apart. This will be your starting position.', 'Perform a short squat in preparation for jumping, swinging your arms behind you.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Box_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000287', 'Front Cable Raise', 'Shoulders', 'B', 'Strength', 'Select the weight on a low pulley machine and grasp the single hand cable attachment that is attached to the low pulley with your left hand.', 'Face away from the pulley and put your arm straight down with the hand cable attachment in front of your thighs at arms'' length with the palms of the hand facing your thighs. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Cable_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000288', 'Front Cone Hops (or hurdle hops)', 'Legs', 'A', 'Plyometrics', 'Set up a row of cones or other small barriers, placing them a few feet apart.', 'Stand in front of the first cone with your feet shoulder width apart. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Cone_Hops_or_hurdle_hops/0.jpg'),
  ('00000000-0000-0000-0000-000000000289', 'Front Dumbbell Raise', 'Shoulders', 'B', 'Strength', 'Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.', 'While maintaining the torso stationary (no swinging), lift the left dumbbell to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top. Inhale after the second pause.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Dumbbell_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000290', 'Front Incline Dumbbell Raise', 'Shoulders', 'S', 'Strength', 'Sit down on an incline bench with the incline set anywhere between 30 to 60 degrees while holding a dumbbell on each hand. Tip: You can change the angle to hit the muscle a little differently each time.', 'Extend your arms straight in front of you and have your palms facing down with the dumbbells raised about 1 inch above your thighs. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Incline_Dumbbell_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000291', 'Front Leg Raises', 'Legs', 'A', 'Stretching', 'Stand next to a chair or other support, holding on with one hand.', 'Swing your leg forward, keeping the leg straight. Continue with a downward swing, bringing the leg as far back as your flexibility allows. Repeat 5-10 times, and then switch legs.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Leg_Raises/0.jpg'),
  ('00000000-0000-0000-0000-000000000292', 'Front Plate Raise', 'Shoulders', 'B', 'Strength', 'While standing straight, hold a barbell plate in both hands at the 3 and 9 o''clock positions. Your palms should be facing each other and your arms should be extended and locked with a slight bend at the elbows and the plate should be down near your waist in front of you as far as you can go. Tip: The arms will remain in this position throughout the exercise. This will be your starting position.', 'Slowly raise the plate as you exhale until it is a little above shoulder level. Hold the contraction for a second. Tip: make sure that you do not swing the weight or bend at the elbows. Your torso should remain stationary throughout the movement as well.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Plate_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000293', 'Front Raise And Pullover', 'Chest', 'B', 'Strength', 'Lie on a flat bench while holding a barbell using a palms down grip that is about 15 inches apart.', 'Place the bar on your upper thighs, extend your arms and lock them while keeping a slight bend on the elbows. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Raise_And_Pullover/0.jpg'),
  ('00000000-0000-0000-0000-000000000294', 'Front Squat (Clean Grip)', 'Legs', 'A', 'Strength', 'To begin, first set the bar in a rack slightly below shoulder level. Rest the bar on top of the deltoids, pushing into the clavicles, and lightly touching the throat. Your hands should be in a clean grip, touching the bar only with your fingers to help keep it in position.', 'Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso. Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head and elbows up at all times. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Squat_Clean_Grip/0.jpg'),
  ('00000000-0000-0000-0000-000000000295', 'Front Squats With Two Kettlebells', 'Legs', 'S', 'Strength', 'Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so.', 'Looking straight ahead at all times, squat as low as you can and pause at the bottom. As you squat down, push your knees out. You should squat between your legs, keeping an upright torso, with your head and chest up.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Squats_With_Two_Kettlebells/0.jpg'),
  ('00000000-0000-0000-0000-000000000296', 'Front Two-Dumbbell Raise', 'Shoulders', 'B', 'Strength', 'Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.', 'While maintaining the torso stationary (no swinging), lift the dumbbells to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arms are slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Front_Two-Dumbbell_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000297', 'Full Range-Of-Motion Lat Pulldown', 'Back', 'A', 'Strength', 'Either standing or seated on a high bench, grasp two stirrup cables that are attached to the high pulleys. Grab with the opposing hand so your arms are crisscrossed about you and your palms are facing forward.', 'Keeping your chest up and maintaining a slight arch in your lower back, pull the handles down as if you were doing a regular pulldown. The range of motion will be more of an arc. During the movement, rotate your hands so that in the bottom position your palms face each other rather than forward. Return slowly to the starting position and repeat.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Full_Range-Of-Motion_Lat_Pulldown/0.jpg'),
  ('00000000-0000-0000-0000-000000000298', 'Gironda Sternum Chins', 'Back', 'B', 'Strength', 'Grasp the pull-up bar with a shoulder width underhand grip.', 'Now hang with your arms fully extended and stick your chest out and lean back. Tip: You will be leaning back throughout the entire movement. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Gironda_Sternum_Chins/0.jpg'),
  ('00000000-0000-0000-0000-000000000299', 'Glute Ham Raise', 'Legs', 'B', 'Powerlifting', 'Begin by adjusting the equipment to fit your body. Place your feet against the footplate in between the rollers as you lie facedown. Your knees should be just behind the pad.', 'Start from the bottom of the movement. Keep your back arched as you begin the movement by flexing the knees. Drive your toes into the foot plate as you do so. Keep your upper body straight, and continue until your body is upright.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Glute_Ham_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000300', 'Glute Kickback', 'Legs', 'S', 'Strength', 'Kneel on the floor or an exercise mat and bend at the waist with your arms extended in front of you (perpendicular to the torso) in order to get into a kneeling push-up position but with the arms spaced at shoulder width. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.', 'As you exhale, lift up your right leg until the hamstrings are in line with the back while maintaining the 90-degree angle bend. Contract the glutes throughout this movement and hold the contraction at the top for a second. Tip: At the end of the movement the upper leg should be parallel to the floor while the calf should be perpendicular to it.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Glute_Kickback/0.jpg'),
  ('00000000-0000-0000-0000-000000000301', 'Goblet Squat', 'Legs', 'B', 'Strength', 'Stand holding a light kettlebell by the horns close to your chest. This will be your starting position.', 'Squat down between your legs until your hamstrings are on your calves. Keep your chest and head up and your back straight.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Goblet_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000302', 'Good Morning', 'Legs', 'B', 'Powerlifting', 'Begin with a bar on a rack at shoulder height. Rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Step back from the rack.', 'Begin by bending at the hips, moving them back as you bend over to near parallel. Keep your back arched and your cervical spine in proper alignment.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Good_Morning/0.jpg'),
  ('00000000-0000-0000-0000-000000000303', 'Good Morning off Pins', 'Legs', 'A', 'Powerlifting', 'Begin with a bar on a rack at about the same height as your stomach. Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.', 'Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight. Slowly lower the weight back to the pins returning to the starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Good_Morning_off_Pins/0.jpg'),
  ('00000000-0000-0000-0000-000000000304', 'Gorilla Chin/Crunch', 'Core', 'B', 'Strength', 'Hang from a chin-up bar using an underhand grip (palms facing you) that is slightly wider than shoulder width.', 'Now bend your knees at a 90 degree angle so that the calves are parallel to the floor while the thighs remain perpendicular to it. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Gorilla_Chin_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000305', 'Groin and Back Stretch', 'Legs', 'S', 'Stretching', 'Sit on the floor with your knees bent and feet together.', 'Interlock your fingers behind your head. This will be your starting position.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Groin_and_Back_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000306', 'Groiners', 'Legs', 'A', 'Stretching', 'Begin in a pushup position on the floor. This will be your starting position.', 'Using both legs, jump forward landing with your feet next to your hands. Keep your head up as you do so.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Groiners/0.jpg'),
  ('00000000-0000-0000-0000-000000000307', 'Hack Squat', 'Legs', 'B', 'Strength', 'Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.', 'Position your legs in the platform using a shoulder width medium stance with the toes slightly pointed out. Tip: Keep your head up at all times and also maintain the back on the pad at all times.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hack_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000308', 'Hammer Curls', 'Arms', 'B', 'Strength', 'Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.', 'The palms of the hands should be facing your torso. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hammer_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000309', 'Hammer Grip Incline DB Bench Press', 'Chest', 'A', 'Strength', 'Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.', 'By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hammer_Grip_Incline_DB_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000310', 'Hamstring-SMR', 'Legs', 'S', 'Stretching', 'In a seated position, extend your legs over a foam roll so that it is position on the back of the upper legs. Place your hands to the side or behind you to help support your weight. This will be your starting position.', 'Using your hands, lift your hips off of the floor and shift your weight on the foam roll to one leg. Relax the hamstrings of the leg you are stretching.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hamstring-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000311', 'Hamstring Stretch', 'Legs', 'B', 'Stretching', 'Lie on your back with one leg extended above you, with the hip at ninety degrees. Keep the other leg flat on the floor.', 'Loop a belt, band, or rope over the ball of your foot. This will be your starting position.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hamstring_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000312', 'Handstand Push-Ups', 'Shoulders', 'A', 'Strength', 'With your back to the wall bend at the waist and place both hands on the floor at shoulder width.', 'Kick yourself up against the wall with your arms straight. Your body should be upside down with the arms and legs fully extended. Keep your whole body as straight as possible. Tip: If doing this for the first time, have a spotter help you. Also, make sure that you keep facing the wall with your head, rather than looking down.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Handstand_Push-Ups/0.jpg'),
  ('00000000-0000-0000-0000-000000000313', 'Hang Clean', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.', 'Begin by aggressively extending through the hips, knees and ankles, driving the weight upward. As you do so, shrug your shoulders towards your ears.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000314', 'Hang Clean - Below the Knees', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a shoulder width, double overhand or hook grip, with the bar hanging just below the knees. Your back should be straight and inclined slightly forward.', 'Begin by aggressively extending through the hips, knees and ankles, driving the weight upward. As you do so, shrug your shoulders towards your ears. As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Clean_-_Below_the_Knees/0.jpg'),
  ('00000000-0000-0000-0000-000000000315', 'Hang Snatch', 'Legs', 'S', 'Olympic weightlifting', 'Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be at the hips. This will be your starting position.', 'Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000316', 'Hang Snatch - Below Knees', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be just below the knees. This will be your starting position.', 'Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Snatch_-_Below_Knees/0.jpg'),
  ('00000000-0000-0000-0000-000000000317', 'Hanging Bar Good Morning', 'Legs', 'B', 'Powerlifting', 'Begin with a bar on a rack at about the same height as your stomach. Suspend the bar using chains or suspension straps.', 'Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your traps. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Bar_Good_Morning/0.jpg'),
  ('00000000-0000-0000-0000-000000000318', 'Hanging Leg Raise', 'Core', 'A', 'Strength', 'Hang from a chin-up bar with both arms extended at arms length in top of you using either a wide grip or a medium grip. The legs should be straight down with the pelvis rolled slightly backwards. This will be your starting position.', 'Raise your legs until the torso makes a 90-degree angle with the legs. Exhale as you perform this movement and hold the contraction for a second or so.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Leg_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000319', 'Hanging Pike', 'Core', 'B', 'Strength', 'Hang from a chin-up bar with your legs and feet together using an overhand grip (palms facing away from you) that is slightly wider than shoulder width. Tip: You may use wrist wraps in order to facilitate holding on to the bar.', 'Now bend your knees at a 90 degree angle and bring the upper legs forward so that the calves are perpendicular to the floor while the thighs remain parallel to it. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Pike/0.jpg'),
  ('00000000-0000-0000-0000-000000000320', 'Heaving Snatch Balance', 'Legs', 'S', 'Olympic weightlifting', 'This drill helps you learn the snatch. Begin by holding a light weight across the back of the shoulders. Your feet should be slightly wider than hip width apart with the feet turned out, the same position that you would perform a squat with.', 'Begin by dipping with the knees slightly, and popping back up to briefly unload the bar. Drive yourself underneath the bar, elevating it overhead as you descend into a full squat.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heaving_Snatch_Balance/0.jpg'),
  ('00000000-0000-0000-0000-000000000321', 'Heavy Bag Thrust', 'Chest', 'A', 'Plyometrics', 'Utilize a heavy bag for this exercise. Assume an upright stance next to the bag, with your feet staggered, fairly wide apart. Place your hand on the bag at about chest height. This will be your starting position.', 'Begin by twisting at the waist, pushing the bag forward as hard as possible. Perform this move quickly, pushing the bag away from your body.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heavy_Bag_Thrust/0.jpg'),
  ('00000000-0000-0000-0000-000000000322', 'High Cable Curls', 'Arms', 'B', 'Strength', 'Stand between a couple of high pulleys and grab a handle in each arm. Position your upper arms in a way that they are parallel to the floor with the palms of your hands facing you. This will be your starting position.', 'Curl the handles towards you until they are next to your ears. Make sure that as you do so you flex your biceps and exhale. The upper arms should remain stationary and only the forearms should move. Hold for a second in the contracted position as you squeeze the biceps.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/High_Cable_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000323', 'Hip Circles (prone)', 'Legs', 'B', 'Stretching', 'Position yourself on your hands and knees on the ground. Maintaining good posture, raise one bent knee off of the ground. This will be your starting position.', 'Keeping the knee in a bent position, rotate the femur in an arc, attempting to make a big circle with your knee.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Circles_prone/0.jpg'),
  ('00000000-0000-0000-0000-000000000324', 'Hip Extension with Bands', 'Legs', 'A', 'Strength', 'Secure one end of the band to the lower portion of a post and attach the other to one ankle.', 'Facing the attachment point of the band, hold on to the column to stabilize yourself.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Extension_with_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000325', 'Hip Flexion with Band', 'Legs', 'S', 'Strength', 'Secure one end of the band to the lower portion of a post and attach the other to one ankle.', 'Face away from the attachment point of the band.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Flexion_with_Band/0.jpg'),
  ('00000000-0000-0000-0000-000000000326', 'Hip Lift with Band', 'Legs', 'B', 'Powerlifting', 'After choosing a suitable band, lay down in the middle of the rack, after securing the band on either side of you. If your rack doesn''t have pegs, the band can be secured using heavy dumbbells or similar objects, just ensure they won''t move.', 'Adjust your position so that the band is directly over your hips. Bend your knees and place your feet flat on the floor. Your hands can be on the floor or holding the band in position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Lift_with_Band/0.jpg'),
  ('00000000-0000-0000-0000-000000000327', 'Hug A Ball', 'Back', 'A', 'Stretching', 'Seat yourself on the floor.', 'Straddle an exercise ball between both legs and lower your hips down toward the floor.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_A_Ball/0.jpg'),
  ('00000000-0000-0000-0000-000000000328', 'Hug Knees To Chest', 'Back', 'B', 'Stretching', 'Lie down on your back and pull both knees up to your chest.', 'Hold your arms under the knees, not over (that would put to much pressure on your knee joints).', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_Knees_To_Chest/0.jpg'),
  ('00000000-0000-0000-0000-000000000329', 'Hurdle Hops', 'Legs', 'B', 'Plyometrics', 'Set up a row of hurdles or other small barriers, placing them a few feet apart.', 'Stand in front of the first hurdle with your feet shoulder width apart. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hurdle_Hops/0.jpg'),
  ('00000000-0000-0000-0000-000000000330', 'Hyperextensions (Back Extensions)', 'Back', 'S', 'Strength', 'Lie face down on a hyperextension bench, tucking your ankles securely under the footpads.', 'Adjust the upper pad if possible so your upper thighs lie flat across the wide pad, leaving enough room for you to bend at the waist without any restriction.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hyperextensions_Back_Extensions/0.jpg'),
  ('00000000-0000-0000-0000-000000000331', 'Hyperextensions With No Hyperextension Bench', 'Back', 'B', 'Strength', 'With someone holding down your legs, slide yourself down to the edge a flat bench until your hips hang off the end of the bench. Tip: Your entire upper body should be hanging down towards the floor. Also, you will be in the same position as if you were on a hyperextension bench but the range of motion will be shorter due to the height of the flat bench vs. that of the hyperextension bench.', 'With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hyperextensions_With_No_Hyperextension_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000332', 'IT Band and Glute Stretch', 'Legs', 'B', 'Stretching', 'Loop a belt, rope, or band around one of your feet, and swing that leg across your body to the opposite side, keeping the leg extended as you lay on the ground. This will be your starting position.', 'Keeping your foot off of the floor, pull on the belt, using the tension to pull the toes up. Hold for 10-20 seconds, and repeat on the other side.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/IT_Band_and_Glute_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000333', 'Iliotibial Tract-SMR', 'Legs', 'A', 'Stretching', 'Lay on your side, with the bottom leg placed onto a foam roller between the hip and the knee. The other leg can be crossed in front of you.', 'Place as much of your weight as is tolerable onto your bottom leg; there is no need to keep your bottom leg in contact with the ground. Be sure to relax the muscles of the leg you are stretching.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iliotibial_Tract-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000334', 'Inchworm', 'Legs', 'B', 'Stretching', 'Stand with your feet close together. Keeping your legs straight, stretch down and put your hands on the floor directly in front of you. This will be your starting position.', 'Begin by walking your hands forward slowly, alternating your left and your right. As you do so, bend only at the hip, keeping your legs straight.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inchworm/0.jpg'),
  ('00000000-0000-0000-0000-000000000335', 'Incline Barbell Triceps Extension', 'Arms', 'S', 'Strength', 'Hold a barbell with an overhand grip (palms down) that is a little closer together than shoulder width.', 'Lie back on an incline bench set at any angle between 45-75-degrees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Barbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000336', 'Incline Bench Pull', 'Back', 'A', 'Strength', 'Grab a dumbbell in each hand and lie face down on an incline bench that is set to an incline that is approximately 30 degrees.', 'Let the arms hang to your sides fully extended as they point to the floor.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Bench_Pull/0.jpg'),
  ('00000000-0000-0000-0000-000000000337', 'Incline Cable Chest Press', 'Chest', 'B', 'Strength', 'Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 45 degrees to the body, with your head and chest up. The elbows should be bent to about 90 degrees. This will be your starting position.', 'Begin by extending through the elbow, pressing the handles together straight in front of you. Keep your shoulder blades retracted as you execute the movement.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Cable_Chest_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000338', 'Incline Cable Flye', 'Chest', 'B', 'Strength', 'To get yourself into the starting position, set the pulleys at the floor level (lowest level possible on the machine that is below your torso).', 'Place an incline bench (set at 45 degrees) in between the pulleys, select a weight on each one and grab a pulley on each hand.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Cable_Flye/0.jpg'),
  ('00000000-0000-0000-0000-000000000339', 'Incline Dumbbell Bench With Palms Facing In', 'Chest', 'A', 'Strength', 'Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.', 'By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Bench_With_Palms_Facing_In/0.jpg'),
  ('00000000-0000-0000-0000-000000000340', 'Incline Dumbbell Curl', 'Arms', 'S', 'Strength', 'Sit back on an incline bench with a dumbbell in each hand held at arms length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.', 'While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000341', 'Incline Dumbbell Flyes', 'Chest', 'B', 'Strength', 'Hold a dumbbell on each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.', 'Extend your arms above you with a slight bend at the elbows.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Flyes/0.jpg'),
  ('00000000-0000-0000-0000-000000000342', 'Incline Dumbbell Flyes - With A Twist', 'Chest', 'A', 'Strength', 'Hold a dumbbell in each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.', 'Extend your arms above you with a slight bend at the elbows.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Flyes_-_With_A_Twist/0.jpg'),
  ('00000000-0000-0000-0000-000000000343', 'Incline Dumbbell Press', 'Chest', 'B', 'Strength', 'Lie back on an incline bench with a dumbbell in each hand atop your thighs. The palms of your hands will be facing each other.', 'Then, using your thighs to help push the dumbbells up, lift the dumbbells one at a time so that you can hold them at shoulder width.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000344', 'Incline Hammer Curls', 'Arms', 'B', 'Strength', 'Seat yourself on an incline bench with a dumbbell in each hand. You should pressed firmly against he back with your feet together. Allow the dumbbells to hang straight down at your side, holding them with a neutral grip. This will be your starting position.', 'Initiate the movement by flexing at the elbow, attempting to keep the upper arm stationary.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Hammer_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000345', 'Incline Inner Biceps Curl', 'Arms', 'S', 'Strength', 'Hold a dumbbell in each hand and lie back on an incline bench.', 'The dumbbells should be at arm''s length hanging at your sides and your palms should be facing out. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Inner_Biceps_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000346', 'Incline Push-Up', 'Chest', 'B', 'Strength', 'Stand facing bench or sturdy elevated platform. Place hands on edge of bench or platform, slightly wider than shoulder width.', 'Position forefoot back from bench or platform with arms and body straight. Arms should be perpendicular to body. Keeping body straight, lower chest to edge of box or platform by bending arms.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000347', 'Incline Push-Up Close-Grip', 'Arms', 'B', 'Strength', 'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.', 'Place your hands next to one another on the bar.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Close-Grip/0.jpg'),
  ('00000000-0000-0000-0000-000000000348', 'Incline Push-Up Depth Jump', 'Chest', 'A', 'Plyometrics', 'For this drill you will need a box about 12 inches high, and two thick mats or aerobics steps.', 'Place the steps just outside of your shoulders, and place your feet on top of the box so that you are in an incline pushup position, your hands just inside the steps. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Depth_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000349', 'Incline Push-Up Medium', 'Chest', 'B', 'Strength', 'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.', 'Place your hands on the bar, with your hands about shoulder width apart.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Medium/0.jpg'),
  ('00000000-0000-0000-0000-000000000350', 'Incline Push-Up Reverse Grip', 'Chest', 'S', 'Strength', 'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.', 'Place your hands on the bar palms up, with your hands about shoulder width apart.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Reverse_Grip/0.jpg'),
  ('00000000-0000-0000-0000-000000000351', 'Incline Push-Up Wide', 'Chest', 'A', 'Strength', 'Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.', 'Place your hands on the bar, with your hands wider than shoulder width.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Wide/0.jpg'),
  ('00000000-0000-0000-0000-000000000352', 'Intermediate Groin Stretch', 'Legs', 'B', 'Stretching', 'Lie on your back with your legs extended. Loop a belt, rope, or band around one of your feet, and swing that leg as far to the side as you can. This will be your starting position.', 'Pull gently on the belt to create tension in your groin and hamstring muscles. Hold for 10-20 seconds, and repeat on the other side.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Groin_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000353', 'Intermediate Hip Flexor and Quad Stretch', 'Legs', 'B', 'Stretching', 'Lie face down on the floor, with a rope, belt, or band looped around one foot.', 'Flex the knee and extend the hip of the leg to be stretched, using both hands to pull on the belt. Your knee and your hip should come off of the floor, creating tension in the hip flexors and quadriceps. Hold the stretch for 10-20 seconds, and repeat on the other leg.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Hip_Flexor_and_Quad_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000354', 'Internal Rotation with Band', 'Shoulders', 'A', 'Strength', 'Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away.', 'Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Internal_Rotation_with_Band/0.jpg'),
  ('00000000-0000-0000-0000-000000000355', 'Inverted Row', 'Back', 'S', 'Strength', 'Position a bar in a rack to about waist height. You can also use a smith machine.', 'Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000356', 'Inverted Row with Straps', 'Back', 'B', 'Strength', 'Hang a rope or suspension straps from a rack or other stable object. Grasp the ends and position yourself in a supine position hanging from the ropes. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.', 'Begin by flexing the elbow, pulling your chest to your hands. Retract your shoulder blades as you perform the movement.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row_with_Straps/0.jpg'),
  ('00000000-0000-0000-0000-000000000357', 'Iron Cross', 'Shoulders', 'A', 'Strength', 'Maintain proper form and control.', 'Targets shoulders.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Cross/0.jpg'),
  ('00000000-0000-0000-0000-000000000358', 'Iron Crosses (stretch)', 'Legs', 'B', 'Stretching', 'Lie face down on the floor, with your arms extended out to your side, palms pressed to the floor. This will be your starting position.', 'To begin, flex one knee and bring that leg across the back of your body, attempting to touch it to the ground near the opposite hand.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Crosses_stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000359', 'Isometric Chest Squeezes', 'Chest', 'B', 'Plyometrics', 'While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso).', 'Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Chest_Squeezes/0.jpg'),
  ('00000000-0000-0000-0000-000000000360', 'Isometric Neck Exercise - Front And Back', 'Neck', 'S', 'Strength', 'With your head and neck in a neutral position (normal position with head erect facing forward), place both of your hands on the front side of your head.', 'Now gently push forward as you contract the neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Front_And_Back/0.jpg'),
  ('00000000-0000-0000-0000-000000000361', 'Isometric Neck Exercise - Sides', 'Neck', 'B', 'Strength', 'With your head and neck in a neutral position (normal position with head erect facing forward), place your left hand on the left side of your head.', 'Now gently push towards the left as you contract the left neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Sides/0.jpg'),
  ('00000000-0000-0000-0000-000000000362', 'Isometric Wipers', 'Chest', 'B', 'Strength', 'Assume a push-up position, supporting your weight on your hands and toes while keeping your body straight. Your hands should be just outside of shoulder width. This will be your starting position.', 'Begin by shifting your body weight as far to one side as possible, allowing the elbow on that side to flex as you lower your body.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Wipers/0.jpg'),
  ('00000000-0000-0000-0000-000000000363', 'JM Press', 'Arms', 'A', 'Strength', 'Start the exercise the same way you would a close grip bench press. You will lie on a flat bench while holding a barbell at arms length (fully extended) with the elbows in. However, instead of having the arms perpendicular to the torso, make sure the bar is set in a direct line above the upper chest. This will be your starting position.', 'Now beginning from a fully extended position lower the bar down as if performing a lying triceps extension. Inhale as you perform this movement. When you reach the half way point, let the bar roll back about one inch by moving the upper arms towards your legs until they are perpendicular to the torso. Tip: Keep the bend at the elbows constant as you bring the upper arms forward.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/JM_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000364', 'Jackknife Sit-Up', 'Core', 'B', 'Strength', 'Lie flat on the floor (or exercise mat) on your back with your arms extended straight back behind your head and your legs extended also. This will be your starting position.', 'As you exhale, bend at the waist while simultaneously raising your legs and arms to meet in a jackknife position. Tip: The legs should be extended and lifted at approximately a 35-45 degree angle from the floor and the arms should be extended and parallel to your legs. The upper torso should be off the floor.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jackknife_Sit-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000365', 'Janda Sit-Up', 'Core', 'S', 'Strength', 'Position your body on the floor in the basic sit-up position; knees to a ninety degree angle with feet flat on the floor and arms either crossed over your chest or to the sides. This will be your starting position.', 'As you strongly tighten your glutes and hamstrings, fill your lungs with air and in a slow (three to six second count) ascent, slowly exhale. Tip: It is important to tighten the glutes and hamstrings as this will cause the hip flexors to be inactivated in a process called reciprocal inhibition, which basically means that opposite muscles to the contracted ones will relax.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Janda_Sit-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000366', 'Jefferson Squats', 'Legs', 'A', 'Strength', 'Place a barbell on the floor.', 'Stand in the middle of the bar length wise.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jefferson_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000367', 'Jerk Balance', 'Shoulders', 'B', 'Olympic weightlifting', 'This drill helps you learn to drive yourself low enough during the jerk and corrects those who move backward during the movement. Begin with the bar racked in the jerk position, with the shoulders forward, torso upright, and the feet split slightly apart.', 'Initiate the movement as you would a normal jerk, dipping at the knees while keeping your torso vertical, and driving back up forcefully, using momentum and not your arms to elevate the weight.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Balance/0.jpg'),
  ('00000000-0000-0000-0000-000000000368', 'Jerk Dip Squat', 'Legs', 'B', 'Olympic weightlifting', 'This movement strengthens the dip portion of the jerk. Begin with the bar racked in the jerk position, with the shoulders forward to create a shelf and the bar lightly contacting the throat. The feet should be directly under the hips, with the feet turned out as is comfortable.', 'Keeping the torso vertical, dip by flexing the knees, allowing them to travel forward and without moving the hips to the rear. The dip should not be excessive. Return the weight to the starting position by driving forcefully though the feet.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Dip_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000369', 'Jogging, Treadmill', 'Legs', 'A', 'Cardio', 'To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.', 'Treadmills offer convenience, cardiovascular benefits, and usually have less impact than jogging outside. A 150 lb person will burn almost 250 calories jogging for 30 minutes, compared to more than 450 calories running. Maintain proper posture as you jog, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jogging_Treadmill/0.jpg'),
  ('00000000-0000-0000-0000-000000000370', 'Keg Load', 'Back', 'S', 'Strongman', 'To load kegs, place the desired number a distance from the loading platform, typically 30-50 feet.', 'Begin by grabbing the close handle of the first keg, tilting it onto its side to grab the opposite edge of the bottom of the keg. Lift the keg up to your chest.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Keg_Load/0.jpg'),
  ('00000000-0000-0000-0000-000000000371', 'Kettlebell Arnold Press', 'Shoulders', 'B', 'Strength', 'Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you raise the kettlebell towards your shoulder. The palm should be facing inward.', 'Looking straight ahead, press the kettlebell out and overhead, rotating your wrist so that your palm faces forward at the top of the motion.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Arnold_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000372', 'Kettlebell Dead Clean', 'Legs', 'A', 'Strength', 'Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.', 'Clean the kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Dead_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000373', 'Kettlebell Figure 8', 'Core', 'B', 'Strength', 'Place one kettlebell between your legs and take a wider than shoulder width stance. Bend over by pushing your butt out and keeping your back flat.', 'Pick up a kettlebell and pass it to your other hand between your legs. The receiving hand should reach from behind the legs. Go back and forth for several repetitions.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Figure_8/0.jpg'),
  ('00000000-0000-0000-0000-000000000374', 'Kettlebell Hang Clean', 'Legs', 'B', 'Strength', 'Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.', 'Clean kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Hang_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000375', 'Kettlebell One-Legged Deadlift', 'Legs', 'S', 'Strength', 'Hold a kettlebell by the handle in one hand. Stand on one leg, on the same side that you hold the kettlebell.', 'Keeping that knee slightly bent, perform a stiff legged deadlift by bending at the hip, extending your free leg behind you for balance.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_One-Legged_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000376', 'Kettlebell Pass Between The Legs', 'Core', 'B', 'Strength', 'Place one kettlebell between your legs and take a comfortable stance. Bend over by pushing your butt out and keeping your back flat.', 'Pick up a kettlebell and pass it to your other hand between your legs, in the fashion of a "W". Go back and forth for several repetitions.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pass_Between_The_Legs/0.jpg'),
  ('00000000-0000-0000-0000-000000000377', 'Kettlebell Pirate Ships', 'Shoulders', 'B', 'Strength', 'With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position.', 'Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pirate_Ships/0.jpg'),
  ('00000000-0000-0000-0000-000000000378', 'Kettlebell Pistol Squat', 'Legs', 'A', 'Strength', 'Pick up a kettlebell with two hands and hold it by the horns. Hold one leg off of the floor and squat down on the other.', 'Squat down by flexing the knee and sitting back with the hips, holding the kettlebell up in front of you.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pistol_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000379', 'Kettlebell Seated Press', 'Shoulders', 'B', 'Strength', 'Sit on the floor and spread your legs out comfortably.', 'Clean one kettlebell to your shoulder.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seated_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000380', 'Kettlebell Seesaw Press', 'Shoulders', 'S', 'Strength', 'Clean two kettlebells two your shoulders.', 'Press one kettlebell.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seesaw_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000381', 'Kettlebell Sumo High Pull', 'Other', 'A', 'Strength', 'Place a kettlebell on the ground between your feet. Position your feet in a wide stance, and grasp the kettlebell with two hands. Set your hips back as far as possible, with your knees bent. Keep your chest and head up. This will be your starting position.', 'Begin by extending the hips and knees, simultaneously pulling the kettlebell to your shoulders, raising your elbows as you do so. Reverse the motion to return to the starting position.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Sumo_High_Pull/0.jpg'),
  ('00000000-0000-0000-0000-000000000382', 'Kettlebell Thruster', 'Shoulders', 'B', 'Strength', 'Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so. This will be your starting position.', 'Begin to squat by flexing your hips and knees, lowering your hips between your legs. Maintain an upright, straight back as you descend as low as you can.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Thruster/0.jpg'),
  ('00000000-0000-0000-0000-000000000383', 'Kettlebell Turkish Get-Up (Lunge style)', 'Shoulders', 'B', 'Strength', 'Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell.', 'Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position. Using your free hand, push yourself to a seated position, then progressing to one knee.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Lunge_style/0.jpg'),
  ('00000000-0000-0000-0000-000000000384', 'Kettlebell Turkish Get-Up (Squat style)', 'Shoulders', 'A', 'Strength', 'Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell.', 'Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Squat_style/0.jpg'),
  ('00000000-0000-0000-0000-000000000385', 'Kettlebell Windmill', 'Core', 'S', 'Strength', 'Place a kettlebell in front of your lead foot and clean and press it overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward. Press it overhead by extending the elbow.', 'Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell. Bending at the hip to one side, sticking your butt out, slowly lean until you can touch the floor with your free hand. Keep your eyes on the kettlebell that you hold over your head at all times.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Windmill/0.jpg'),
  ('00000000-0000-0000-0000-000000000386', 'Kipping Muscle Up', 'Back', 'B', 'Strength', 'Grip the rings using a false grip, with the base of your palms on top of the rings.', 'Begin with a movement swinging your legs backward slightly.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kipping_Muscle_Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000387', 'Knee Across The Body', 'Legs', 'A', 'Stretching', 'Lie down on the floor with your right leg straight. Bend your left leg and lower it across your body, holding the knee down toward the floor with your right hand. (The knee doesn''t need to touch the floor if you''re tight.)', 'Place your left arm comfortably beside you and turn your head to the left. Imagine you have a weight tied to your tailbone. let your tailbone fall back toward the floor as your chest reaches in the opposite direction to stretch your lower back. Switch sides.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Across_The_Body/0.jpg'),
  ('00000000-0000-0000-0000-000000000388', 'Knee Circles', 'Legs', 'B', 'Stretching', 'Stand with your legs together and hands by your waist.', 'Now move your knees in a circular motion as you breathe normally.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Circles/0.jpg'),
  ('00000000-0000-0000-0000-000000000389', 'Knee/Hip Raise On Parallel Bars', 'Core', 'B', 'Strength', 'Position your body on the vertical leg raise bench so that your forearms are resting on the pads next to the torso and holding on to the handles. Your arms will be bent at a 90 degree angle.', 'The torso should be straight with the lower back pressed against the pad of the machine and the legs extended pointing towards the floor. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Hip_Raise_On_Parallel_Bars/0.jpg'),
  ('00000000-0000-0000-0000-000000000390', 'Knee Tuck Jump', 'Legs', 'S', 'Plyometrics', 'Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position.', 'Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Tuck_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000391', 'Kneeling Arm Drill', 'Shoulders', 'B', 'Plyometrics', 'This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated.', 'Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Arm_Drill/0.jpg'),
  ('00000000-0000-0000-0000-000000000392', 'Kneeling Cable Crunch With Alternating Oblique Twists', 'Core', 'B', 'Strength', 'Connect a rope attachment to a high pulley cable and position a mat on the floor in front of it.', 'Grab the rope with both hands and kneel approximately two feet back from the tower.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists/0.jpg'),
  ('00000000-0000-0000-0000-000000000393', 'Kneeling Cable Triceps Extension', 'Arms', 'A', 'Strength', 'Place a bench sideways in front of a high pulley machine.', 'Hold a straight bar attachment above your head with your hands about 6 inches apart with your palms facing down.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000394', 'Kneeling Forearm Stretch', 'Arms', 'B', 'Stretching', 'Start by kneeling on a mat with your palms flat and your fingers pointing back toward your knees.', 'Slowly lean back keeping your palms flat on the floor until you feel a stretch in your wrists and forearms. Hold for 20-30 seconds.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Forearm_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000395', 'Kneeling High Pulley Row', 'Back', 'S', 'Strength', 'Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position.', 'Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_High_Pulley_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000396', 'Kneeling Hip Flexor', 'Legs', 'A', 'Stretching', 'Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor.', 'Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Hip_Flexor/0.jpg'),
  ('00000000-0000-0000-0000-000000000397', 'Kneeling Jump Squat', 'Legs', 'B', 'Olympic weightlifting', 'Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier.', 'Sit back with your hips until your glutes touch your feet, keeping your head and chest up.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Jump_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000398', 'Kneeling Single-Arm High Pulley Row', 'Back', 'B', 'Strength', 'Attach a single handle to a high pulley and make your weight selection.', 'Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Single-Arm_High_Pulley_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000399', 'Kneeling Squat', 'Legs', 'A', 'Powerlifting', 'Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight.', 'With your head looking forward, sit back with your butt until you touch your calves.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000400', 'Landmine 180''s', 'Core', 'S', 'Strength', 'Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.', 'Raise the bar from the floor, taking it to shoulder height with both hands with your arms extended in front of you. Adopt a wide stance. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_180s/0.jpg'),
  ('00000000-0000-0000-0000-000000000401', 'Landmine Linear Jammer', 'Shoulders', 'B', 'Strength', 'Position a bar into landmine or, lacking one, securely anchor it in a corner. Load the bar to an appropriate weight and position the handle attachment on the bar.', 'Raise the bar from the floor, taking the handles to your shoulders. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_Linear_Jammer/0.jpg'),
  ('00000000-0000-0000-0000-000000000402', 'Lateral Bound', 'Legs', 'A', 'Plyometrics', 'Assume a half squat position facing 90 degrees from your direction of travel. This will be your starting position.', 'Allow your lead leg to do a countermovement inward as you shift your weight to the outside leg.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Bound/0.jpg'),
  ('00000000-0000-0000-0000-000000000403', 'Lateral Box Jump', 'Legs', 'B', 'Plyometrics', 'Assume a comfortable standing position, with a short box positioned next to you. This will be your starting position.', 'Quickly dip into a quarter squat to initiate the stretch reflex, and immediately reverse direction to jump up and to the side.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Box_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000404', 'Lateral Cone Hops', 'Legs', 'B', 'Plyometrics', 'Position a number of cones in a row several feet apart.', 'Stand next to the end of the cones, facing 90 degrees to the direction of travel. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Cone_Hops/0.jpg'),
  ('00000000-0000-0000-0000-000000000405', 'Lateral Raise - With Bands', 'Shoulders', 'S', 'Strength', 'To begin, stand on an exercise band so that tension begins at arm''s length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on the sides of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.', 'Use your side shoulders to lift the handles to the sides as you exhale. Continue to lift the handles until they are slightly above parallel. Tip: As you lift the handles, slightly tilt the hand as if you were pouring water and keep your arms extended. Also, keep your torso stationary and pause for a second at the top of the movement.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Raise_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000406', 'Latissimus Dorsi-SMR', 'Back', 'B', 'Stretching', 'While lying on the floor, place a foam roll under your back and to one side, just behind your arm pit. This will be your starting position.', 'Keep the arm of the side being stretched behind and to the side of you as you shift your weight onto your lats, keeping your upper body off of the ground. Hold for 10-30 seconds, and switch sides.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Latissimus_Dorsi-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000407', 'Leg-Over Floor Press', 'Chest', 'B', 'Strength', 'Lie on the floor with one kettlebell in place on your chest, holding it by the handle. Extend leg on working side over leg on non-working side.Your free arm can be extended out to your side for support.', 'Press the kettlebll into a locked out position.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Over_Floor_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000408', 'Leg-Up Hamstring Stretch', 'Legs', 'A', 'Stretching', 'Lie flat on your back, bend one knee, and put that foot flat on the floor to stabilize your spine.', 'Extend the other leg in the air. If you''re tight, you wont be able to straighten it. That''s okay. Extend the knee so that the sole of the lifted foot faces the ceiling (or as close as you can get it).', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Up_Hamstring_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000409', 'Leg Extensions', 'Legs', 'B', 'Strength', 'For this exercise you will need to use a leg extension machine. First choose your weight and sit on the machine with your legs under the pad (feet pointed forward) and the hands holding the side bars. This will be your starting position. Tip: You will need to adjust the pad so that it falls on top of your lower leg (just above your feet). Also, make sure that your legs form a 90-degree angle between the lower and upper leg. If the angle is less than 90-degrees then that means the knee is over the toes which in turn creates undue stress at the knee joint. If the machine is designed that way, either look for another machine or just make sure that when you start executing the exercise you stop going down once you hit the 90-degree angle.', 'Using your quadriceps, extend your legs to the maximum as you exhale. Ensure that the rest of the body remains stationary on the seat. Pause a second on the contracted position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Extensions/0.jpg'),
  ('00000000-0000-0000-0000-000000000410', 'Leg Lift', 'Legs', 'S', 'Strength', 'While standing up straight with both feet next to each other at around shoulder width, grab a sturdy surface such as the sides of a squat rack or the top of a chair to brace yourself and keep balance.', 'With or without an ankle weight, lift one leg behind you as if performing a leg curl but standing up while keeping the other leg straight. Breathe out as you perform this movement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Lift/0.jpg'),
  ('00000000-0000-0000-0000-000000000411', 'Leg Press', 'Legs', 'A', 'Strength', 'Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).', 'Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000412', 'Leg Pull-In', 'Core', 'B', 'Strength', 'Lie on an exercise mat with your legs extended and your hands either palms facing down next to you or under your glutes. Tip: My preference is with the hands next to me. This will be your starting position.', 'Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue the motion until your knees are around chest level. Contract your abs as you execute this movement and hold for a second at the top. Tip: As you perform the motion, the lower legs (calves) should always remain parallel to the floor.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Pull-In/0.jpg'),
  ('00000000-0000-0000-0000-000000000413', 'Leverage Chest Press', 'Chest', 'B', 'Strength', 'Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the bottom or middle of the pectorals at the beginning of the motion.', 'Your chest and head should be up and your shoulder blades retracted. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Chest_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000414', 'Leverage Deadlift', 'Legs', 'A', 'Strength', 'Load the pins to an appropriate weight. Position yourself directly between the handles. Grasp the bottom handles with a comfortable grip, and then lower your hips as you take a breath. Look forward with your head and keep your chest up. This will be your starting position.', 'Return the weight to the starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000415', 'Leverage Decline Chest Press', 'Chest', 'S', 'Strength', 'Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the bottom of the pectorals at the beginning of the motion. Your chest and head should be up and your shoulder blades retracted. This will be your starting position.', 'Press the handles forward by extending through the elbow.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Decline_Chest_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000416', 'Leverage High Row', 'Back', 'B', 'Strength', 'Load an appropriate weight onto the pins and adjust the seat height so that you can just reach the handles above you. Adjust the knee pad to help keep you down. Grasp the handles with a pronated grip. This will be your starting position.', 'Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_High_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000417', 'Leverage Incline Chest Press', 'Chest', 'A', 'Strength', 'Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the pectorals at the beginning of the motion. Your chest and head should be up and your shoulder blades retracted. This will be your starting position.', 'Press the handles forward by extending through the elbow.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Incline_Chest_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000418', 'Leverage Iso Row', 'Back', 'B', 'Strength', 'Load an appropriate weight onto the pins and adjust the seat height so that the handles are at chest level. Grasp the handles with either a neutral or pronated grip. This will be your starting position.', 'Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Iso_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000419', 'Leverage Shoulder Press', 'Shoulders', 'B', 'Strength', 'Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the shoulders at the beginning of the motion. Your chest and head should be up and handles held with a pronated grip. This will be your starting position.', 'Press the handles upward by extending through the elbow.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000420', 'Leverage Shrug', 'Other', 'S', 'Strength', 'Load the pins to an appropriate weight. Position yourself directly between the handles.', 'Grasp the top handles with a comfortable grip, and then lower your hips as you take a breath. Look forward with your head and keep your chest up.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000421', 'Linear 3-Part Start Technique', 'Legs', 'B', 'Plyometrics', 'This drill helps you accelerate as quickly as possible into a sprint from a dead stop. It helps to use a line to start from. Begin with two feet on the line. Place your left foot with the toe next to your right ankle. Place your right foot 4-6 inches behind the left.', 'Place your right hand onto the line, and thing bring your nose close to your left knee.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_3-Part_Start_Technique/0.jpg'),
  ('00000000-0000-0000-0000-000000000422', 'Linear Acceleration Wall Drill', 'Legs', 'B', 'Plyometrics', 'Lean at around 45 degrees against a wall. Your feet should be together, glutes contracted.', 'Begin by lifting your right knee quickly, pausing, and then driving it straight down into the ground.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_Acceleration_Wall_Drill/0.jpg'),
  ('00000000-0000-0000-0000-000000000423', 'Linear Depth Jump', 'Legs', 'A', 'Plyometrics', 'You will need two boxes or benches spaced a few feet away from each other. Begin by standing on one box facing towards the other platform.', 'To initiate the movement, gently drop down to the ground between your platforms, allowing the knees and hips to flex.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_Depth_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000424', 'Log Lift', 'Shoulders', 'B', 'Strongman', 'Begin standing with the log in front of you. Grasp the handles, and begin to clean the log. As you are bent over to start the clean, attempt to get the log as high as possible, pulling it into your chest. Extend through the hips and knees to bring it up to complete the clean.', 'Push your head back and look up, creating a shelf on your chest to rest the log. Begin the press by dipping, flexing slightly through the knees and reversing the motion. This push press will generate momentum to start the log moving vertically. Continue by extending through the elbows to press the log above your head. There are no strict rules on form, so use whatever techniques you are most efficient with. As the log is pressed, ensure that you push your head through on each repetition, looking forward.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Log_Lift/0.jpg'),
  ('00000000-0000-0000-0000-000000000425', 'London Bridges', 'Back', 'S', 'Strength', 'Attach a climbing rope to a high beam or cross member. Below it, ensure that the smith machine bar is locked in place with the safeties and cannot move. Alternatively, a secure box could also be utilized.', 'Stand on the bar, using the rope to balance yourself. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/London_Bridges/0.jpg'),
  ('00000000-0000-0000-0000-000000000426', 'Looking At Ceiling', 'Legs', 'A', 'Stretching', 'Kneel on the floor, holding your heels with both hands.', 'Lift your buttocks up and forward while bringing your head back to look up at the ceiling, to give an arch in your back.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Looking_At_Ceiling/0.jpg'),
  ('00000000-0000-0000-0000-000000000427', 'Low Cable Crossover', 'Chest', 'B', 'Strength', 'To move into the starting position, place the pulleys at the low position, select the resistance to be used and grasp a handle in each hand.', 'Step forward, gaining tension in the pulleys. Your palms should be facing forward, hands below the waist, and your arms straight. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Cable_Crossover/0.jpg'),
  ('00000000-0000-0000-0000-000000000428', 'Low Cable Triceps Extension', 'Arms', 'B', 'Strength', 'Select the desired weight and lay down face up on the bench of a seated row machine that has a rope attached to it. Your head should be pointing towards the attachment.', 'Grab the outside of the rope ends with your palms facing each other (neutral grip).', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Cable_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000429', 'Low Pulley Row To Neck', 'Shoulders', 'A', 'Strength', 'Sit on a low pulley row machine with a rope attachment.', 'Grab the ends of the rope using a palms-down grip and sit with your back straight and your knees slightly bent. Tip: Keep your back almost completely vertical and your arms fully extended in front of you. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Pulley_Row_To_Neck/0.jpg'),
  ('00000000-0000-0000-0000-000000000430', 'Lower Back-SMR', 'Back', 'S', 'Stretching', 'In a seated position, place a foam roll under your lower back. Cross your arms in front of you and protract your shoulders. This will be your starting position.', 'Raise your hips off of the floor and lean back, keeping your weight on your lower back. Now shift your weight slightly to one side, keeping your weight off of the spine and on the muscles to the side of it. Roll over your lower back, holding points of tension for 10-30 seconds. Repeat on the other side.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lower_Back-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000431', 'Lower Back Curl', 'Core', 'B', 'Stretching', 'Lie on your stomach with your arms out to your sides. This will be your starting position.', 'Using your lower back muscles, extend your spine lifting your chest off of the ground. Do not use your arms to push yourself up. Keep your head up during the movement. Repeat for 10-20 repetitions.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lower_Back_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000432', 'Lunge Pass Through', 'Legs', 'A', 'Strength', 'Stand with your torso upright holding a kettlebell in your right hand. This will be your starting position.', 'Step forward with your left foot and lower your upper body down by flexing the hip and the knee, keeping the torso upright. Lower your back knee until it nearly touches the ground.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lunge_Pass_Through/0.jpg'),
  ('00000000-0000-0000-0000-000000000433', 'Lunge Sprint', 'Legs', 'B', 'Strength', 'Adjust a bar in a Smith machine to an appropriate height. Position yourself under the bar, racking it across the back of your shoulders. Unrack the bar, and then split your feet, moving one foot forward and one foot back. This will be your starting position.', 'Lower your back knee nearly to the ground, flexing the knees and lowering your hips as you do so.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lunge_Sprint/0.jpg'),
  ('00000000-0000-0000-0000-000000000434', 'Lying Bent Leg Groin', 'Legs', 'B', 'Stretching', 'Lie on your back with your knees bent and the soles of the feet pressed together. Have your partner hold your knees. This will be your starting position.', 'Attempt to squeeze your knees together, while your partner prevents any movement from occurring.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Bent_Leg_Groin/0.jpg'),
  ('00000000-0000-0000-0000-000000000435', 'Lying Cable Curl', 'Arms', 'S', 'Strength', 'Grab a straight bar or E-Z bar attachment that is attached to the low pulley with both hands, using an underhand (palms facing up) shoulder-width grip.', 'Lie flat on your back on top of an exercise mat in front of the weight stack with your feet flat against the frame of the pulley machine and your legs straight.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Cable_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000436', 'Lying Cambered Barbell Row', 'Back', 'B', 'Strength', 'Place a cambered bar underneath an exercise bench.', 'Lie face down on the exercise bench and grab the bar using a palms down (pronated grip) that is wider than shoulder width. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Cambered_Barbell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000437', 'Lying Close-Grip Bar Curl On High Pulley', 'Arms', 'B', 'Strength', 'Place a flat bench in front of a high pulley or lat pulldown machine.', 'Hold the straight bar attachment using an underhand grip (palms up) that is about shoulder width.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Bar_Curl_On_High_Pulley/0.jpg'),
  ('00000000-0000-0000-0000-000000000438', 'Lying Close-Grip Barbell Triceps Extension Behind The Head', 'Arms', 'A', 'Strength', 'While holding a barbell or EZ Curl bar with a pronated grip (palms facing forward), lie on your back on a flat bench with your head close to the end of the bench. Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles.', 'Extend your arms in front of you and slowly bring the bar back in a semi circular motion (while keeping the arms extended) to a position over your head. At the end of this step your arms should be overhead and parallel to the floor. This will be your starting position. Tip: Keep your elbows in at all times.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Barbell_Triceps_Extension_Behind_The_Head/0.jpg'),
  ('00000000-0000-0000-0000-000000000439', 'Lying Close-Grip Barbell Triceps Press To Chin', 'Arms', 'B', 'Strength', 'While holding a barbell or EZ Curl bar with a pronated grip (palms facing forward), lie on your back on a flat bench with your head off the end of the bench. Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles.', 'Extend your arms in front of you as you hold the barbell over your chest. The arms should be perpendicular to your torso (90-degree angle). This will be your starting position.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Barbell_Triceps_Press_To_Chin/0.jpg'),
  ('00000000-0000-0000-0000-000000000440', 'Lying Crossover', 'Legs', 'S', 'Stretching', 'Lie on your back with your legs extended.', 'Cross one leg over your body with the knee bent, attempting to touch the knee to the ground. Your partner should kneel beside you, holding your shoulder down with one hand and controlling the crossed leg with the other. this will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Crossover/0.jpg'),
  ('00000000-0000-0000-0000-000000000441', 'Lying Dumbbell Tricep Extension', 'Arms', 'A', 'Strength', 'Lie on a flat bench while holding two dumbbells directly in front of you. Your arms should be fully extended at a 90-degree angle from your torso and the floor. The palms should be facing in and the elbows should be tucked in. This is the starting position.', 'As you breathe in and you keep the upper arms stationary with the elbows in, slowly lower the weight until the dumbbells are near your ears.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Dumbbell_Tricep_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000442', 'Lying Face Down Plate Neck Resistance', 'Neck', 'B', 'Strength', 'Lie face down with your whole body straight on a flat bench while holding a weight plate behind your head. Tip: You will need to position yourself so that your shoulders are slightly above the end of a flat bench in order for the upper chest, neck and face to be off the bench. This will be your starting position.', 'While keeping the plate secure on the back of your head slowly lower your head (as in saying "yes") as you breathe in.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Face_Down_Plate_Neck_Resistance/0.jpg'),
  ('00000000-0000-0000-0000-000000000443', 'Lying Face Up Plate Neck Resistance', 'Neck', 'B', 'Strength', 'Lie face up with your whole body straight on a flat bench while holding a weight plate on top of your forehead. Tip: You will need to position yourself so that your shoulders are slightly above the end of a flat bench in order for the traps, neck and head to be off the bench. This will be your starting position.', 'While keeping the plate secure on your forehead slowly lower your head back in a semi-circular motion as you breathe in.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Face_Up_Plate_Neck_Resistance/0.jpg'),
  ('00000000-0000-0000-0000-000000000444', 'Lying Glute', 'Legs', 'A', 'Stretching', 'Lie on your back with your partner kneeling beside you.', 'Flex the hip of one leg, raising it off of the floor. Rotate the leg so the foot is over the opposite hip, the lower leg perpendicular to your body. Your partner should hold the knee and ankle in place. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Glute/0.jpg'),
  ('00000000-0000-0000-0000-000000000445', 'Lying Hamstring', 'Legs', 'S', 'Stretching', 'Lie on your back with your legs extended. Your partner should be kneeling beside you. Raise one leg up towards the ceiling and have your partner hold the ankle. Your partner can use their shoulder to brace your leg if necessary. This will be your starting position.', 'With your partner holding your leg in place, attempt to flex the knee, contracting the hamstrings for 10-20 seconds.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Hamstring/0.jpg'),
  ('00000000-0000-0000-0000-000000000446', 'Lying High Bench Barbell Curl', 'Arms', 'B', 'Strength', 'Lie face forward on a tall flat bench while holding a barbell with a supinated grip (palms facing up). Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles. Your upper body should be positioned in a way that the upper chest is over the end of the bench and the barbell is hanging in front of you with the arms extended and perpendicular to the floor. This will be your starting position.', 'While keeping the elbows in and the upper arms stationary, curl the weight up in a semi-circular motion as you contract the biceps and exhale. Hold at the top of the movement for a second.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_High_Bench_Barbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000447', 'Lying Leg Curls', 'Legs', 'A', 'Strength', 'Adjust the machine lever to fit your height and lie face down on the leg curl machine with the pad of the lever on the back of your legs (just a few inches under the calves). Tip: Preferably use a leg curl machine that is angled as opposed to flat since an angled position is more favorable for hamstrings recruitment.', 'Keeping the torso flat on the bench, ensure your legs are fully stretched and grab the side handles of the machine. Position your toes straight (or you can also use any of the other two stances described on the foot positioning section). This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Leg_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000448', 'Lying Machine Squat', 'Legs', 'B', 'Strength', 'Adjust the leg machine to a height that will allow you to get inside it with your knees bent and the thighs slightly below parallel.', 'Once you select the weight, position yourself inside the machine face up with the knees bent and thighs slightly below parallel to the platform. Make sure that the knees do not go past the toes. The angle created between the hamstrings and the calves should be one that is slightly less than 90 degrees (since your starting position requires you to start slightly below parallel). Your back and your head should be resting on the machine while your shoulders are pressed under the shoulder pads.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Machine_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000449', 'Lying One-Arm Lateral Raise', 'Shoulders', 'B', 'Strength', 'While holding a dumbbell in one hand, lay with your chest down on a flat bench. The other hand can be used to hold to the leg of the bench for stability.', 'Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_One-Arm_Lateral_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000450', 'Lying Prone Quadriceps', 'Legs', 'S', 'Stretching', 'Lay face down on the floor with your partner kneeling beside you. Flex one knee and raise that leg off the ground, attempting to touch your glutes with your foot. Your partner should hold the knee and ankle. This will be your starting position.', 'Attempt to extend your knee while your partner prevents any actual movement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Prone_Quadriceps/0.jpg'),
  ('00000000-0000-0000-0000-000000000451', 'Lying Rear Delt Raise', 'Shoulders', 'B', 'Strength', 'While holding a dumbbell in each hand, lay with your chest down on a flat bench.', 'Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Rear_Delt_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000452', 'Lying Supine Dumbbell Curl', 'Arms', 'B', 'Strength', 'Lie down on a flat bench face up while holding a dumbbell in each arm on top of your thighs.', 'Bring the dumbbells to the sides with the arms extended and the palms of the hands facing your thighs (neutral grip).', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Supine_Dumbbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000453', 'Lying T-Bar Row', 'Back', 'A', 'Strength', 'Load up the T-bar Row Machine with the desired weight and adjust the leg height so that your upper chest is at the top of the pad. Tip: In some machines all you can do is stand on the appropriate step that allows you to be at a height that has the upper chest at the top of the pad.', 'Lay face down on the pad and grab the handles. You can either use a palms down, palms up, or palms in position depending on what part of your back you want to emphasize.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_T-Bar_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000454', 'Lying Triceps Press', 'Arms', 'B', 'Strength', 'Lie on a flat bench with either an e-z bar (my preference) or a straight bar placed on the floor behind your head and your feet on the floor.', 'Grab the bar behind you, using a medium overhand (pronated) grip, and raise the bar in front of you at arms length. Tip: The arms should be perpendicular to the torso and the floor. The elbows should be tucked in. This is the starting position.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Triceps_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000455', 'Machine Bench Press', 'Chest', 'S', 'Strength', 'Sit down on the Chest Press Machine and select the weight.', 'Step on the lever provided by the machine since it will help you to bring the handles forward so that you can grab the handles and fully extend the arms.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000456', 'Machine Bicep Curl', 'Arms', 'A', 'Strength', 'Adjust the seat to the appropriate height and make your weight selection. Place your upper arms against the pads and grasp the handles. This will be your starting position.', 'Perform the movement by flexing the elbow, pulling your lower arm towards your upper arm.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Bicep_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000457', 'Machine Preacher Curls', 'Arms', 'B', 'Strength', 'Sit down on the Preacher Curl Machine and select the weight.', 'Place the back of your upper arms (your triceps) on the preacher pad provided and grab the handles using an underhand grip (palms facing up). Tip: Make sure that when you place the arms on the pad you keep the elbows in. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Preacher_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000458', 'Machine Shoulder (Military) Press', 'Shoulders', 'B', 'Strength', 'Sit down on the Shoulder Press Machine and select the weight.', 'Grab the handles to your sides as you keep the elbows bent and in line with your torso. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Shoulder_Military_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000459', 'Machine Triceps Extension', 'Arms', 'A', 'Strength', 'Adjust the seat to the appropriate height and make your weight selection. Place your upper arms against the pads and grasp the handles. This will be your starting position.', 'Perform the movement by extending the elbow, pulling your lower arm away from your upper arm.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000460', 'Medicine Ball Chest Pass', 'Chest', 'S', 'Plyometrics', 'You will need a partner for this exercise. Lacking one, this movement can be performed against a wall.', 'Begin facing your partner holding the medicine ball at your torso with both hands.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Chest_Pass/0.jpg'),
  ('00000000-0000-0000-0000-000000000461', 'Medicine Ball Full Twist', 'Core', 'B', 'Plyometrics', 'For this exercise you will need a medicine ball and a partner. Stand back to back with your partner, spaced 2-3 feet apart. This will be your starting position.', 'Hold the ball in front of the trunk. Open the hips and turn the shoulders at the same time as your partner.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Full_Twist/0.jpg'),
  ('00000000-0000-0000-0000-000000000462', 'Medicine Ball Scoop Throw', 'Shoulders', 'A', 'Plyometrics', 'Assume a semisquat stance with a medicine ball in your hands. Your arms should hang so the ball is near your feet.', 'Begin by thrusting the hips forward as you extend through the legs, jumping up.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Scoop_Throw/0.jpg'),
  ('00000000-0000-0000-0000-000000000463', 'Middle Back Shrug', 'Back', 'B', 'Strength', 'Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position.', 'As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000464', 'Middle Back Stretch', 'Back', 'B', 'Stretching', 'Stand so your feet are shoulder width apart and your hands are on your hips.', 'Twist at your waist until you feel a stretch. Hold for 10 to 15 seconds, then twist to the other side.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000465', 'Mixed Grip Chin', 'Back', 'S', 'Strength', 'Using a spacing that is just about 1 inch wider than shoulder width, grab a pull-up bar with the palms of one hand facing forward and the palms of the other hand facing towards you. This will be your starting position.', 'Now start to pull yourself up as you exhale. Tip: With the arm that has the palms facing up concentrate on using the back muscles in order to perform the movement. The elbow of that arm should remain close to the torso. With the other arm that has the palms facing forward, the elbows will be away but in line with the torso. You will concentrate on using the lats to pull your body up.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mixed_Grip_Chin/0.jpg'),
  ('00000000-0000-0000-0000-000000000466', 'Monster Walk', 'Legs', 'B', 'Strength', 'Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart.', 'To begin, take short steps forward alternating your left and right foot.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Monster_Walk/0.jpg'),
  ('00000000-0000-0000-0000-000000000467', 'Mountain Climbers', 'Legs', 'B', 'Plyometrics', 'Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position.', 'Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mountain_Climbers/0.jpg'),
  ('00000000-0000-0000-0000-000000000468', 'Moving Claw Series', 'Legs', 'A', 'Plyometrics', 'This move helps prepare your running form to help you excel at sprinting. As you run, be sure to flex the knee, aiming to kick your glutes as the hip extends.', 'Reload the quad as the leg moves back forward, attacking the ground on the next step.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Moving_Claw_Series/0.jpg'),
  ('00000000-0000-0000-0000-000000000469', 'Muscle Snatch', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a loaded barbell held at the mid thigh position with a wide grip. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.', 'Begin the pull by driving through the front of the heels, raising the bar. Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Muscle_Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000470', 'Muscle Up', 'Back', 'S', 'Strength', 'Grip the rings using a false grip, with the base of your palms on top of the rings. Initiate a pull up by pulling the elbows down to your side, flexing the elbows.', 'As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Muscle_Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000471', 'Narrow Stance Hack Squats', 'Legs', 'A', 'Strength', 'Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.', 'Position your legs in the platform using a less than shoulder width narrow stance with the toes slightly pointed out. Your feet should be around 3 inches or less apart. Tip: Keep your head up at all times and also maintain the back on the pad at all times.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Hack_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000472', 'Narrow Stance Leg Press', 'Legs', 'B', 'Strength', 'Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a less-than-shoulder-width narrow stance with the toes slightly pointed out. Your feet should be around 3 inches or less apart. Tip: Keep your head up at all times and also maintain the back on the pad at all times.', 'Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Leg_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000473', 'Narrow Stance Squats', 'Legs', 'B', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000474', 'Natural Glute Ham Raise', 'Legs', 'A', 'Strength', 'Using the leg pad of a lat pulldown machine or a preacher bench, position yourself so that your ankles are under the pads, knees on the seat, and you are facing away from the machine. You should be upright and maintaining good posture.', 'This will be your starting position. Lower yourself under control until your knees are almost completely straight.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Natural_Glute_Ham_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000475', 'Neck-SMR', 'Neck', 'S', 'Stretching', 'Using a muscle roller or a rolling pin, place the roller behind your head and against your neck. Make sure that you do not place the roller directly against the spine, but turned slightly so that the roller is pressed against the muscles to either side of the spine. This will be your starting position.', 'Starting at the top of your neck, slowly roll down the muscles of your neck, pausing at points of tension for 10-30 seconds.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Neck-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000476', 'Neck Press', 'Chest', 'B', 'Strength', 'Lie back on a flat bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over your neck with your arms locked. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your neck.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Neck_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000477', 'Oblique Crunches', 'Core', 'A', 'Strength', 'Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put one hand beside your head and the other to the side against the floor.', 'Make sure your feet are elevated and resting on a flat surface.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Oblique_Crunches/0.jpg'),
  ('00000000-0000-0000-0000-000000000478', 'Oblique Crunches - On The Floor', 'Core', 'B', 'Strength', 'Start out by lying on your right side with your legs lying on top of each other. Make sure your knees are bent a little bit.', 'Place your left hand behind your head.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Oblique_Crunches_-_On_The_Floor/0.jpg'),
  ('00000000-0000-0000-0000-000000000479', 'Olympic Squat', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a barbell supported on top of the traps. The chest should be up, and the head facing forward. Adopt a hip width stance with the feet turned out as needed.', 'Descend by flexing the knees, refraining from moving the hips back as much as possible. This requires that the knees travel forward; ensure that they stay aligned with the feet. The goal is to keep the torso as upright as possible. Continue all the way down, keeping the weight on the front of the heel.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Olympic_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000480', 'On-Your-Back Quad Stretch', 'Legs', 'S', 'Stretching', 'Lie on a flat bench or step, and hang one leg and arm over the side.', 'Bend the knee and hold the top of the foot. As you do this, be careful not to arch your lower back.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/On-Your-Back_Quad_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000481', 'On Your Side Quad Stretch', 'Legs', 'B', 'Stretching', 'Start off by lying on your right side, with your right knee bent at a 90-degree angle resting on the floor in front of you (this stabilizes the torso).', 'Bend your left knee behind you and hold your left foot with your left hand. To stretch your hip flexor, press your left hip forward as you push your left foot back into your hand. Switch sides.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/On_Your_Side_Quad_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000482', 'One-Arm Dumbbell Row', 'Back', 'B', 'Strength', 'Choose a flat bench and place a dumbbell on each side of it.', 'Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Dumbbell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000483', 'One-Arm Flat Bench Dumbbell Flye', 'Chest', 'A', 'Strength', 'Lie down on a flat bench with a dumbbell in one hand resting on top of your thigh. The palm of your hand with the dumbbell in it should be at a neutral grip.', 'By using your thighs to help you get the dumbbell up, clean the dumbbell so that you can hold it in front of you with your lifting arm being fully extended. Remember to maintain a neutral grip with this exercise. Your non lifting hand should be to the side holding the flat bench for better support. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Flat_Bench_Dumbbell_Flye/0.jpg'),
  ('00000000-0000-0000-0000-000000000484', 'One-Arm High-Pulley Cable Side Bends', 'Core', 'B', 'Strength', 'Connect a standard handle to a tower. Move cable to highest pulley position.', 'Stand with side to cable. With one hand, reach up and grab handle with underhand grip.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_High-Pulley_Cable_Side_Bends/0.jpg'),
  ('00000000-0000-0000-0000-000000000485', 'One-Arm Incline Lateral Raise', 'Shoulders', 'S', 'Strength', 'Lie down sideways on an incline bench press with a dumbbell in the hand. Make sure the shoulder is pressing against the incline bench and the arm is lying across your body with the palm around your navel.', 'Hold a dumbbell in your uppermost arm while keeping it extended in front of you parallel to the floor. This is your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Incline_Lateral_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000486', 'One-Arm Kettlebell Clean', 'Legs', 'A', 'Strength', 'Place a kettlebell between your feet. As you bend down to grab the kettlebell, push your butt back and keep your eyes looking forward.', 'Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000487', 'One-Arm Kettlebell Clean and Jerk', 'Shoulders', 'B', 'Strength', 'Hold a kettlebell by the handle.', 'Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Clean_and_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000488', 'One-Arm Kettlebell Floor Press', 'Chest', 'B', 'Strength', 'Lie on the floor holding a kettlebell with one hand, with your upper arm supported by the floor. The palm should be facing in.', 'Press the kettlebell straight up toward the ceiling, rotating your wrist.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Floor_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000489', 'One-Arm Kettlebell Jerk', 'Shoulders', 'A', 'Strength', 'Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.', 'Dip your body by bending the knees, keeping your torso upright.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000490', 'One-Arm Kettlebell Military Press To The Side', 'Shoulders', 'S', 'Strength', 'Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces inward. This will be your starting position.', 'Look at the kettlebell and press it up and out until it is locked out overhead.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Military_Press_To_The_Side/0.jpg'),
  ('00000000-0000-0000-0000-000000000491', 'One-Arm Kettlebell Para Press', 'Shoulders', 'B', 'Strength', 'Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.', 'Hold the kettlebell with the elbow out to the side, and press it up and out until it is locked out overhead.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Para_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000492', 'One-Arm Kettlebell Push Press', 'Shoulders', 'A', 'Strength', 'Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.', 'Dip your body by bending the knees, keeping your torso upright.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Push_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000493', 'One-Arm Kettlebell Row', 'Back', 'B', 'Strength', 'Place a kettlebell in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position. Grab the kettlebell and pull it to your stomach, retracting your shoulder blade and flexing the elbow. Keep your back straight. Lower and repeat.', 'Targets middle back.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000494', 'One-Arm Kettlebell Snatch', 'Shoulders', 'B', 'Strength', 'Place a kettlebell between your feet. Bend your knees and push your butt back to get in the proper starting position.', 'Look straight ahead and swing the kettlebell back between your legs.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000495', 'One-Arm Kettlebell Split Jerk', 'Shoulders', 'S', 'Strength', 'Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.', 'Dip your body by bending the knees, keeping your torso upright.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Split_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000496', 'One-Arm Kettlebell Split Snatch', 'Shoulders', 'B', 'Strength', 'Hold a kettlebell in one hand by the handle.', 'Squat towards the floor, and then reverse the motion, extending the hips, knees, and finally the ankles, to raise the kettlebell overhead.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Split_Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000497', 'One-Arm Kettlebell Swings', 'Legs', 'B', 'Strength', 'Maintain proper form and control.', 'Targets hamstrings.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Swings/0.jpg'),
  ('00000000-0000-0000-0000-000000000498', 'One-Arm Long Bar Row', 'Back', 'A', 'Strength', 'Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.', 'Stand next to the bar, and take a grip with one hand close to the collar. Using your hips and legs, rise to a standing position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Long_Bar_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000499', 'One-Arm Medicine Ball Slam', 'Core', 'B', 'Strength', 'Start in a standing position with a staggered, athletic stance. Hold a medicine ball in one hand, on the same side as your back leg. This will be your starting position.', 'Begin by winding the arm, raising the medicine ball above your head. As you do so, extend through the hips, knees, and ankles to load up for the slam.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Medicine_Ball_Slam/0.jpg'),
  ('00000000-0000-0000-0000-000000000500', 'One-Arm Open Palm Kettlebell Clean', 'Legs', 'S', 'Strength', 'Place one kettlebell between your feet.', 'Grab the handle with one hand and raise the kettlebell rapidly, let it flip so that the ball of the kettlebell lands in the palm of your hand.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Open_Palm_Kettlebell_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000501', 'One-Arm Overhead Kettlebell Squats', 'Legs', 'A', 'Strength', 'Clean and press a kettlebell with one arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so. Press the weight overhead by extending through the elbow.This will be your starting position.', 'Looking straight ahead and keeping a kettlebell locked out above you, flex the knees and hips and lower your torso between your legs, keeping your head and chest up.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Overhead_Kettlebell_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000502', 'One-Arm Side Deadlift', 'Legs', 'B', 'Strength', 'Stand to the side of a barbell next to its center. Bend your knees and lower your body until you are able to reach the barbell.', 'Grasp the bar as if you were grabbing a briefcase (palms facing you since the bar is sideways). You may need a wrist wrap if you are using a significant amount of weight. This is your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Side_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000503', 'One-Arm Side Laterals', 'Shoulders', 'B', 'Strength', 'Pick a dumbbell and place it in one of your hands. Your non lifting hand should be used to grab something steady such as an incline bench press. Lean towards your lifting arm and away from the hand that is gripping the incline bench as this will allow you to keep your balance.', 'Stand with a straight torso and have the dumbbell by your side at arm''s length with the palm of the hand facing you. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Side_Laterals/0.jpg'),
  ('00000000-0000-0000-0000-000000000504', 'One-Legged Cable Kickback', 'Legs', 'A', 'Strength', 'Hook a leather ankle cuff to a low cable pulley and then attach the cuff to your ankle.', 'Face the weight stack from a distance of about two feet, grasping the steel frame for support.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Legged_Cable_Kickback/0.jpg'),
  ('00000000-0000-0000-0000-000000000505', 'One Arm Against Wall', 'Back', 'S', 'Stretching', 'From a standing position, place a bent arm against a wall or doorway.', 'Slowly lean toward your arm until you feel a stretch in your lats.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Against_Wall/0.jpg'),
  ('00000000-0000-0000-0000-000000000506', 'One Arm Chin-Up', 'Back', 'B', 'Strength', 'For this exercise, start out by placing a towel around a chin up bar.', 'Grab the chin-up bar with your palm facing you. One hand will be grabbing the chin-up bar and the other will be grabbing the towel.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Chin-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000507', 'One Arm Dumbbell Bench Press', 'Chest', 'A', 'Strength', 'Lie down on a flat bench with a dumbbell in one hand on top of your thigh.', 'By using your thigh to help you get the dumbbell up, clean the dumbbell up so that you can hold it in front of you at shoulder width. Use the hand you are not lifting with to help position the dumbbell over you properly.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Dumbbell_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000508', 'One Arm Dumbbell Preacher Curl', 'Arms', 'B', 'Strength', 'Grab a dumbbell with the right arm and place the upper arm on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.', 'As you breathe in, slowly lower the dumbbell until your upper arm is extended and the biceps is fully stretched.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Dumbbell_Preacher_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000509', 'One Arm Floor Press', 'Arms', 'B', 'Strength', 'Lie down on a flat surface with your back pressing against the floor or an exercise mat. Make sure your knees are bent.', 'Have a partner hand you the bar on one hand. When starting, your arm should be just about fully extended, similar to the starting position of a barbell bench press. However, this time your grip will be neutral (palms facing your torso).', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Floor_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000510', 'One Arm Lat Pulldown', 'Back', 'S', 'Strength', 'Select an appropriate weight and adjust the knee pad to help keep you down. Grasp the handle with a pronated grip. This will be your starting position.', 'Pull the handle down, squeezing your elbow to your side as you flex the elbow.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Lat_Pulldown/0.jpg'),
  ('00000000-0000-0000-0000-000000000511', 'One Arm Pronated Dumbbell Triceps Extension', 'Arms', 'B', 'Strength', 'Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your feet as a pronated grip is required to perform this exercise.', 'Place your non lifting hand on your bicep for support.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Pronated_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000512', 'One Arm Supinated Dumbbell Triceps Extension', 'Arms', 'B', 'Strength', 'Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your face as a supinated grip is required to perform this exercise.', 'Place your non lifting hand on your bicep for support.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Supinated_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000513', 'One Half Locust', 'Legs', 'A', 'Stretching', 'Lie facedown on the floor.', 'Put your left hand under your left hipbone to pad your hip and pubic bone.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Half_Locust/0.jpg'),
  ('00000000-0000-0000-0000-000000000514', 'One Handed Hang', 'Back', 'B', 'Stretching', 'Grab onto a chinup bar with one hand, using a pronated grip. Keep your feet on the floor or a step. Allow the majority of your weight to hang from that hand, while keeping your feet on the ground. Hold for 10-20 seconds and switch sides.', 'Targets lats.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Handed_Hang/0.jpg'),
  ('00000000-0000-0000-0000-000000000515', 'One Knee To Chest', 'Legs', 'S', 'Stretching', 'Start off by lying on the floor.', 'Extend one leg straight and pull the other knee to your chest. Hold under the knee joint to protect the kneecap.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Knee_To_Chest/0.jpg'),
  ('00000000-0000-0000-0000-000000000516', 'One Leg Barbell Squat', 'Legs', 'A', 'Strength', 'Start by standing about 2 to 3 feet in front of a flat bench with your back facing the bench. Have a barbell in front of you on the floor. Tip: Your feet should be shoulder width apart from each other.', 'Bend the knees and use a pronated grip with your hands being wider than shoulder width apart from each other to lift the barbell up until you can rest it on your chest.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Leg_Barbell_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000517', 'Open Palm Kettlebell Clean', 'Legs', 'B', 'Strength', 'Place one kettlebell between your feet. Clean the kettlebell by extending through the legs and hips as you raise the kettlebell towards your shoulders.', 'Release the kettlebell as it comes up, and let it flip so that the ball of the kettlebell lands in the palms of your hands.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Open_Palm_Kettlebell_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000518', 'Otis-Up', 'Core', 'B', 'Strength', 'Secure your feet and lay back on the floor. Your knees should be bent. Hold a weight with both hands to your chest. This will be your starting position.', 'Initiate the movement by flexing the hips and spine to raise your torso up from the ground.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Otis-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000519', 'Overhead Cable Curl', 'Arms', 'A', 'Strength', 'To begin, set a weight that is comfortable on each side of the pulley machine. Note: Make sure that the amount of weight selected is the same on each side.', 'Now adjust the height of the pulleys on each side and make sure that they are positioned at a height higher than that of your shoulders.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Cable_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000520', 'Overhead Lat', 'Back', 'S', 'Stretching', 'Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your tricep and wrist. This will be your starting position.', 'Attempt to pull your upper arm to your side as your partner prevents you from doing actually doing so.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Lat/0.jpg'),
  ('00000000-0000-0000-0000-000000000521', 'Overhead Slam', 'Back', 'B', 'Plyometrics', 'Hold a medine ball with both hands and stand with your feet at shoulder width. This will be your starting position.', 'Initiate the countermovement by raising the ball above your head and fully extending your body.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Slam/0.jpg'),
  ('00000000-0000-0000-0000-000000000522', 'Overhead Squat', 'Legs', 'A', 'Olympic weightlifting', 'Start out by having a barbell in front of you on the floor. Your feet should be wider than shoulder width apart from each other.', 'Bend the knees and use a pronated grip (palms facing you) to grab the barbell. Your hands should be at a wider than shoulder width apart from each other before lifting. Once you are positioned, lift the barbell up until you can rest it on your chest.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000523', 'Overhead Stretch', 'Core', 'B', 'Stretching', 'Standing straight up, lace your fingers together and open your palms to the ceiling. Keep your shoulders down as you extend your arms up.', 'To create a full torso stretch, pull your tailbone down and stabilize your torso as you do this. Stretch the muscles on both the front and the back of the torso.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000524', 'Overhead Triceps', 'Arms', 'B', 'Stretching', 'Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your elbow and wrist. This will be your starting position.', 'Attempt to extend the arm straight into the air as your partner prevents you from doing actually doing so.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Triceps/0.jpg'),
  ('00000000-0000-0000-0000-000000000525', 'Pallof Press', 'Core', 'S', 'Strength', 'Connect a standard handle to a tower, and—if possible—position the cable to shoulder height. If not, a low pulley will suffice.', 'With your side to the cable, grab the handle with both hands and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000526', 'Pallof Press With Rotation', 'Core', 'B', 'Strength', 'Connect a standard handle to a tower, and position the cable to shoulder height.', 'With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Align outstretched arm with cable.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press_With_Rotation/0.jpg'),
  ('00000000-0000-0000-0000-000000000527', 'Palms-Down Dumbbell Wrist Curl Over A Bench', 'Arms', 'B', 'Strength', 'Start out by placing two dumbbells on one side of a flat bench.', 'Kneel down on both of your knees so that your body is facing the flat bench.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000528', 'Palms-Down Wrist Curl Over A Bench', 'Arms', 'A', 'Strength', 'Start out by placing a barbell on one side of a flat bench.', 'Kneel down on both of your knees so that your body is facing the flat bench.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Wrist_Curl_Over_A_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000529', 'Palms-Up Barbell Wrist Curl Over A Bench', 'Arms', 'B', 'Strength', 'Start out by placing a barbell on one side of a flat bench.', 'Kneel down on both of your knees so that your body is facing the flat bench.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Barbell_Wrist_Curl_Over_A_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000530', 'Palms-Up Dumbbell Wrist Curl Over A Bench', 'Arms', 'S', 'Strength', 'Start out by placing two dumbbells on one side of a flat bench.', 'Kneel down on both of your knees so that your body is facing the flat bench.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000531', 'Parallel Bar Dip', 'Arms', 'A', 'Strength', 'Stand between a set of parallel bars. Place a hand on each bar, and then take a small jump to help you get into the starting position with your arms locked out.', 'Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Parallel_Bar_Dip/0.jpg'),
  ('00000000-0000-0000-0000-000000000532', 'Pelvic Tilt Into Bridge', 'Back', 'B', 'Stretching', 'Lie down with your feet on the floor, heels directly under your knees.', 'Lift only your tailbone to the ceiling to stretch your lower back. (Don''t lift the entire spine yet.) Pull in your stomach.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pelvic_Tilt_Into_Bridge/0.jpg'),
  ('00000000-0000-0000-0000-000000000533', 'Peroneals-SMR', 'Legs', 'B', 'Stretching', 'Lay on your side, supporting your weight on your forearm and on a foam roller placed on the outside of your lower leg. Your upper leg can either be on top of your lower leg, or you can cross it in front of you. This will be your starting position.', 'Raise your hips off of the ground and begin to roll from below the knee to above the ankle on the side of your leg, pausing at points of tension for 10-30 seconds. Repeat on the other leg.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000534', 'Peroneals Stretch', 'Legs', 'A', 'Stretching', 'In a seated position, loop a belt, rope, or band around one foot. This will be your starting position.', 'With the leg extended and the heel off of the ground, pull on the belt so that the foot is inverted, with the inside of the foot being pulled towards you. Hold for 10-20 seconds, and then switch sides.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000535', 'Physioball Hip Bridge', 'Legs', 'S', 'Strength', 'Lay on a ball so that your upper back is on the ball with your hips unsupported. Both feet should be flat on the floor, hip width apart or wider. This will be your starting position.', 'Begin by extending the hips using your glutes and hamstrings, raising your hips upward as you bridge.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Physioball_Hip_Bridge/0.jpg'),
  ('00000000-0000-0000-0000-000000000536', 'Pin Presses', 'Arms', 'B', 'Powerlifting', 'Pin presses remove the eccentric phase of the bench press, developing starting strength. They also allow you to train a desired range of motion.', 'The bench should be set up in a power rack. Set the pins to the desired point in your range of motion, whether it just be lockout or an inch off of your chest. The bar should be moved to the pins and prepared for lifting.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pin_Presses/0.jpg'),
  ('00000000-0000-0000-0000-000000000537', 'Piriformis-SMR', 'Legs', 'A', 'Stretching', 'Sit with your buttocks on top of a foam roll. Bend your knees, and then cross one leg so that the ankle is over the knee. This will be your starting position.', 'Shift your weight to the side of the crossed leg, rolling over the buttocks until you feel tension in your upper glute. You may assist the stretch by using one hand to pull the bent knee towards your chest. Hold this position for 10-30 seconds, and then switch sides.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Piriformis-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000538', 'Plank', 'Core', 'B', 'Strength', 'Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.', 'Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plank/0.jpg'),
  ('00000000-0000-0000-0000-000000000539', 'Plate Pinch', 'Arms', 'B', 'Strength', 'Grab two wide-rimmed plates and put them together with the smooth sides facing outward', 'Use your fingers to grip the outside part of the plate and your thumb for the other side thus holding both plates together. This is the starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plate_Pinch/0.jpg'),
  ('00000000-0000-0000-0000-000000000540', 'Plate Twist', 'Core', 'S', 'Strength', 'Lie down on the floor or an exercise mat with your legs fully extended and your upper body upright. Grab the plate by its sides with both hands out in front of your abdominals with your arms slightly bent.', 'Slowly cross your legs near your ankles and lift them up off the ground. Your knees should also be bent slightly. Note: Move your upper body back slightly to help keep you balanced turning this exercise. This is the starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plate_Twist/0.jpg'),
  ('00000000-0000-0000-0000-000000000541', 'Platform Hamstring Slides', 'Legs', 'B', 'Strength', 'For this movement a wooden floor or similar is needed. Lay on your back with your legs extended. Place a gym towel or a light weight underneath your heel. This will be your starting position.', 'Begin the movement by flexing the knee, keeping your other leg straight.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Platform_Hamstring_Slides/0.jpg'),
  ('00000000-0000-0000-0000-000000000542', 'Plie Dumbbell Squat', 'Legs', 'B', 'Strength', 'Hold a dumbbell at the base with both hands and stand straight up. Move your legs so that they are wider than shoulder width apart from each other with your knees slightly bent.', 'Your toes should be facing out. Note: Your arms should be stationary while performing the exercise. This is the starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plie_Dumbbell_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000543', 'Plyo Kettlebell Pushups', 'Chest', 'A', 'Strength', 'Place a kettlebell on the floor. Place yourself in a pushup position, on your toes with one hand on the ground and one hand holding the kettlebell, with your elbows extended. This will be your starting position.', 'Begin by lowering yourself as low as you can, keeping your back straight.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plyo_Kettlebell_Pushups/0.jpg'),
  ('00000000-0000-0000-0000-000000000544', 'Plyo Push-up', 'Chest', 'B', 'Plyometrics', 'Move into a prone position on the floor, supporting your weight on your hands and toes.', 'Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plyo_Push-up/0.jpg'),
  ('00000000-0000-0000-0000-000000000545', 'Posterior Tibialis Stretch', 'Legs', 'S', 'Stretching', 'In a seated position, loop a belt, rope, or band around one foot. This will be your starting position.', 'With the leg extended and the heel off of the ground, pull on the belt so that the foot is everted, with the outside of the foot being pulled towards you. Hold for 10-20 seconds, and then switch sides.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Posterior_Tibialis_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000546', 'Power Clean', 'Legs', 'A', 'Strength', 'Stand with your feet slightly wider than shoulder width apart and toes pointing out slightly.', 'Squat down and grasp bar with a closed, pronated grip. Your hands should be slightly wider than shoulder width apart outside knees with elbows fully extended.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000547', 'Power Clean from Blocks', 'Legs', 'B', 'Olympic weightlifting', 'With a barbell on boxes of the desired height, take a grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.', 'Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. As the bar approaches the mid-thigh position, begin extending through the hips.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Clean_from_Blocks/0.jpg'),
  ('00000000-0000-0000-0000-000000000548', 'Power Jerk', 'Legs', 'B', 'Olympic weightlifting', 'Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible.', 'Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000549', 'Power Partials', 'Shoulders', 'A', 'Strength', 'Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.', 'The palms of the hands should be facing your torso. Your feet should be about shoulder width apart. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Partials/0.jpg'),
  ('00000000-0000-0000-0000-000000000550', 'Power Snatch', 'Legs', 'S', 'Olympic weightlifting', 'Begin with a loaded barbell on the floor. The bar should be close to or touching the shins, and a wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.', 'Begin the first pull by driving through the front of the heels, raising the bar from the ground. The back angle should stay the same until the bar passes the knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000551', 'Power Snatch from Blocks', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a loaded barbell on boxes or stands of the desired height. A wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar, with the elbows pointed out. This will be the starting position.', 'Begin the first pull by driving through the front of the heels, raising the bar from the boxes.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Snatch_from_Blocks/0.jpg'),
  ('00000000-0000-0000-0000-000000000552', 'Power Stairs', 'Legs', 'A', 'Strongman', 'In the power stairs, implements are moved up a staircase. For training purposes, these can be performed with a tire or box.', 'Begin by taking the implement with both hands. Set your feet wide, with your head and chest up. Drive through the ground with your heels, extending your knees and hips to raise the weight from the ground.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Stairs/0.jpg'),
  ('00000000-0000-0000-0000-000000000553', 'Preacher Curl', 'Arms', 'B', 'Strength', 'To perform this movement you will need a preacher bench and an E-Z bar. Grab the E-Z curl bar at the close inner handle (either have someone hand you the bar which is preferable or grab the bar from the front bar rest provided by most preacher benches). The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar.', 'With the upper arms positioned against the preacher bench pad and the chest against it, hold the E-Z Curl Bar at shoulder length. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Preacher_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000554', 'Preacher Hammer Dumbbell Curl', 'Arms', 'B', 'Strength', 'Place the upper part of both arms on top of the preacher bench as you hold a dumbbell in each hand with the palms facing each other (neutral grip).', 'As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Preacher_Hammer_Dumbbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000555', 'Press Sit-Up', 'Core', 'S', 'Strength', 'To begin, lie down on a bench with a barbell resting on your chest. Position your legs so they are secure on the extension of the abdominal bench. This is the starting position.', 'While inhaling, tighten your abdominals and glutes. Simultaneously curl your torso as you do when performing a sit-up and press the barbell to an overhead position while exhaling. Tip: Use your arms to push the barbell out as you perform this exercise while still focusing on the abdominal muscles.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Press_Sit-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000556', 'Prone Manual Hamstring', 'Legs', 'B', 'Strength', 'You will need a partner for this exercise. Lay face down with your legs straight. Your assistant will place their hand on your heel.', 'To begin, flex the knee to curl your leg up. Your partner should provide resistance, starting light and increasing the pressure as the movement is completed. Communicate with your partner to monitor appropriate resistance levels.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Prone_Manual_Hamstring/0.jpg'),
  ('00000000-0000-0000-0000-000000000557', 'Prowler Sprint', 'Legs', 'B', 'Cardio', 'Place your sled on an appropriate surface, loaded to a suitable weight. The sled should provide enough resistance to require effort, but not so heavy that you are significantly slowed down.', 'You may use the upright or the low handles for this exercise. Place your hands on the handles with your arms extended, leaning into the implement.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Prowler_Sprint/0.jpg'),
  ('00000000-0000-0000-0000-000000000558', 'Pull Through', 'Legs', 'A', 'Strength', 'Begin standing a few feet in front of a low pulley with a rope or handle attached. Face away from the machine, straddling the cable, with your feet set wide apart.', 'Begin the movement by reaching through your legs as far as possible, bending at the hips. Keep your knees slightly bent. Keeping your arms straight, extend through the hip to stand straight up. Avoid pulling upward through the shoulders; all of the motion should originate through the hips.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pull_Through/0.jpg'),
  ('00000000-0000-0000-0000-000000000559', 'Pullups', 'Back', 'B', 'Strength', 'Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.', 'As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pullups/0.jpg'),
  ('00000000-0000-0000-0000-000000000560', 'Push-Up Wide', 'Chest', 'S', 'Strength', 'With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position.', 'To begin, allow the elbows to flex, lowering your chest to the floor as you inhale.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Up_Wide/0.jpg'),
  ('00000000-0000-0000-0000-000000000561', 'Push-Ups - Close Triceps Position', 'Arms', 'A', 'Strength', 'Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms'' length.', 'Lower yourself until your chest almost touches the floor as you inhale.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_-_Close_Triceps_Position/0.jpg'),
  ('00000000-0000-0000-0000-000000000562', 'Push-Ups With Feet Elevated', 'Chest', 'B', 'Strength', 'Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.', 'Place your toes on top of a flat bench. This will allow your body to be elevated. Note: The higher the elevation of the flat bench, the higher the resistance of the exercise is.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_Elevated/0.jpg'),
  ('00000000-0000-0000-0000-000000000563', 'Push-Ups With Feet On An Exercise Ball', 'Chest', 'B', 'Strength', 'Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.', 'Place your toes on top of an exercise ball. This will allow your body to be elevated.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_On_An_Exercise_Ball/0.jpg'),
  ('00000000-0000-0000-0000-000000000564', 'Push Press', 'Shoulders', 'A', 'Olympic weightlifting', 'Maintain proper form and control.', 'Targets shoulders.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000565', 'Push Press - Behind the Neck', 'Shoulders', 'S', 'Olympic weightlifting', 'Standing with the weight racked on the back of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, moving the bar in a vertical path.', 'Using the momentum generated, finish pressing the weight overhead be extending through the arms.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press_-_Behind_the_Neck/0.jpg'),
  ('00000000-0000-0000-0000-000000000566', 'Push Up to Side Plank', 'Chest', 'B', 'Strength', 'Get into pushup position on the toes with your hands just outside of shoulder width.', 'Perform a pushup by allowing the elbows to flex. As you descend, keep your body straight.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Up_to_Side_Plank/0.jpg'),
  ('00000000-0000-0000-0000-000000000567', 'Pushups', 'Chest', 'A', 'Strength', 'Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length.', 'Next, lower yourself downward until your chest almost touches the floor as you inhale.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups/0.jpg'),
  ('00000000-0000-0000-0000-000000000568', 'Pushups (Close and Wide Hand Positions)', 'Chest', 'B', 'Strength', 'Lie on the floor face down and body straight with your toes on the floor and the hands wider than shoulder width for a wide hand position and closer than shoulder width for a close hand position. Make sure you are holding your torso up at arms length.', 'Lower yourself until your chest almost touches the floor as you inhale.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups_Close_and_Wide_Hand_Positions/0.jpg'),
  ('00000000-0000-0000-0000-000000000569', 'Pyramid', 'Back', 'B', 'Stretching', 'Start off by rolling your torso forward onto the ball so your hips rest on top of the ball and become the highest point of your body.', 'Rest your hands and feet on the floor. Your arms and legs can be slightly bent or straight, depending on the size of the ball, your flexibility, and the length of your limbs. This also helps develop stabilizing strength in your torso and shoulders.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pyramid/0.jpg'),
  ('00000000-0000-0000-0000-000000000570', 'Quad Stretch', 'Legs', 'S', 'Stretching', 'Lay on your side. Loop a belt, rope, or band around your top foot. Flex the knee and extend your hip, attempting to touch your glutes with your foot, and holding the belt with your hands. This will be your starting position.', 'With the belt being held over the shoulder or overhead, gently pull to increase the stretch in the quadriceps. Hold for 10-20 seconds, and then switch sides.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quad_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000571', 'Quadriceps-SMR', 'Legs', 'B', 'Stretching', 'Lay facedown on the floor with your weight supported by your hands or forearms. Place a foam roll underneath one leg on the quadriceps, and keep the foot off of the ground. Make sure to relax the leg as much as possible. This will be your starting position.', 'Shifting as much weight onto the leg to be stretched as is tolerable, roll over the foam from above the knee to below the hip, holding points of tension for 10-30 seconds. Switch sides.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quadriceps-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000572', 'Quick Leap', 'Legs', 'B', 'Plyometrics', 'You will need a box for this exerise.', 'Begin facing the box standing 1-2 feet from its edge.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quick_Leap/0.jpg'),
  ('00000000-0000-0000-0000-000000000573', 'Rack Delivery', 'Shoulders', 'A', 'Olympic weightlifting', 'This drill teaches the delivery of the barbell to the rack position on the shoulders. Begin holding a bar in the scarecrow position, with the upper arms parallel to the floor, and the forearms hanging down. Use a hook grip, with your fingers wrapped over your thumbs.', 'Begin by rotating the elbows around the bar, delivering the bar to the shoulders. As your elbows come forward, relax your grip. The shoulders should be protracted, providing a shelf for the bar, which should lightly contact the throat.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Delivery/0.jpg'),
  ('00000000-0000-0000-0000-000000000574', 'Rack Pull with Bands', 'Back', 'B', 'Powerlifting', 'Set up in a power rack with the bar on the pins. The pins should be set to the desired point; just below the knees, just above, or in the mid thigh position. Attach bands to the base of the rack, or secure them with dumbbells. Attach the other end to the bar. You may need to choke the bands to provide tension.', 'Position yourself against the bar in proper deadlifting position. Your feet should be under your hips, your grip shoulder width, back arched, and hips back to engage the hamstrings. Since the weight is typically heavy, you may use a mixed grip, a hook grip, or use straps to aid in holding the weight.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Pull_with_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000575', 'Rack Pulls', 'Back', 'S', 'Powerlifting', 'Set up in a power rack with the bar on the pins. The pins should be set to the desired point; just below the knees, just above, or in the mid thigh position. Position yourself against the bar in proper deadlifting position. Your feet should be under your hips, your grip shoulder width, back arched, and hips back to engage the hamstrings. Since the weight is typically heavy, you may use a mixed grip, a hook grip, or use straps to aid in holding the weight.', 'With your head looking forward, extend through the hips and knees, pulling the weight up and back until lockout. Be sure to pull your shoulders back as you complete the movement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Pulls/0.jpg'),
  ('00000000-0000-0000-0000-000000000576', 'Rear Leg Raises', 'Legs', 'A', 'Stretching', 'Place yourself on your hands knees on an exercise mat. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.', 'Extend one leg up and behind you. The knee and hip should both extend. Repeat for 5-10 repetitions, and then switch sides.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rear_Leg_Raises/0.jpg'),
  ('00000000-0000-0000-0000-000000000577', 'Recumbent Bike', 'Legs', 'B', 'Cardio', 'To begin, seat yourself on the bike and adjust the seat to your height.', 'Select the desired option from the menu. You may have to start pedaling to turn it on. You can use the manual setting, or you can select a program to use. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. The level of resistance can be changed throughout the workout. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Recumbent_Bike/0.jpg'),
  ('00000000-0000-0000-0000-000000000578', 'Return Push from Stance', 'Shoulders', 'B', 'Plyometrics', 'You will need a partner for this drill.', 'Begin in an athletic 2 or 3 point stance.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Return_Push_from_Stance/0.jpg'),
  ('00000000-0000-0000-0000-000000000579', 'Reverse Band Bench Press', 'Arms', 'A', 'Powerlifting', 'Position a bench inside a power rack, with the bar set to the correct height. Begin by anchoring bands either to band pegs or to the top of the rack. Ensure that you will be position properly under the bands. Attach the other end to the barbell.', 'Lie on the bench, tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement. However wide your grip, it should cover the ring on the bar.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000580', 'Reverse Band Box Squat', 'Legs', 'S', 'Powerlifting', 'Begin in a power rack with a box at the appropriate height behind you. Set up the bands either on band pegs or attached to the top of the rack, ensuring they will be directly above the bar during the squat. Attach the other end to the bar.', 'Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wider for more emphasis on the back, glutes, adductors, and hamstrings, or closer together for more quad development. Keep your head facing forward.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Box_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000581', 'Reverse Band Deadlift', 'Back', 'B', 'Powerlifting', 'Set the bar up in a power rack. Attach bands to the top of the rack, using either bands pegs or the frame itself. Attach the other end of the bands to the bar.', 'Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000582', 'Reverse Band Power Squat', 'Legs', 'A', 'Powerlifting', 'Begin in a power rack with the pins and bar set at the appropriate height. After loading the bar, attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end of the bands to the bar.', 'Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Power_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000583', 'Reverse Band Sumo Deadlift', 'Legs', 'B', 'Powerlifting', 'Begin with a bar loaded on the floor inside of a power rack. Attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end to the barbell.', 'Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Sumo_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000584', 'Reverse Barbell Curl', 'Arms', 'B', 'Strength', 'Stand up with your torso upright while holding a barbell at shoulder width with the elbows close to the torso. The palm of your hands should be facing down (pronated grip). This will be your starting position.', 'While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Barbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000585', 'Reverse Barbell Preacher Curls', 'Arms', 'S', 'Strength', 'Grab an EZ-bar using a shoulder width and palms down (pronated) grip.', 'Now place the upper part of both arms on top of the preacher bench and have your arms extended. This will be your starting position.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Barbell_Preacher_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000586', 'Reverse Cable Curl', 'Arms', 'B', 'Strength', 'Stand up with your torso upright while holding a bar attachment that is attached to a low pulley using a pronated (palms down) and shoulder width grip. Make sure also that you keep the elbows close to the torso. This will be your starting position.', 'While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Cable_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000587', 'Reverse Crunch', 'Core', 'B', 'Strength', 'Lie down on the floor with your legs fully extended and arms to the side of your torso with the palms on the floor. Your arms should be stationary for the entire exercise.', 'Move your legs up so that your thighs are perpendicular to the floor and feet are together and parallel to the floor. This is the starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000588', 'Reverse Flyes', 'Shoulders', 'A', 'Strength', 'To begin, lie down on an incline bench with the chest and stomach pressing against the incline. Have the dumbbells in each hand with the palms facing each other (neutral grip).', 'Extend the arms in front of you so that they are perpendicular to the angle of the bench. The legs should be stationary while applying pressure with the ball of your toes. This is the starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Flyes/0.jpg'),
  ('00000000-0000-0000-0000-000000000589', 'Reverse Flyes With External Rotation', 'Shoulders', 'B', 'Strength', 'To begin, lie down on an incline bench set at a 30-degree angle with the chest and stomach pressing against the incline.', 'Have the dumbbells in each hand with the palms facing down to the floor. Your arms should be in front of you so that they are perpendicular to the angle of the bench. Tip: Your elbows should have a slight bend. The legs should be stationary while applying pressure with the ball of your toes (your heels should not be touching the floor). This is the starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Flyes_With_External_Rotation/0.jpg'),
  ('00000000-0000-0000-0000-000000000590', 'Reverse Grip Bent-Over Rows', 'Back', 'S', 'Strength', 'Stand erect while holding a barbell with a supinated grip (palms facing up).', 'Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Grip_Bent-Over_Rows/0.jpg'),
  ('00000000-0000-0000-0000-000000000591', 'Reverse Grip Triceps Pushdown', 'Arms', 'A', 'Strength', 'Start by setting a bar attachment (straight or e-z) on a high pulley machine.', 'Facing the bar attachment, grab it with the palms facing up (supinated grip) at shoulder width. Lower the bar by using your lats until your arms are fully extended by your sides. Tip: Elbows should be in by your sides and your feet should be shoulder width apart from each other. This is the starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Grip_Triceps_Pushdown/0.jpg'),
  ('00000000-0000-0000-0000-000000000592', 'Reverse Hyperextension', 'Legs', 'B', 'Strength', 'Place your feet between the pads after loading an appropriate weight. Lay on the top pad, allowing your hips to hang off the back, while grasping the handles to hold your position.', 'To begin the movement, flex the hips, pulling the legs forward.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Hyperextension/0.jpg'),
  ('00000000-0000-0000-0000-000000000593', 'Reverse Machine Flyes', 'Shoulders', 'B', 'Strength', 'Adjust the handles so that they are fully to the rear. Make an appropriate weight selection and adjust the seat height so the handles are at shoulder level. Grasp the handles with your hands facing inwards. This will be your starting position.', 'In a semicircular motion, pull your hands out to your side and back, contracting your rear delts.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Machine_Flyes/0.jpg'),
  ('00000000-0000-0000-0000-000000000594', 'Reverse Plate Curls', 'Arms', 'A', 'Strength', 'Start by standing straight with a weighted plate held by both hands and arms fully extended. Use a pronated grip (palms facing down) and make sure your fingers grab the rough side of the plate while your thumb grabs the smooth side. Note: For the best results, grab the weighted plate at an 11:00 and 1:00 o''clock position.', 'Your feet should be shoulder width apart from each other and the weighted plate should be near the groin area. This is the starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Plate_Curls/0.jpg'),
  ('00000000-0000-0000-0000-000000000595', 'Reverse Triceps Bench Press', 'Arms', 'S', 'Strength', 'Lie back on a flat bench. Using a close, supinated grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked extended in front of you and perpendicular to the floor. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Triceps_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000596', 'Rhomboids-SMR', 'Back', 'B', 'Stretching', 'Lay down with your back on the floor. Place a foam roll underneath your upper back, and cross your arms in front of you, protracting your shoulders. This will be your starting position.', 'Raise your hips off of the ground, placing your weight onto the foam roll. Shift your weight to one side at a time, rolling over your middle and upper back. Pause at points of tension for 10-30 seconds.', 'Foam roll', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rhomboids-SMR/0.jpg'),
  ('00000000-0000-0000-0000-000000000597', 'Rickshaw Carry', 'Arms', 'A', 'Strongman', 'Position the frame at the starting point, and load with the appropriate weight. Standing in the center of the frame, begin by gripping the handles and driving through your heels to lift the frame. Ensure your chest and head are up and your back is straight.', 'Immediately begin walking briskly with quick, controlled steps. Keep your chest up and head forward, and make sure you continue breathing. Bring the frame to the ground after you have reached the end point.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rickshaw_Carry/0.jpg'),
  ('00000000-0000-0000-0000-000000000598', 'Rickshaw Deadlift', 'Legs', 'B', 'Strongman', 'Load the frame with the desired weight. Center yourself between the handles. You feet should be about hip width apart. Bend at the hips to grip the handles, allowing your shoulder blades to protract.', 'With your feet and your grip set, take a big breath and then lower your hips and flex the knees. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. As the weight comes up, pull your shoulder blades together as you drive your hips forward.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rickshaw_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000599', 'Ring Dips', 'Arms', 'B', 'Strength', 'Grip a ring in each hand, and then take a small jump to help you get into the starting position with your arms locked out.', 'Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ring_Dips/0.jpg'),
  ('00000000-0000-0000-0000-000000000600', 'Rocket Jump', 'Legs', 'S', 'Plyometrics', 'Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.', 'To initiate the move, squat down halfway and explode back up as high as possible.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rocket_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000601', 'Rocking Standing Calf Raise', 'Legs', 'B', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place it on the back of your shoulders (slightly below the neck).', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rocking_Standing_Calf_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000602', 'Rocky Pull-Ups/Pulldowns', 'Back', 'B', 'Strength', 'Grab the pull-up bar with the palms facing forward using a wide grip.', 'As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rocky_Pull-Ups_Pulldowns/0.jpg'),
  ('00000000-0000-0000-0000-000000000603', 'Romanian Deadlift', 'Legs', 'A', 'Strength', 'Put a barbell in front of you on the ground and grab it using a pronated (palms facing down) grip that a little wider than shoulder width. Tip: Depending on the weight used, you may need wrist wraps to perform the exercise and also a raised platform in order to allow for better range of motion.', 'Bend the knees slightly and keep the shins vertical, hips back and back straight. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Romanian_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000604', 'Romanian Deadlift from Deficit', 'Legs', 'B', 'Olympic weightlifting', 'Begin standing while holding a bar at arm''s length in front of you. You can stand on a raised platform to increase the range of motion.', 'Begin by flexing the knees slightly, and then flex at the hip, moving your butt back as far as possible, lowering the torso as far as flexibility allows. The back should remain in absolute extension at all times, and the bar should remain in contact with the legs. If done properly, there should be heavy tension felt in the hamstrings.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Romanian_Deadlift_from_Deficit/0.jpg'),
  ('00000000-0000-0000-0000-000000000605', 'Rope Climb', 'Back', 'S', 'Strength', 'Grab the rope with both hands above your head. Pull down on the rope as you take a small jump.', 'Wrap the rope around one leg, using your feet to pinch the rope. Reach up as high as possible with your arms, gripping the rope tightly.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Climb/0.jpg'),
  ('00000000-0000-0000-0000-000000000606', 'Rope Crunch', 'Core', 'A', 'Strength', 'Kneel 1-2 feet in front of a cable system with a rope attached.', 'After selecting an appropriate weight, grasp the rope with both hands reaching overhead. Your torso should be upright in the starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000607', 'Rope Jumping', 'Legs', 'B', 'Cardio', 'Hold an end of the rope in each hand. Position the rope behind you on the ground. Raise your arms up and turn the rope over your head bringing it down in front of you. When it reaches the ground, jump over it. Find a good turning pace that can be maintained. Different speeds and techniques can be used to introduce variation.', 'Rope jumping is exciting, challenges your coordination, and requires a lot of energy. A 150 lb person will burn about 350 calories jumping rope for 30 minutes, compared to over 450 calories running.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Jumping/0.jpg'),
  ('00000000-0000-0000-0000-000000000608', 'Rope Straight-Arm Pulldown', 'Back', 'B', 'Strength', 'Attach a rope to a high pulley and make your weight selection. Stand a couple feet back from the pulley with your feet staggered and take the rope with both hands. Lean forward from the hip, keeping your back straight, with your arms extended up in front of you. This will be your starting position.', 'Keeping your arms straight, extend the shoulder to pull the rope down to your thighs.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Straight-Arm_Pulldown/0.jpg'),
  ('00000000-0000-0000-0000-000000000609', 'Round The World Shoulder Stretch', 'Shoulders', 'A', 'Stretching', 'Stand up straight with your legs together, holding a bodybar or broomstick.', 'Hold the pole behind your hips with a wider than shoulder width grip. Your palms should be down and your thumbs facing out.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Round_The_World_Shoulder_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000610', 'Rowing, Stationary', 'Legs', 'S', 'Cardio', 'To begin, seat yourself on the rower. Make sure that your heels are resting comfortably against the base of the foot pedals and that the straps are secured. Select the program that you wish to use, if applicable. Sit up straight and bend forward at the hips.', 'There are three phases of movement when using a rower. The first phase is when you come forward on the rower. Your knees are bent and against your chest. Your upper body is leaning slightly forward while still maintaining good posture. Next, push against the foot pedals and extend your legs while bringing your hands to your upper abdominal area, squeezing your shoulders back as you do so. To avoid straining your back, use primarily your leg and hip muscles.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rowing_Stationary/0.jpg'),
  ('00000000-0000-0000-0000-000000000611', 'Runner''s Stretch', 'Legs', 'B', 'Stretching', 'It''s easiest to get into this stretch if you start standing up, put one leg behind you, and slowly lower your torso down to the floor.', 'Keep the front heel on the floor (if it lifts up, scoot your other leg further back).', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Runners_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000612', 'Running, Treadmill', 'Legs', 'A', 'Cardio', 'To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.', 'Treadmills offer convenience, cardiovascular benefits, and usually have less impact than running outside. A 150 lb person will burn over 450 calories running 8 miles per hour for 30 minutes. Maintain proper posture as you run, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Running_Treadmill/0.jpg'),
  ('00000000-0000-0000-0000-000000000613', 'Russian Twist', 'Core', 'B', 'Strength', 'Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.', 'Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Russian_Twist/0.jpg'),
  ('00000000-0000-0000-0000-000000000614', 'Sandbag Load', 'Legs', 'B', 'Strongman', 'To load sandbags or other objects, begin with the implements placed a distance from the loading platform, typically 50 feet.', 'Begin by lifting the sandbag. Sandbags are extremely awkward, and the manner of lifting them can vary depending on the particular sandbag used. Reach as far around it as possible, extending through the hips and knees to pull it up high. Shouldering is usually not allowed.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sandbag_Load/0.jpg'),
  ('00000000-0000-0000-0000-000000000615', 'Scapular Pull-Up', 'Other', 'S', 'Strength', 'Take a pronated grip on a pull-up bar.', 'From a hanging position, raise yourself a few inches without using your arms. Do this by depressing your shoulder girdle in a reverse shrugging motion.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Scapular_Pull-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000616', 'Scissor Kick', 'Core', 'B', 'Stretching', 'To begin, lie down with your back pressed against the floor or on an exercise mat (optional). Your arms should be fully extended to the sides with your palms facing down. Note: The arms should be stationary the entire time.', 'With a slight bend at the knees, lift your legs up so that your heels are about 6 inches off the ground. This is the starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Scissor_Kick/0.jpg'),
  ('00000000-0000-0000-0000-000000000617', 'Scissors Jump', 'Legs', 'B', 'Plyometrics', 'Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.', 'Ensure that the front knee is over the midline of the foot. Extending through both legs, jump as high as possible, swinging your arms to gain lift.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Scissors_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000618', 'Seated Band Hamstring Curl', 'Legs', 'A', 'Strength', 'Secure a band close to the ground and place a bench a couple feet away from it.', 'Seat yourself on the bench and secure the band behind your ankles, beginning with your legs straight. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Band_Hamstring_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000619', 'Seated Barbell Military Press', 'Shoulders', 'B', 'Strength', 'Sit on a Military Press Bench with a bar behind your head and either have a spotter give you the bar (better on the rotator cuff this way) or pick it up yourself carefully with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down.', 'Once you pick up the barbell with the correct grip length, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Barbell_Military_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000620', 'Seated Barbell Twist', 'Core', 'S', 'Strength', 'Start out by sitting at the end of a flat bench with a barbell placed on top of your thighs. Your feet should be shoulder width apart from each other.', 'Grip the bar with your palms facing down and make sure your hands are wider than shoulder width apart from each other. Begin to lift the barbell up over your head until your arms are fully extended.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Barbell_Twist/0.jpg'),
  ('00000000-0000-0000-0000-000000000621', 'Seated Bent-Over One-Arm Dumbbell Triceps Extension', 'Arms', 'A', 'Strength', 'Sit down at the end of a flat bench with a dumbbell in one arm using a neutral grip (palms of the hand facing you).', 'Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000622', 'Seated Bent-Over Rear Delt Raise', 'Shoulders', 'B', 'Strength', 'Place a couple of dumbbells looking forward in front of a flat bench.', 'Sit on the end of the bench with your legs together and the dumbbells behind your calves.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Bent-Over_Rear_Delt_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000623', 'Seated Bent-Over Two-Arm Dumbbell Triceps Extension', 'Arms', 'B', 'Strength', 'Sit down at the end of a flat bench with a dumbbell in both arms using a neutral grip (palms of the hand facing you).', 'Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000624', 'Seated Biceps', 'Arms', 'A', 'Stretching', 'Sit on the floor with your knees bent and your partner standing behind you. Extend your arms straight behind you with your palms facing each other. Your partner will hold your wrists for you. This will be the starting position.', 'Attempt to flex your elbows, while your partner prevents any actual movement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Biceps/0.jpg'),
  ('00000000-0000-0000-0000-000000000625', 'Seated Cable Rows', 'Back', 'S', 'Strength', 'For this exercise you will need access to a low pulley row machine with a V-bar. Note: The V-bar will enable you to have a neutral grip where the palms of your hands face each other. To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.', 'Lean over as you keep the natural alignment of your back and grab the V-bar handles.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Cable_Rows/0.jpg'),
  ('00000000-0000-0000-0000-000000000626', 'Seated Cable Shoulder Press', 'Shoulders', 'B', 'Strength', 'Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 90 degrees to the body, with your head and chest up. The elbows should also be bent to about 90 degrees. This will be your starting position.', 'Begin by extending through the elbow, pressing the handles together above your head.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Cable_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000627', 'Seated Calf Raise', 'Legs', 'A', 'Strength', 'Sit on the machine and place your toes on the lower portion of the platform provided with the heels extending off. Choose the toe positioning of your choice (forward, in, or out) as per the beginning of this chapter.', 'Place your lower thighs under the lever pad, which will need to be adjusted according to the height of your thighs. Now place your hands on top of the lever pad in order to prevent it from slipping forward.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Calf_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000628', 'Seated Calf Stretch', 'Legs', 'B', 'Stretching', 'Sit up straight on an exercise mat.', 'Bend one knee and put that foot on the floor to stabilize the torso.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Calf_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000629', 'Seated Close-Grip Concentration Barbell Curl', 'Arms', 'B', 'Strength', 'Sit down on a flat bench with a barbell or E-Z Bar in front of you in between your legs. Your legs should be spread with the knees bent and the feet on the floor.', 'Use your arms to pick the barbell up and place the back of your upper arms on top of your inner thighs (around three and a half inches away from the front of the knee). A supinated grip closer than shoulder width is needed to perform this exercise. Tip: Your arm should be extended at arms length and the barbell should be above the floor. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Close-Grip_Concentration_Barbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000630', 'Seated Dumbbell Curl', 'Arms', 'S', 'Strength', 'Sit on a flat bench with a dumbbell on each hand being held at arms length. The elbows should be close to the torso.', 'Rotate the palms of the hands so that they are facing your torso. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Dumbbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000631', 'Seated Dumbbell Inner Biceps Curl', 'Arms', 'B', 'Strength', 'Sit on the end of a flat bench with a dumbbell in each hand being held at arms length. The elbows should be close to the torso.', 'Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Dumbbell_Inner_Biceps_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000632', 'Seated Dumbbell Palms-Down Wrist Curl', 'Arms', 'B', 'Strength', 'Start out by placing two dumbbells on the floor in front of a flat bench.', 'Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Dumbbell_Palms-Down_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000633', 'Seated Dumbbell Palms-Up Wrist Curl', 'Arms', 'A', 'Strength', 'Start out by placing two dumbbells on the floor in front of a flat bench.', 'Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Dumbbell_Palms-Up_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000634', 'Seated Dumbbell Press', 'Shoulders', 'B', 'Strength', 'Grab a couple of dumbbells and sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs.', 'Clean the dumbbells up one at a time by using your thighs to bring the dumbbells up to shoulder height at each side.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000635', 'Seated Flat Bench Leg Pull-In', 'Core', 'S', 'Strength', 'Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.', 'Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Flat_Bench_Leg_Pull-In/0.jpg'),
  ('00000000-0000-0000-0000-000000000636', 'Seated Floor Hamstring Stretch', 'Legs', 'A', 'Stretching', 'Sit on a mat with your right leg extended in front of you and your left leg bent with your foot against your right inner thigh.', 'Lean forward from your hips and reach for your ankle until you feel a stretch in your hamstring. Hold for 15 seconds, then repeat for your other side.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Floor_Hamstring_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000637', 'Seated Front Deltoid', 'Shoulders', 'B', 'Stretching', 'Sit upright on the floor with your legs bent, your partner standing behind you. Stick your arms straight out to your sides, with your palms facing the ground. Attempt to move them as far behind you as possible, as your assistant holds your wrists. This will be your starting position.', 'Keeping your elbows straight, attempt to move your arms to the front, with your partner gently restraining you to prevent any actual movement for 10-20 seconds.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Front_Deltoid/0.jpg'),
  ('00000000-0000-0000-0000-000000000638', 'Seated Glute', 'Legs', 'B', 'Stretching', 'In a seated position with your knees bent, cross one ankle over the opposite knee. Your partner will stand behind you. Now, lean forward as your partner braces your shoulders with their hands. This will be your starting position.', 'Attempt to push your torso back for 10-20 seconds, as your partner prevents any actual movement of your torso.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Glute/0.jpg'),
  ('00000000-0000-0000-0000-000000000639', 'Seated Good Mornings', 'Back', 'A', 'Powerlifting', 'Set up a box in a power rack. The pins should be set at an appropriate height. Begin by stepping under the bar and placing it across the back of the shoulders, not on top of your traps. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders.', 'Remove the bar from the rack, creating a tight arch in your lower back. Keep your head facing forward. With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips until you are seated on the box. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Good_Mornings/0.jpg'),
  ('00000000-0000-0000-0000-000000000640', 'Seated Hamstring', 'Legs', 'S', 'Stretching', 'In a seated position with your legs extended, have your partner stand behind you. Now, lean forward as your partner braces your shoulders with their hands. This will be your starting position.', 'Attempt to push your torso back for 10-20 seconds, as your partner prevents any actual movement of your torso.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Hamstring/0.jpg'),
  ('00000000-0000-0000-0000-000000000641', 'Seated Hamstring and Calf Stretch', 'Legs', 'B', 'Stretching', 'Loop a belt, rope, or band around one foot. Sit down with both legs extended . This will be your starting position.', 'Leaning forward slightly, pull on the belt to draw the toes of your foot back. Hold this position for 10-20 seconds and then repeat with the other leg.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Hamstring_and_Calf_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000642', 'Seated Head Harness Neck Resistance', 'Neck', 'A', 'Strength', 'Place a neck strap on the floor at the end of a flat bench. Once you have selected the weights, sit at the end of the flat bench with your feet wider than shoulder width apart from each other. Your toes should be pointed out.', 'Slowly move your torso forward until it is almost parallel with the floor. Using both hands, securely position the neck strap around your head. Tip: Make sure the weights are still lying on the floor to prevent any strain on the neck. Now grab the weight with both hands while elevating your torso back until it is almost perpendicular to the floor. Note: Your head and torso needs to be slightly tilted forward to perform this exercise.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Head_Harness_Neck_Resistance/0.jpg'),
  ('00000000-0000-0000-0000-000000000643', 'Seated Leg Curl', 'Legs', 'B', 'Strength', 'Adjust the machine lever to fit your height and sit on the machine with your back against the back support pad.', 'Place the back of lower leg on top of padded lever (just a few inches under the calves) and secure the lap pad against your thighs, just above the knees. Then grasp the side handles on the machine as you point your toes straight (or you can also use any of the other two stances) and ensure that the legs are fully straight right in front of you. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Leg_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000644', 'Seated Leg Tucks', 'Core', 'B', 'Strength', 'Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.', 'Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Leg_Tucks/0.jpg'),
  ('00000000-0000-0000-0000-000000000645', 'Seated One-Arm Dumbbell Palms-Down Wrist Curl', 'Arms', 'S', 'Strength', 'Sit on a flat bench with a dumbbell in your right hand.', 'Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_One-Arm_Dumbbell_Palms-Down_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000646', 'Seated One-Arm Dumbbell Palms-Up Wrist Curl', 'Arms', 'B', 'Strength', 'Sit on a flat bench with a dumbbell in your right hand.', 'Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_One-Arm_Dumbbell_Palms-Up_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000647', 'Seated One-arm Cable Pulley Rows', 'Back', 'B', 'Strength', 'To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.', 'Lean over as you keep the natural alignment of your back and grab the single handle attachment with your left arm using a palms-down grip.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_One-arm_Cable_Pulley_Rows/0.jpg'),
  ('00000000-0000-0000-0000-000000000648', 'Seated Overhead Stretch', 'Core', 'A', 'Stretching', 'Sit up straight on an exercise mat.', 'Touch the soles of your feet together with your feet six to eight inches in front of your hips.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Overhead_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000649', 'Seated Palm-Up Barbell Wrist Curl', 'Arms', 'B', 'Strength', 'Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.', 'Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Palm-Up_Barbell_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000650', 'Seated Palms-Down Barbell Wrist Curl', 'Arms', 'S', 'Strength', 'Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width.', 'Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Palms-Down_Barbell_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000651', 'Seated Side Lateral Raise', 'Shoulders', 'A', 'Strength', 'Pick a couple of dumbbells and sit at the end of a flat bench with your feet firmly on the floor. Hold the dumbbells with your palms facing in and your arms straight down at your sides at arms'' length. This will be your starting position.', 'While maintaining the torso stationary (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Side_Lateral_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000652', 'Seated Triceps Press', 'Arms', 'B', 'Strength', 'Sit down on a bench with back support and grasp a dumbbell with both hands and hold it overhead at arm''s length. Tip: a better way is to have somebody hand it to you especially if it is very heavy. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hand should be facing inward. This will be your starting position.', 'Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semi-circular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Triceps_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000653', 'Seated Two-Arm Palms-Up Low-Pulley Wrist Curl', 'Arms', 'B', 'Strength', 'Put a bench in front of a low pulley machine that has a barbell or EZ Curl attachment on it.', 'Move the bench far enough away so that when you bring the handle to the top of your thighs tension is created on the cable due to the weight stack being moved up.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Two-Arm_Palms-Up_Low-Pulley_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000654', 'See-Saw Press (Alternating Side Press)', 'Shoulders', 'A', 'Strength', 'Grab a dumbbell with each hand and stand up erect.', 'Clean (lift) the dumbbells to the chest/shoulder level and then rotate your wrists so that your palms are facing towards you as if you were getting ready to perform an Arnold Press. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/See-Saw_Press_Alternating_Side_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000655', 'Shotgun Row', 'Back', 'S', 'Strength', 'Attach a single handle to a low cable.', 'After selecting the correct weight, stand a couple feet back with a wide-split stance. Your arm should be extended and your shoulder forward. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shotgun_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000656', 'Shoulder Circles', 'Shoulders', 'B', 'Stretching', 'With shoulders relaxed and arms resting loosely at your sides (or in your lap if you''re seated), gently roll your shoulders forward, up, back, and down.', 'Reverse direction. You can do this exercise alternating shoulders or both at the same time.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Circles/0.jpg'),
  ('00000000-0000-0000-0000-000000000657', 'Shoulder Press - With Bands', 'Shoulders', 'A', 'Strength', 'To begin, stand on an exercise band so that tension begins at arm''s length. Grasp the handles and lift them so that the hands are at shoulder height at each side.', 'Rotate the wrists so that the palms of your hands are facing forward. Your elbows should be bent, with the upper arms and forearms in line to the torso. This is your starting position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Press_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000658', 'Shoulder Raise', 'Shoulders', 'B', 'Stretching', 'Relax your arms to your sides and raise your shoulders up toward your ears, then back down.', 'Targets shoulders.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000659', 'Shoulder Stretch', 'Shoulders', 'B', 'Stretching', 'Reach your left arm across your body and hold it straight.', 'Targets shoulders.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Shoulder_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000660', 'Side-Lying Floor Stretch', 'Back', 'S', 'Stretching', 'First lie on your left side, bending your left knee in front of you to stabilize your torso (use your abdominal muscles as well to hold you upright).', 'Straighten your right leg and rest the right foot on the floor behind your left. Straighten your right arm over your head and gently pull on your right wrist to stretch the entire right side of the body. Switch sides.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side-Lying_Floor_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000661', 'Side Bridge', 'Core', 'B', 'Strength', 'Maintain proper form and control.', 'Targets abdominals.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Bridge/0.jpg'),
  ('00000000-0000-0000-0000-000000000662', 'Side Hop-Sprint', 'Legs', 'B', 'Plyometrics', 'Stand to the side of a cone or hurdle.', 'Begin this drill by hopping sideways over the obstacle, rebounding out of your landing to hop back to where you started.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Hop-Sprint/0.jpg'),
  ('00000000-0000-0000-0000-000000000663', 'Side Jackknife', 'Core', 'A', 'Strength', 'Maintain proper form and control.', 'Targets abdominals.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Jackknife/0.jpg'),
  ('00000000-0000-0000-0000-000000000664', 'Side Lateral Raise', 'Shoulders', 'B', 'Strength', 'Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position.', 'While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Lateral_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000665', 'Side Laterals to Front Raise', 'Shoulders', 'S', 'Strength', 'In a standing position, hold a pair of dumbbells at your side. This will be your starting position.', 'Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Laterals_to_Front_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000666', 'Side Leg Raises', 'Legs', 'A', 'Stretching', 'Stand next to a chair, which you may hold onto as a support. Stand on one leg. This will be your starting position.', 'Keeping your leg straight, raise it as far out to the side as possible, and swing it back down, allowing it to cross the opposite leg.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Leg_Raises/0.jpg'),
  ('00000000-0000-0000-0000-000000000667', 'Side Lying Groin Stretch', 'Legs', 'B', 'Stretching', 'Start off by lying on your right side and bend your right knee in front of you to stabilize the torso.', 'Rest your head on your right hand or shoulder. Lift your left leg upward and hold it by the back of the knee (easier) or the foot (harder).', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Lying_Groin_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000668', 'Side Neck Stretch', 'Neck', 'B', 'Stretching', 'Start with your shoulders relaxed, gently tilt your head towards your shoulder.', 'Assist stretch with a gentle pull on the side of the head.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Neck_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000669', 'Side Standing Long Jump', 'Legs', 'A', 'Plyometrics', 'Begin standing with your feet hip width apart in an athletic stance. Your head and chest should be up, knees and hips slightly bent. This will be your starting position.', 'Leaning to your right, extend through your hips, knees, and ankles to jump into the air. Block with the arms to lead the movement, jumping as far to your right as you can.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Standing_Long_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000670', 'Side To Side Chins', 'Back', 'S', 'Strength', 'Grab the pull-up bar with the palms facing forward using a wide grip.', 'As you have both arms extended in front of you holding the bar at a wide grip, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_To_Side_Chins/0.jpg'),
  ('00000000-0000-0000-0000-000000000671', 'Side Wrist Pull', 'Shoulders', 'B', 'Stretching', 'This stretch works best standing. Cross your left arm over the midline of your body and hold the left wrist in your right hand down at the level of your hips. Start the stretch with a bent left arm.', 'Slowly straighten, pull, and lift it up to shoulder height, as pictured. Feel this stretch originate in your back, not your shoulders, and don''t pull too hard on the shoulders joint. Switch sides.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_Wrist_Pull/0.jpg'),
  ('00000000-0000-0000-0000-000000000672', 'Side to Side Box Shuffle', 'Legs', 'A', 'Plyometrics', 'Stand to one side of the box with your left foot resting on the middle of it.', 'To begin, jump up and over to the other side of the box, landing with your right foot on top of the box and your left foot on the floor. Swing your arms to aid your movement.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Side_to_Side_Box_Shuffle/0.jpg'),
  ('00000000-0000-0000-0000-000000000673', 'Single-Arm Cable Crossover', 'Chest', 'B', 'Strength', 'Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand.', 'Step forward in front of both pulleys with your arms extended in front of you, bringing your hands together. Your head and chest should be up as you lean forward, while your feet should be staggered. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Arm_Cable_Crossover/0.jpg'),
  ('00000000-0000-0000-0000-000000000674', 'Single-Arm Linear Jammer', 'Shoulders', 'B', 'Strength', 'Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.', 'Raise the bar from the floor, taking it to your shoulders with one or both hands. Adopt a wide stance. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Arm_Linear_Jammer/0.jpg'),
  ('00000000-0000-0000-0000-000000000675', 'Single-Arm Push-Up', 'Chest', 'S', 'Strength', 'Begin laying prone on the ground. Move yourself into a position supporting your weight on your toes and one arm. Your working arm should be placed directly under the shoulder, fully extended. Your legs should be extended, and for this movement you may need a wider base, placing your feet further apart than in a normal push-up.', 'Maintain good posture, and place your free hand behind your back. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Arm_Push-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000676', 'Single-Cone Sprint Drill', 'Legs', 'B', 'Plyometrics', 'This drill teaches quick foot action. You need a single cone. Begin standing next to the cone with one arm back and one arm forward.', 'Chop the feet as quickly as possible, blocking with the arms. Circle the cone, keep your knees up, with violent foot action.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Cone_Sprint_Drill/0.jpg'),
  ('00000000-0000-0000-0000-000000000677', 'Single-Leg High Box Squat', 'Legs', 'B', 'Strength', 'Position a box in a rack. Secure a band or rope in place above the box.', 'Standing in front of it, step onto the box to a full standing position, letting your other leg remain unsupported. Hold onto the band for balance', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_High_Box_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000678', 'Single-Leg Hop Progression', 'Legs', 'A', 'Plyometrics', 'Arrange a line of cones in front of you. Assume a relaxed standing position, balanced on one leg. Raise the knee of your opposite leg. This will be your starting position.', 'Hop forward, jumping and landing with the same leg over the cone.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Hop_Progression/0.jpg'),
  ('00000000-0000-0000-0000-000000000679', 'Single-Leg Lateral Hop', 'Legs', 'B', 'Plyometrics', 'Stand to the side of a cone or hurdle. To get into the start position, stand on one leg with your knee slightly bent.', 'To begin, execute a counterjump to hop sideways over the cone.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Lateral_Hop/0.jpg'),
  ('00000000-0000-0000-0000-000000000680', 'Single-Leg Leg Extension', 'Legs', 'S', 'Strength', 'Seat yourself in the machine and adjust it so that you are positioned properly. The pad should be against the lower part of the shin but not in contact with the ankle. Adjust the seat so that the pivot point is in line with your knee. Select a weight appropriate for your abilities.', 'Maintaining good posture, fully extend one leg, pausing at the top of the motion.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Leg_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000681', 'Single-Leg Stride Jump', 'Legs', 'A', 'Plyometrics', 'Stand to the side of a box with your inside foot on top of it, close to the edge.', 'Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single-Leg_Stride_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000682', 'Single Dumbbell Raise', 'Shoulders', 'B', 'Strength', 'With a wide stance, hold a dumbell with both hands, grasping the head of the dumbbell instead of the handle. Your arms should be extended and hanging at the waist. This will be your starting position.', 'Raise the weight until it is above shoulder level, keeping your arms extended. Your torso and hips should remain stationary throughout the movement.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Dumbbell_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000683', 'Single Leg Butt Kick', 'Legs', 'B', 'Plyometrics', 'Begin by standing on one leg, with the bent knee raised. This will be your start position.', 'Using a countermovement jump, take off upward by extending the hip, knee, and ankle of the grounded leg.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Leg_Butt_Kick/0.jpg'),
  ('00000000-0000-0000-0000-000000000684', 'Single Leg Glute Bridge', 'Legs', 'A', 'Strength', 'Lay on the floor with your feet flat and knees bent.', 'Raise one leg off of the ground, pulling the knee to your chest. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Leg_Glute_Bridge/0.jpg'),
  ('00000000-0000-0000-0000-000000000685', 'Single Leg Push-off', 'Legs', 'S', 'Plyometrics', 'Stand on the ground with one foot resting on the box, heel close to the edge.', 'Push off with your foot on top of the box, trying to gain as much height as possible by extending through the hip and knee.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Single_Leg_Push-off/0.jpg'),
  ('00000000-0000-0000-0000-000000000686', 'Sit-Up', 'Core', 'B', 'Strength', 'Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.', 'Place your hands behind your head and lock them together by clasping your fingers. This is the starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sit-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000687', 'Sit Squats', 'Legs', 'A', 'Stretching', 'Stand with your feet shoulder width apart. This will be your starting position.', 'Begin the movement by flexing your knees and hips, sitting back with your hips.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sit_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000688', 'Skating', 'Legs', 'B', 'Cardio', 'Roller skating is a fun activity which can be effective in improving cardiorespiratory fitness and muscular endurance. It requires relatively good balance and coordination. It is necessary to learn the basics of skating including turning and stopping and to wear protective gear to avoid possible injury.', 'You can skate at a comfortable pace for 30 minutes straight. If you want a cardio challenge, do interval skating — speed skate two minutes of every five minutes, using the remaining three minutes to recover. A 150 lb person will typically burn about 175 calories in 30 minutes skating at a comfortable pace, similar to brisk walking.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Skating/0.jpg'),
  ('00000000-0000-0000-0000-000000000689', 'Sled Drag - Harness', 'Legs', 'B', 'Strongman', 'To begin, load the sled with the desired weight and attach the pulling strap. You can pull with handles, use a harness, or attach the pulling strap to a weight belt.', 'Whether pulling forwards or backwards, lean in the direction of travel and progress by extending through the hips and knees.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Drag_-_Harness/0.jpg'),
  ('00000000-0000-0000-0000-000000000690', 'Sled Overhead Backward Walk', 'Shoulders', 'S', 'Strength', 'Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.', 'Face the sled, backing up until there is some tension in the line. Hold your hands directly above your head with your elbows extended. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Overhead_Backward_Walk/0.jpg'),
  ('00000000-0000-0000-0000-000000000691', 'Sled Overhead Triceps Extension', 'Arms', 'B', 'Strength', 'Attach dual handles to a sled using a chain or rope. Load the sled to an appropriate load.', 'Facing away from the sled, step away until there is tension in the line. Raise your hands above your head, keeping them together, palms facing each other. Your elbows should be pointed upward with the elbows flexed. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Overhead_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000692', 'Sled Push', 'Legs', 'B', 'Strongman', 'Load your pushing sled with the desired weight.', 'Take an athletic posture, leaning into the sled with your arms fully extended, grasping the handles. Push the sled as fast as possible, focusing on extending your hips and knees to strengthen your posterior chain.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Push/0.jpg'),
  ('00000000-0000-0000-0000-000000000693', 'Sled Reverse Flye', 'Shoulders', 'A', 'Strength', 'Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.', 'Face the sled, backing up until there is some tension in the line. Take both handles at arms length at about waist level. Bend the knees slightly and keep your chest and head up. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Reverse_Flye/0.jpg'),
  ('00000000-0000-0000-0000-000000000694', 'Sled Row', 'Back', 'B', 'Strength', 'Attach dual handles to a sled connected by a rope or chain. Load the sled to an appropriate weight. Face the sled, backing up until there is some tension in the line.', 'With a handle in each hand, bend the knees slightly, keep your head and chest up, and begin with your arms extended.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000695', 'Sledgehammer Swings', 'Core', 'S', 'Plyometrics', 'You will need a tire and a sledgehammer for this exercise. Stand in front of the tire about two feet away from it with a staggered stance. Grip the sledgehammer.', 'If you are right handed, your left hand should be at the bottom of the handle, and your right hand should be choking up closer to the head.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sledgehammer_Swings/0.jpg'),
  ('00000000-0000-0000-0000-000000000696', 'Smith Incline Shoulder Raise', 'Shoulders', 'A', 'Strength', 'Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your shoulders are aligned right under the barbell.', 'Using a shoulder width pronated (palms forward) grip, lift the bar from the rack and hold it straight over you with a slight bend at the elbows. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Incline_Shoulder_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000697', 'Smith Machine Behind the Back Shrug', 'Other', 'B', 'Strength', 'With the bar at thigh level, load an appropriate weight.', 'Stand with the bar behind you, taking a shoulder-width, pronated grip on the bar and unhook the weight. You should be standing up straight with your head and chest up and your arms extended. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Behind_the_Back_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000698', 'Smith Machine Bench Press', 'Chest', 'B', 'Strength', 'Place a flat bench underneath the smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your middle chest.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000699', 'Smith Machine Bent Over Row', 'Back', 'A', 'Strength', 'Set the barbell attached to the smith machine to a height that is about 2 inches below your knees.', 'Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Bent_Over_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000700', 'Smith Machine Calf Raise', 'Legs', 'S', 'Strength', 'Place a block or weight plate below the bar on the Smith machine. Set the bar to a position that best matches your height. Once the correct height is chosen and the bar is loaded, step onto the plates with the balls of your feet and place the bar on the back of your shoulders.', 'Take the bar with both hands facing forward. Rotate the bar to unrack it. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Calf_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000701', 'Smith Machine Close-Grip Bench Press', 'Arms', 'B', 'Strength', 'Place a flat bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a close and pronated grip (palms facing forward) that is around shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Close-Grip_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000702', 'Smith Machine Decline Press', 'Chest', 'A', 'Strength', 'Position a decline bench in the rack so that the bar will be above your chest. Load an appropriate weight and take your place on the bench.', 'Rotate the bar to unhook it from the rack and fully extend your arms. Your back should be slightly arched and your shoulder blades retracted. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Decline_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000703', 'Smith Machine Hang Power Clean', 'Legs', 'B', 'Strength', 'Position the bar at knee height and load it to an appropriate weight.', 'Take a pronated grip on the bar outside of shoulder width and unhook the bar from the machine. Your arms should be fully extended with your head and chest up. Your elbows should be pointed out with your shoulders back and down. Your hips should be back, loading the tension into the hamstrings. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Hang_Power_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000704', 'Smith Machine Hip Raise', 'Core', 'B', 'Strength', 'Position a bench in the rack and load the bar to an appropriate weight. Lie down on the bench, placing the bottom of your feet against the bar. Unlock the bar and extend your legs. You may need to use your hands to assist you. For added stability grasp the sides of the Smith Machine. This will be your starting position.', 'Initiate the movement by rotating your pelvis, flexing your spine to raise your hips off of the bench. Maintain a slight bend in the knees throughout the motion.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Hip_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000705', 'Smith Machine Incline Bench Press', 'Chest', 'S', 'Strength', 'Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your upper chest is aligned with the barbell. Using a pronated grip (palms facing forward) that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your upper chest.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Incline_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000706', 'Smith Machine Leg Press', 'Legs', 'B', 'Strength', 'Position a Smith machine bar a couple feet off of the ground. Ensure that it is resting on the safeties. After loading the bar to an appropriate weight, lie underneath the bar. Place the middle of your feet on the bar, tucking your knees to your chest. This will be your starting position.', 'Begin the movement by driving through your feet to move the bar upward, extending the hips and knees. Do not lock out your knees.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Leg_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000707', 'Smith Machine One-Arm Upright Row', 'Shoulders', 'B', 'Strength', 'With the bar at thigh level, load an appropriate weight.', 'Take a wide grip on the bar and unhook the weight, removing your off hand from the bar. Your arm should be extended as you stand up straight with your head and chest up. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_One-Arm_Upright_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000708', 'Smith Machine Overhead Shoulder Press', 'Shoulders', 'A', 'Strength', 'To begin, place a flat bench (or preferably one with back support) underneath a smith machine. Position the barbell at a height so that when seated on the flat bench, the arms must be almost fully extended to reach the barbell.', 'Once you have the correct height, sit slightly in behind the barbell so that there is an imaginary straight line from the tip of your nose to the barbell. Your feet should be stationary. Grab the barbell with the palms facing forward, unlock it and lift it up so that your arms are fully extended. This is the starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Overhead_Shoulder_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000709', 'Smith Machine Pistol Squat', 'Legs', 'B', 'Strength', 'To begin, first set the bar to a position that best matches your height. Step under it and position the bar across the back of your shoulders.', 'Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs. 3', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Pistol_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000710', 'Smith Machine Reverse Calf Raises', 'Legs', 'S', 'Strength', 'Adjust the barbell on the smith machine to fit your height and align a raised platform right under the bar.', 'Stand on the platform with the heels of your feet secured on top of it with the balls of your feet extending off it. Position your toes facing forward with a shoulder width stance.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Reverse_Calf_Raises/0.jpg'),
  ('00000000-0000-0000-0000-000000000711', 'Smith Machine Squat', 'Legs', 'A', 'Strength', 'To begin, first set the bar on the height that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side (palms facing forward), unlock it and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000712', 'Smith Machine Stiff-Legged Deadlift', 'Legs', 'B', 'Strength', 'To begin, set the bar on the smith machine to a height that is around the middle of your thighs. Once the correct height is chosen and the bar is loaded, grasp the bar using a pronated (palms forward) grip that is shoulder width apart. You may need some wrist wraps if using a significant amount of weight.', 'Lift the bar up by fully extending your arms while keeping your back straight. Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Stiff-Legged_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000713', 'Smith Machine Upright Row', 'Other', 'B', 'Strength', 'To begin, set the bar on the smith machine to a height that is around the middle of your thighs. Once the correct height is chosen and the bar is loaded, grasp the bar using a pronated (palms forward) grip that is shoulder width apart. You may need some wrist wraps if using a significant amount of weight.', 'Lift the barbell up and fully extend your arms with your back straight. There should be a slight bend at the elbows. This is the starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Upright_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000714', 'Smith Single-Leg Split Squat', 'Legs', 'A', 'Strength', 'To begin, place a flat bench 2-3 feet behind the smith machine. Then, set the bar on the height that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side (palms facing forward), unlock it and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Single-Leg_Split_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000715', 'Snatch', 'Legs', 'S', 'Olympic weightlifting', 'Place your feet at a shoulder width stance with the barbell resting right above the connection between the toes and the rest of the foot.', 'With a palms facing down grip, bend at the knees and keeping the back flat grab the bar using a wider than shoulder width grip. Bring the hips down and make sure that your body drops as if you were going to sit on a chair. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000716', 'Snatch Balance', 'Legs', 'B', 'Olympic weightlifting', 'Begin with the feet in the pulling position, the bar racked across the back of the shoulders, and the hands placed in a wide snatch grip.', 'Pop the bar with an abrupt dip and drive of the knees, and aggressively drive under the bar, transitioning the feet into the receiving position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch_Balance/0.jpg'),
  ('00000000-0000-0000-0000-000000000717', 'Snatch Deadlift', 'Legs', 'A', 'Olympic weightlifting', 'The snatch deadlift strengthens the first pull of the snatch. Begin with a wide snatch grip with the barbell placed on the platform. The feet should be directly under the hips, with the feet turned out. Squat down to the bar, keeping the back in absolute extension with the head facing forward.', 'Initiate the movement by driving through the heels, raising the hips. The back angle should remain the same until the bar passes the knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000718', 'Snatch Pull', 'Legs', 'B', 'Strength', 'With a barbell on the floor close to the shins, take a wide snatch grip. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.', 'Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch_Pull/0.jpg'),
  ('00000000-0000-0000-0000-000000000719', 'Snatch Shrug', 'Other', 'B', 'Olympic weightlifting', 'Begin with a wide grip, with the bar hanging at the mid thigh position. You can use a hook or overhand grip. Your back should be straight and inclined slightly forward.', 'Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a snatch, avoid overloading to the point that the execution slows down.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch_Shrug/0.jpg'),
  ('00000000-0000-0000-0000-000000000720', 'Snatch from Blocks', 'Legs', 'S', 'Olympic weightlifting', 'Begin with a loaded barbell on boxes or stands of the desired height. A wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar, with the elbows pointed out. This will be the starting position.', 'Begin the first pull by driving through the front of the heels, raising the bar from the boxes.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch_from_Blocks/0.jpg'),
  ('00000000-0000-0000-0000-000000000721', 'Speed Band Overhead Triceps', 'Arms', 'B', 'Strength', 'For this exercise anchor a band to the ground. We used an incline bench and anchored the band to the base, standing over the bench. Alternatively, this could be performed standing on the band.', 'To begin, pull the band behind your head, holding it with a pronated grip and your elbows up. This will be your starting position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Speed_Band_Overhead_Triceps/0.jpg'),
  ('00000000-0000-0000-0000-000000000722', 'Speed Box Squat', 'Legs', 'B', 'Powerlifting', 'Attach bands to the bar that are securely anchored near the ground. You may need to choke the bands to get adequate tension.', 'Use a box of an appropriate height for this exercise. Load the bar to a weight that still requires effort, but isn''t so heavy that speed is compromised. Typically, that will be between 50-70% of your one rep max.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Speed_Box_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000723', 'Speed Squats', 'Legs', 'A', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Speed_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000724', 'Spell Caster', 'Core', 'B', 'Strength', 'Hold a dumbbell in each hand with a pronated grip. Your feet should be wide with your hips and knees extended. This will be your starting position.', 'Begin the movement by pulling both of the dumbbells to one side next to your hip, rotating your torso.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Spell_Caster/0.jpg'),
  ('00000000-0000-0000-0000-000000000725', 'Spider Crawl', 'Core', 'S', 'Strength', 'Begin in a prone position on the floor. Support your weight on your hands and toes, with your feet together and your body straight. Your arms should be bent to 90 degrees. This will be your starting position.', 'Initiate the movement by raising one foot off of the ground. Externally rotate the leg and bring the knee toward your elbow, as far forward as possible.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Spider_Crawl/0.jpg'),
  ('00000000-0000-0000-0000-000000000726', 'Spider Curl', 'Arms', 'A', 'Strength', 'Start out by setting the bar on the part of the preacher bench that you would normally sit on. Make sure to align the barbell properly so that it is balanced and will not fall off.', 'Move to the front side of the preacher bench (the part where the arms usually lay) and position yourself to lay at a 45 degree slant with your torso and stomach pressed against the front side of the preacher bench.', 'E-z curl bar', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Spider_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000727', 'Spinal Stretch', 'Back', 'B', 'Stretching', 'Sit in a chair so your back is straight and your feet planted on the floor.', 'Interlace your fingers behind your head, elbows out and your chin down.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Spinal_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000728', 'Split Clean', 'Legs', 'B', 'Olympic weightlifting', 'With a barbell on the floor close to the shins, take an overhand grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.', 'Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Split_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000729', 'Split Jerk', 'Legs', 'A', 'Olympic weightlifting', 'Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward.', 'Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders. At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Split_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000730', 'Split Jump', 'Legs', 'S', 'Plyometrics', 'Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.', 'Ensure that the front knee is over the midline of the foot.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Split_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000731', 'Split Snatch', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a loaded barbell on the floor. The bar should be close to or touching the shins, and a wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.', 'Begin the first pull by driving through the front of the heels, raising the bar from the ground. The back angle should stay the same until the bar passes the knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Split_Snatch/0.jpg'),
  ('00000000-0000-0000-0000-000000000732', 'Split Squat with Dumbbells', 'Legs', 'A', 'Strength', 'Position yourself into a staggered stance with the rear foot elevated and front foot forward.', 'Hold a dumbbell in each hand, letting them hang at the sides. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Split_Squat_with_Dumbbells/0.jpg'),
  ('00000000-0000-0000-0000-000000000733', 'Split Squats', 'Legs', 'B', 'Stretching', 'Being in a standing position. Jump into a split leg position, with one leg forward and one leg back, flexing the knees and lowering your hips slightly as you do so.', 'As you descend, immediately reverse direction, standing back up and jumping, reversing the position of your legs. Repeat 5-10 times on each leg.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Split_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000734', 'Squat Jerk', 'Legs', 'B', 'Strength', 'Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.', 'At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athlete''s effort to push the bar up will drive them down. The feet should move forcefully to just outside the hips, turned out as necessary. Receive the bar with your body in a full squat and the arms fully extended overhead.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Squat_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000735', 'Squat with Bands', 'Legs', 'S', 'Powerlifting', 'Set up the bands on the sleeves, secured to either band pegs, the rack, or dumbbells so that there is appropriate tension.', 'Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings. Keep your head facing forward.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Squat_with_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000736', 'Squat with Chains', 'Legs', 'B', 'Powerlifting', 'To set up the chains, begin by looping the leader chain over the sleeves of the bar. The heavy chain should be attached using a snap hook. Adjust the length of the lead chain so that a few links are still on the floor at the top of the movement.', 'Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings. Keep your head facing forward.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Squat_with_Chains/0.jpg'),
  ('00000000-0000-0000-0000-000000000737', 'Squat with Plate Movers', 'Legs', 'B', 'Strength', 'To begin, first set the bar on a rack to just below shoulder level. Position a weight plate on the ground a couple feet back from the rack. Once the bar is loaded, step under it and place the back of your shoulders across it.', 'Hold on to the bar with both hands and lift it off the rack by first pushing with your legs and at the same time straighten your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Squat_with_Plate_Movers/0.jpg'),
  ('00000000-0000-0000-0000-000000000738', 'Squats - With Bands', 'Legs', 'A', 'Strength', 'To start out, make sure that the exercise band is at an even split between both the left and right side of the body. To do this, use your hands to grab both sides of the band and place both feet in the middle of the band. Your feet should be shoulder width apart from each other.', 'When holding the bands, they should be the same height on each side. You should be using a pronated grip (palms facing forward) and have the handles of the bands next to your face for this exercise. This is the starting position.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Squats_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000739', 'Stairmaster', 'Legs', 'B', 'Cardio', 'To begin, step onto the stairmaster and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise.', 'Pump your legs up and down in an established rhythm, driving the pedals down but not all the way to the floor. It is recommended that you maintain your grip on the handles so that you don''t fall. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Stairmaster/0.jpg'),
  ('00000000-0000-0000-0000-000000000740', 'Standing Alternating Dumbbell Press', 'Shoulders', 'S', 'Strength', 'Stand with a dumbbell in each hand. Raise the dumbbells to your shoulders with your palms facing forward and your elbows pointed out. This will be your starting position.', 'Extend one arm to press the dumbbell straight up, keeping your off hand in place. Do not lean or jerk the weight during the movement.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Alternating_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000741', 'Standing Barbell Calf Raise', 'Legs', 'A', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the bar on the back of your shoulders (slightly below the neck).', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Barbell_Calf_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000742', 'Standing Barbell Press Behind Neck', 'Shoulders', 'B', 'Strength', 'This exercise is best performed inside a squat rack for easier pick up of the bar. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Barbell_Press_Behind_Neck/0.jpg'),
  ('00000000-0000-0000-0000-000000000743', 'Standing Bent-Over One-Arm Dumbbell Triceps Extension', 'Arms', 'B', 'Strength', 'With a dumbbell in one hand and the palm facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.', 'The upper arm should be close to the torso and parallel to the floor while the forearm is pointing towards the floor as the hand holds the weight. Tip: There should be a 90-degree angle between the forearm and the upper arm. This is your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000744', 'Standing Bent-Over Two-Arm Dumbbell Triceps Extension', 'Arms', 'A', 'Strength', 'With a dumbbell in each hand and the palms facing your torso, bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up. The upper arms should be close to the torso and parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights. Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.', 'Keeping the upper arms stationary, use the triceps to lift the weights as you exhale until the forearms are parallel to the floor and the whole arms are extended. Like many other arm exercises, only the forearm moves.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000745', 'Standing Biceps Cable Curl', 'Arms', 'S', 'Strength', 'Stand up with your torso upright while holding a cable curl bar that is attached to a low pulley. Grab the cable bar at shoulder width and keep the elbows close to the torso. The palm of your hands should be facing up (supinated grip). This will be your starting position.', 'While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Biceps_Cable_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000746', 'Standing Biceps Stretch', 'Arms', 'B', 'Stretching', 'Clasp your hands behind your back with your palms together, straighten arms and then rotate them so your palms face downward.', 'Raise your arms up and hold until you feel a stretch in your biceps.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Biceps_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000747', 'Standing Bradford Press', 'Shoulders', 'A', 'Strength', 'Place a loaded bar at shoulder level in a rack. With a pronated grip at shoulder width, begin with the bar racked across the front of your shoulders. This is your starting position.', 'Initiate the lift by extending the elbows to press the bar overhead. Avoid locking out the elbow as you move the weight behind your head.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Bradford_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000748', 'Standing Cable Chest Press', 'Chest', 'B', 'Strength', 'Position dual pulleys to chest height and select an appropriate weight. Stand a foot or two in front of the cables, holding one in each hand. You can stagger your stance for better stability.', 'Position the upper arm at a 90 degree angle with the shoulder blades together. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Cable_Chest_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000749', 'Standing Cable Lift', 'Core', 'B', 'Strength', 'Connect a standard handle on a tower, and move the cable to the lowest pulley position.', 'With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Your outstretched arm should be aligned with the cable.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Cable_Lift/0.jpg'),
  ('00000000-0000-0000-0000-000000000750', 'Standing Cable Wood Chop', 'Core', 'S', 'Strength', 'Connect a standard handle to a tower, and move the cable to the highest pulley position.', 'With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Your outstretched arm should be aligned with the cable.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Cable_Wood_Chop/0.jpg'),
  ('00000000-0000-0000-0000-000000000751', 'Standing Calf Raises', 'Legs', 'B', 'Strength', 'Adjust the padded lever of the calf raise machine to fit your height.', 'Place your shoulders under the pads provided and position your toes facing forward (or using any of the two other positions described at the beginning of the chapter). The balls of your feet should be secured on top of the calf block with the heels extending off it. Push the lever up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Calf_Raises/0.jpg'),
  ('00000000-0000-0000-0000-000000000752', 'Standing Concentration Curl', 'Arms', 'B', 'Strength', 'Taking a dumbbell in your working hand, lean forward. Allow your working arm to hang perpendicular to the ground with the elbow pointing out. This will be your starting position.', 'Flex the elbow to curl the weight, keeping the upper arm stationary. At the top of the repetition, flex the biceps and pause.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Concentration_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000753', 'Standing Dumbbell Calf Raise', 'Legs', 'A', 'Strength', 'Stand with your torso upright holding two dumbbells in your hands by your sides. Place the ball of the foot on a sturdy and stable wooden board (that is around 2-3 inches tall) while your heels extend off and touch the floor. This will be your starting position.', 'With the toes pointing either straight (to hit all parts equally), inwards (for emphasis on the outer head) or outwards (for emphasis on the inner head), raise the heels off the floor as you exhale by contracting the calves. Hold the top contraction for a second.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Dumbbell_Calf_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000754', 'Standing Dumbbell Press', 'Shoulders', 'B', 'Strength', 'Standing with your feet shoulder width apart, take a dumbbell in each hand. Raise the dumbbells to head height, the elbows out and about 90 degrees. This will be your starting position.', 'Maintaining strict technique with no leg drive or leaning back, extend through the elbow to raise the weights together directly above your head.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000755', 'Standing Dumbbell Reverse Curl', 'Arms', 'S', 'Strength', 'To begin, stand straight with a dumbbell in each hand using a pronated grip (palms facing down). Your arms should be fully extended while your feet are shoulder width apart from each other. This is the starting position.', 'While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the muscle.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Dumbbell_Reverse_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000756', 'Standing Dumbbell Straight-Arm Front Delt Raise Above Head', 'Shoulders', 'A', 'Strength', 'Hold the dumbbells in front of your thighs, palms facing your thighs.', 'Keep your arms straight with a slight bend at the elbows but keep them locked. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Dumbbell_Straight-Arm_Front_Delt_Raise_Above_Head/0.jpg'),
  ('00000000-0000-0000-0000-000000000757', 'Standing Dumbbell Triceps Extension', 'Arms', 'B', 'Strength', 'To begin, stand up with a dumbbell held by both hands. Your feet should be about shoulder width apart from each other. Slowly use both hands to grab the dumbbell and lift it over your head until both arms are fully extended.', 'The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hands should be facing up towards the ceiling. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000758', 'Standing Dumbbell Upright Row', 'Other', 'B', 'Strength', 'Grasp a dumbbell in each hand with a pronated (palms forward) grip that is slightly less than shoulder width. The dumbbells should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.', 'Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be close to the body as you move it up and the elbows should drive the motion. Continue to lift them until they nearly touch your chin. Tip: Your elbows should drive the motion. As you lift the dumbbells, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Dumbbell_Upright_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000759', 'Standing Elevated Quad Stretch', 'Legs', 'A', 'Stretching', 'Start by standing with your back about two to three feet away from a bench or step.', 'Lift one leg behind you and rest your foot on the step,either on your instep or the ball of your foot, whichever you find most comfortable.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Elevated_Quad_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000760', 'Standing Front Barbell Raise Over Head', 'Shoulders', 'S', 'Strength', 'To begin, stand straight with a barbell in your hands. You should grip the bar with palms facing down and a closer than shoulder width grip apart from each other.', 'Your feet should be shoulder width apart from each other. Your elbows should be slightly bent. This is the starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Front_Barbell_Raise_Over_Head/0.jpg'),
  ('00000000-0000-0000-0000-000000000761', 'Standing Gastrocnemius Calf Stretch', 'Legs', 'B', 'Stretching', 'Place your right heel on a step with your knee extended and lean forward to grab your right toe with your right hand. Your left knee should be slightly bent and your back should be straight.', 'Support your weight on your left leg and place your left hand on your left thigh.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Gastrocnemius_Calf_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000762', 'Standing Hamstring and Calf Stretch', 'Legs', 'A', 'Stretching', 'Being by looping a belt, band, or rope around one foot. While standing, place that foot forward.', 'Bend your back leg, while keeping the front one straight. Now raise the toes of your front foot off of the ground and lean forward.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Hamstring_and_Calf_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000763', 'Standing Hip Circles', 'Legs', 'B', 'Stretching', 'Begin standing on one leg, holding to a vertical support.', 'Raise the unsupported knee to 90 degrees. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Hip_Circles/0.jpg'),
  ('00000000-0000-0000-0000-000000000764', 'Standing Hip Flexors', 'Legs', 'B', 'Stretching', 'Stand up straight with the spine vertical, the left foot slightly in front of the right.', 'Bend both knees and lift the back heel off the floor as you press the right hip forward. You can''t get a thorough, deep stretch in this position, however, because it''s hard to relax the hip flexor and stand on it at the same time. Switch sides.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Hip_Flexors/0.jpg'),
  ('00000000-0000-0000-0000-000000000765', 'Standing Inner-Biceps Curl', 'Arms', 'S', 'Strength', 'Stand up with a dumbbell in each hand being held at arms length. The elbows should be close to the torso. Your legs should be at about shoulder''s width apart from each other.', 'Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Inner-Biceps_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000766', 'Standing Lateral Stretch', 'Core', 'B', 'Stretching', 'Take a slightly wider than hip distance stance with your knees slightly bent.', 'Place your right hand on your right hip to support the spine.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Lateral_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000767', 'Standing Leg Curl', 'Legs', 'B', 'Strength', 'Adjust the machine lever to fit your height and lie with your torso bent at the waist facing forward around 30-45 degrees (since an angled position is more favorable for hamstrings recruitment) with the pad of the lever on the back of your right leg (just a few inches under the calves) and the front of the right leg on top of the machine pad.', 'Keeping the torso bent forward, ensure your leg is fully stretched and grab the side handles of the machine. Position your toes straight. This will be your starting position.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Leg_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000768', 'Standing Long Jump', 'Legs', 'A', 'Plyometrics', 'This drill is best done in sand or other soft landing surface. Ensure that you are able to measure distance. Stand in a partial squat stance with feet shoulder width apart.', 'Utilizing a big arm swing and a countermovement of the legs, jump forward as far as you can.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Long_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000769', 'Standing Low-Pulley Deltoid Raise', 'Shoulders', 'B', 'Strength', 'Start by standing to the right side of a low pulley row. Use your left hand to come across the body and grab a single handle attached to the low pulley with a pronated grip (palms facing down). Rest your arm in front of you. Your right hand should grab the machine for better support and balance.', 'Make sure that your back is erect and your feet are shoulder width apart from each other. This is the starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Low-Pulley_Deltoid_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000770', 'Standing Low-Pulley One-Arm Triceps Extension', 'Arms', 'S', 'Strength', 'Grab a single handle with your left arm next to the low pulley machine. Turn away from the machine keeping the handle to the side of your body with your arm fully extended. Now use both hands to elevate the single handle directly above the head with the palm facing forward. Keep your upper arm completely vertical (perpendicular to the floor) and put your right hand on your left elbow to help keep it steady. This is the starting position.', 'Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Low-Pulley_One-Arm_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000771', 'Standing Military Press', 'Shoulders', 'A', 'Strength', 'Start by placing a barbell that is about chest high on a squat rack. Once you have selected the weights, grab the barbell using a pronated (palms facing forward) grip. Make sure to grip the bar wider than shoulder width apart from each other.', 'Slightly bend the knees and place the barbell on your collar bone. Lift the barbell up keeping it lying on your chest. Take a step back and position your feet shoulder width apart from each other.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Military_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000772', 'Standing Olympic Plate Hand Squeeze', 'Arms', 'B', 'Strength', 'To begin, stand straight while holding a weight plate by the ridge at arm''s length in each hand using a neutral grip (palms facing in). You feet should be shoulder width apart from each other. This will be your starting position.', 'Lower the plates until the fingers are nearly extended but can still hold weights. Inhale as you lower the plates.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Olympic_Plate_Hand_Squeeze/0.jpg'),
  ('00000000-0000-0000-0000-000000000773', 'Standing One-Arm Cable Curl', 'Arms', 'B', 'Strength', 'Start out by grabbing single handle next to the low pulley machine. Make sure you are far enough from the machine so that your arm is supporting the weight.', 'Make sure that your upper arm is stationary, perpendicular to the floor with elbows in and palms facing forward. Your non lifting arm should be grabbing your waist. This will allow you to keep your balance.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_One-Arm_Cable_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000774', 'Standing One-Arm Dumbbell Curl Over Incline Bench', 'Arms', 'A', 'Strength', 'Stand on the back side of an incline bench as if you were going to be a spotter for someone. Have a dumbbell in one hand and rest it across the incline bench with a supinated (palms up) grip.', 'Position your non lifting hand at the corner or side of the incline bench. The chest should be pressed against the top part of the incline and your feet should be pressed against the floor at a wide stance. This is the starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_One-Arm_Dumbbell_Curl_Over_Incline_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000775', 'Standing One-Arm Dumbbell Triceps Extension', 'Arms', 'S', 'Strength', 'To begin, stand up with a dumbbell held in one hand. Your feet should be about shoulder width apart from each other. Now fully extend the arm with the dumbbell over your head. Tip: The small finger of your hand should be facing the ceiling and the palm of your hand should be facing forward. The dumbbell should be above your head.', 'This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_One-Arm_Dumbbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000776', 'Standing Overhead Barbell Triceps Extension', 'Arms', 'B', 'Strength', 'To begin, stand up holding a barbell or e-z bar using a pronated grip (palms facing forward) with your hands closer than shoulder width apart from each other. Your feet should be about shoulder width apart.', 'Now elevate the barbell above your head until your arms are fully extended. Keep your elbows in. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Overhead_Barbell_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000777', 'Standing Palm-In One-Arm Dumbbell Press', 'Shoulders', 'A', 'Strength', 'Start by having a dumbbell in one hand with your arm fully extended to the side using a neutral grip. Use your other arm to hold on to an incline bench to keep your balance.', 'Your feet should be shoulder width apart from each other. Now slowly lift the dumbbell up until you create a 90 degree angle with your arm. Note: Your forearm should be perpendicular to the floor. Continue to maintain a neutral grip throughout the entire exercise.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Palm-In_One-Arm_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000778', 'Standing Palms-In Dumbbell Press', 'Shoulders', 'B', 'Strength', 'Start by having a dumbbell in each hand with your arm fully extended to the side using a neutral grip. Your feet should be shoulder width apart from each other. Now slowly lift the dumbbells up until you create a 90 degree angle with your arms. Note: Your forearms should be perpendicular to the floor. This the starting position.', 'Continue to maintain a neutral grip throughout the entire exercise. Slowly lift the dumbbells up until your arms are fully extended.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Palms-In_Dumbbell_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000779', 'Standing Palms-Up Barbell Behind The Back Wrist Curl', 'Arms', 'B', 'Strength', 'Start by standing straight and holding a barbell behind your glutes at arm''s length while using a pronated grip (palms will be facing back away from the glutes) and having your hands shoulder width apart from each other.', 'You should be looking straight forward while your feet are shoulder width apart from each other. This is the starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Palms-Up_Barbell_Behind_The_Back_Wrist_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000780', 'Standing Pelvic Tilt', 'Back', 'S', 'Stretching', 'Start off with your feet hip-distance apart.', 'Bend your knees slightly to keep them soft and springy.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Pelvic_Tilt/0.jpg'),
  ('00000000-0000-0000-0000-000000000781', 'Standing Rope Crunch', 'Core', 'B', 'Strength', 'Attach a rope to a high pulley and select an appropriate weight.', 'Stand with your back to the cable tower. Take the rope with both hands over your shoulders, holding it to your upper chest. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Rope_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000782', 'Standing Soleus And Achilles Stretch', 'Legs', 'B', 'Stretching', 'Stand with your feet hip-distance apart, one foot slightly in front of the other.', 'Bend both knees, keeping your back heel on the floor. Switch sides.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Soleus_And_Achilles_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000783', 'Standing Toe Touches', 'Legs', 'A', 'Stretching', 'Stand with some space in front and behind you.', 'Bend at the waist, keeping your legs straight, until you can relax and let your upper body hang down in front of you. Let your arms and hands hang down naturally. Hold for 10 to 20 seconds.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Toe_Touches/0.jpg'),
  ('00000000-0000-0000-0000-000000000784', 'Standing Towel Triceps Extension', 'Arms', 'B', 'Strength', 'To begin, stand up with both arms fully extended above the head holding one end of a towel with both hands. Your elbows should be in and the arms perpendicular to the floor with the palms facing each other while your feet should be shoulder width apart from each other. This is the starting position.', 'Now communicate with your partner so that he/she can grip the other side of the towel to apply resistance. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Towel_Triceps_Extension/0.jpg'),
  ('00000000-0000-0000-0000-000000000785', 'Standing Two-Arm Overhead Throw', 'Shoulders', 'S', 'Plyometrics', 'Stand with your feet shoulder width apart holding a medicine ball in both hands. To begin, reach the medicine ball deep behind your head as you bend the knees slightly and lean back.', 'Violently throw the ball forward, flexing at the hip and using your whole body to complete the movement.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Two-Arm_Overhead_Throw/0.jpg'),
  ('00000000-0000-0000-0000-000000000786', 'Star Jump', 'Legs', 'A', 'Plyometrics', 'Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.', 'To initiate the move, squat down halfway and explode back up as high as possible. Fully extend your entire body, spreading your legs and arms away from the body.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Star_Jump/0.jpg'),
  ('00000000-0000-0000-0000-000000000787', 'Step-up with Knee Raise', 'Legs', 'B', 'Strength', 'Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position.', 'Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Step-up_with_Knee_Raise/0.jpg'),
  ('00000000-0000-0000-0000-000000000788', 'Step Mill', 'Legs', 'B', 'Cardio', 'To begin, step onto the stepmill and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Use caution so that you don''t trip as you climb the stairs. It is recommended that you maintain your grip on the handles so that you don''t fall.', 'Stepmills offer convenience, cardiovascular benefits, and usually have less impact than running outside while offering a similar rate of calories burned. They are typically much harder than other cardio equipment. A 150 lb person will typically burn over 300 calories in 30 minutes, compared to about 175 calories walking.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Step_Mill/0.jpg'),
  ('00000000-0000-0000-0000-000000000789', 'Stiff-Legged Barbell Deadlift', 'Legs', 'A', 'Strength', 'Grasp a bar using an overhand grip (palms facing down). You may need some wrist wraps if using a significant amount of weight.', 'Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Stiff-Legged_Barbell_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000790', 'Stiff-Legged Dumbbell Deadlift', 'Legs', 'S', 'Strength', 'Grasp a couple of dumbbells holding them by your side at arm''s length.', 'Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Stiff-Legged_Dumbbell_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000791', 'Stiff Leg Barbell Good Morning', 'Back', 'B', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Stiff_Leg_Barbell_Good_Morning/0.jpg'),
  ('00000000-0000-0000-0000-000000000792', 'Stomach Vacuum', 'Core', 'A', 'Stretching', 'To begin, stand straight with your feet shoulder width apart from each other. Place your hands on your hips. This is the starting position.', 'Now slowly inhale as much air as possible and then start to exhale as much as possible while bringing your stomach in as much as possible and hold this position. Try to visualize your navel touching your backbone.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Stomach_Vacuum/0.jpg'),
  ('00000000-0000-0000-0000-000000000793', 'Straight-Arm Dumbbell Pullover', 'Chest', 'B', 'Strength', 'Place a dumbbell standing up on a flat bench.', 'Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Straight-Arm_Dumbbell_Pullover/0.jpg'),
  ('00000000-0000-0000-0000-000000000794', 'Straight-Arm Pulldown', 'Back', 'B', 'Strength', 'You will start by grabbing the wide bar from the top pulley of a pulldown machine and using a wider than shoulder-width pronated (palms down) grip. Step backwards two feet or so.', 'Bend your torso forward at the waist by around 30-degrees with your arms fully extended in front of you and a slight bend at the elbows. If your arms are not fully extended then you need to step a bit more backwards until they are. Once your arms are fully extended and your torso is slightly bent at the waist, tighten the lats and then you are ready to begin.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Straight-Arm_Pulldown/0.jpg'),
  ('00000000-0000-0000-0000-000000000795', 'Straight Bar Bench Mid Rows', 'Back', 'S', 'Strength', 'Place a loaded barbell on the end of a bench. Standing on the bench behind the bar, take a medium, pronated grip. Stand with your hips back and chest up, maintaining a neutral spine. This will be your starting position.', 'Row the bar to your torso by retracting the shoulder blades and flexing the elbows. Use a controlled movement with no jerking.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Straight_Bar_Bench_Mid_Rows/0.jpg'),
  ('00000000-0000-0000-0000-000000000796', 'Straight Raises on Incline Bench', 'Shoulders', 'B', 'Strength', 'Place a bar on the ground behind the head of an incline bench.', 'Lay on the bench face down. With a pronated grip, pick the barbell up from the floor, keeping your arms straight. Allow the bar to hang straight down. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Straight_Raises_on_Incline_Bench/0.jpg'),
  ('00000000-0000-0000-0000-000000000797', 'Stride Jump Crossover', 'Legs', 'B', 'Plyometrics', 'Stand to the side of a box with your inside foot on top of it, close to the edge.', 'Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Stride_Jump_Crossover/0.jpg'),
  ('00000000-0000-0000-0000-000000000798', 'Sumo Deadlift', 'Legs', 'A', 'Powerlifting', 'Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.', 'Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sumo_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000799', 'Sumo Deadlift with Bands', 'Legs', 'B', 'Powerlifting', 'To deadlift with short bands, simply loop them over the bar before you start, and step into them to set up. Ensure that they under the back half of your foot, directly where you are driving into the floor.', 'Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sumo_Deadlift_with_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000800', 'Sumo Deadlift with Chains', 'Legs', 'S', 'Powerlifting', 'You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift. Attempt to keep the ends of the chains away from the plates so you don''t hit them when you lower the weight.', 'Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sumo_Deadlift_with_Chains/0.jpg'),
  ('00000000-0000-0000-0000-000000000801', 'Superman', 'Back', 'A', 'Stretching', 'To begin, lie straight and face down on the floor or exercise mat. Your arms should be fully extended in front of you. This is the starting position.', 'Simultaneously raise your arms, legs, and chest off of the floor and hold this contraction for 2 seconds. Tip: Squeeze your lower back to get the best results from this exercise. Remember to exhale during this movement. Note: When holding the contracted position, you should look like superman when he is flying.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Superman/0.jpg'),
  ('00000000-0000-0000-0000-000000000802', 'Supine Chest Throw', 'Arms', 'B', 'Plyometrics', 'This drill is great for chest passes when you lack a partner or a wall of sufficient strength. Lay on the ground on your back with your knees bent.', 'Begin with the ball on your chest, held with both hands on the bottom.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Supine_Chest_Throw/0.jpg'),
  ('00000000-0000-0000-0000-000000000803', 'Supine One-Arm Overhead Throw', 'Core', 'B', 'Plyometrics', 'Lay on the ground on your back with your knees bent. Hold the ball with one hand, extending the arm fully behind your head. This will be your starting position.', 'Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Supine_One-Arm_Overhead_Throw/0.jpg'),
  ('00000000-0000-0000-0000-000000000804', 'Supine Two-Arm Overhead Throw', 'Core', 'A', 'Plyometrics', 'Lay on the ground on your back with your knees bent.', 'Hold the ball with both hands, extending the arms fully behind your head. This will be your starting position.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Supine_Two-Arm_Overhead_Throw/0.jpg'),
  ('00000000-0000-0000-0000-000000000805', 'Suspended Fallout', 'Core', 'S', 'Strength', 'Adjust the straps so the handles are at an appropriate height, below waist level.', 'Begin standing and grasping the handles. Lean into the straps, moving to an incline push-up position. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Fallout/0.jpg'),
  ('00000000-0000-0000-0000-000000000806', 'Suspended Push-Up', 'Chest', 'B', 'Strength', 'Anchor your suspension straps securely to the top of a rack or other object.', 'Leaning into the straps, take a handle in each hand and move into a push-up plank position. You should be as close to parallel to the ground as you can manage with your arms fully extended, maintaining good posture.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Push-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000807', 'Suspended Reverse Crunch', 'Core', 'A', 'Strength', 'Secure a set of suspension straps with the handles hanging about a foot off of the ground. Move yourself into a pushup plank position facing away from the rack.', 'Place your feet into the handles. You should maintain a straight posture, not allowing the hips to sag. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Reverse_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000808', 'Suspended Row', 'Back', 'B', 'Strength', 'Suspend your straps at around chest height. Take a handle in each hand and lean back. Keep your body erect and your head and chest up. Your arms should be fully extended. This will be your starting position.', 'Begin by flexing the elbow to initiate the movement. Protract your shoulder blades as you do so.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000809', 'Suspended Split Squat', 'Legs', 'B', 'Strength', 'Suspend your straps so the handles are 18-30 inches from the floor.', 'Facing away from the setup, place your rear foot into the handle behind you. Keep your head looking forward and your chest up, with your knee slightly bent. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Split_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000810', 'Svend Press', 'Chest', 'S', 'Strength', 'Begin in a standing position.', 'Press two lightweight plates together with your hands. Hold the plates together close to your chest to create an isometric contraction in your chest muscles. Your fingers should be pointed forward. This is your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Svend_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000811', 'T-Bar Row with Handle', 'Back', 'B', 'Strength', 'Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.', 'Stand over the bar, and position a Double D row handle around the bar next to the collar. Using your hips and legs, rise to a standing position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/T-Bar_Row_with_Handle/0.jpg'),
  ('00000000-0000-0000-0000-000000000812', 'Tate Press', 'Arms', 'B', 'Strength', 'Lie down on a flat bench with a dumbbell in each hand on top of your thighs. The palms of your hand will be facing each other.', 'By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them in front of you at shoulder width. Note: when holding the dumbbells in front of you, make sure your arms are wider than shoulder width apart from each other using a pronated (palms forward) grip. Allow your elbows to point out. This is your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Tate_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000813', 'The Straddle', 'Legs', 'A', 'Stretching', 'Begin in a seated, upright position. Start by extending your legs in front of you in a V.', 'With your hands on the floor, lean forward as far as possible. Hold for 10 to 20 seconds.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/The_Straddle/0.jpg'),
  ('00000000-0000-0000-0000-000000000814', 'Thigh Abductor', 'Legs', 'B', 'Strength', 'To begin, sit down on the abductor machine and select a weight you are comfortable with. When your legs are positioned properly, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.', 'Slowly press against the machine with your legs to move them away from each other while exhaling.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Thigh_Abductor/0.jpg'),
  ('00000000-0000-0000-0000-000000000815', 'Thigh Adductor', 'Legs', 'S', 'Strength', 'To begin, sit down on the adductor machine and select a weight you are comfortable with. When your legs are positioned properly on the leg pads of the machine, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.', 'Slowly press against the machine with your legs to move them towards each other while exhaling.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Thigh_Adductor/0.jpg'),
  ('00000000-0000-0000-0000-000000000816', 'Tire Flip', 'Legs', 'A', 'Strongman', 'Begin by gripping the bottom of the tire on the tread, and position your feet back a bit. Your chest should be driving into the tire.', 'To lift the tire, extend through the hips, knees, and ankles, driving into the tire and up.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Tire_Flip/0.jpg'),
  ('00000000-0000-0000-0000-000000000817', 'Toe Touchers', 'Core', 'B', 'Stretching', 'To begin, lie down on the floor or an exercise mat with your back pressed against the floor. Your arms should be lying across your sides with the palms facing down.', 'Your legs should be touching each other. Slowly elevate your legs up in the air until they are almost perpendicular to the floor with a slight bend at the knees. Your feet should be parallel to the floor.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Toe_Touchers/0.jpg'),
  ('00000000-0000-0000-0000-000000000818', 'Torso Rotation', 'Core', 'B', 'Stretching', 'Stand upright holding an exercise ball with both hands. Extend your arms so the ball is straight out in front of you. This will be your starting position.', 'Rotate your torso to one side, keeping your eyes on the ball as you move. Now, rotate back to the opposite direction. Repeat for 10-20 repetitions.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Torso_Rotation/0.jpg'),
  ('00000000-0000-0000-0000-000000000819', 'Trail Running/Walking', 'Legs', 'A', 'Cardio', 'Running or hiking on trails will get the blood pumping and heart beating almost immediately. Make sure you have good shoes. While you use the muscles in your calves and buttocks to pull yourself up a hill, the knees, joints and ankles absorb the bulk of the pounding coming back down. Take smaller steps as you walk downhill, keep your knees bent to reduce the impact and slow down to avoid falling.', 'A 150 lb person can burn over 200 calories for 30 minutes walking uphill, compared to 175 on a flat surface. If running the trail, a 150 lb person can burn well over 500 calories in 30 minutes.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Trail_Running_Walking/0.jpg'),
  ('00000000-0000-0000-0000-000000000820', 'Trap Bar Deadlift', 'Legs', 'S', 'Strength', 'For this exercise load a trap bar, also known as a hex bar, to an appropriate weight resting on the ground. Stand in the center of the apparatus and grasp both handles.', 'Lower your hips, look forward with your head and keep your chest up.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Trap_Bar_Deadlift/0.jpg'),
  ('00000000-0000-0000-0000-000000000821', 'Tricep Dumbbell Kickback', 'Arms', 'B', 'Strength', 'Start with a dumbbell in each hand and your palms facing your torso. Keep your back straight with a slight bend in the knees and bend forward at the waist. Your torso should be almost parallel to the floor. Make sure to keep your head up. Your upper arms should be close to your torso and parallel to the floor. Your forearms should be pointed towards the floor as you hold the weights. There should be a 90-degree angle formed between your forearm and upper arm. This is your starting position.', 'Now, while keeping your upper arms stationary, exhale and use your triceps to lift the weights until the arm is fully extended. Focus on moving the forearm.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Tricep_Dumbbell_Kickback/0.jpg'),
  ('00000000-0000-0000-0000-000000000822', 'Tricep Side Stretch', 'Arms', 'A', 'Stretching', 'Bring right arm across your body and over your left shoulder, holding your elbow with your left hand, until you feel a stretch in your tricep. Then repeat for your other arm.', 'Targets triceps.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Tricep_Side_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000823', 'Triceps Overhead Extension with Rope', 'Arms', 'B', 'Strength', 'Attach a rope to a low pulley. After selecting an appropriate weight, grasp the rope with both hands and face away from the cable.', 'Position your hands behind your head with your elbows point straight up. Your elbows should start out flexed, and you can stagger your stance and lean gently away from the machine to create greater stability. This will be your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Triceps_Overhead_Extension_with_Rope/0.jpg'),
  ('00000000-0000-0000-0000-000000000824', 'Triceps Pushdown', 'Arms', 'B', 'Strength', 'Attach a straight or angled bar to a high pulley and grab with an overhand grip (palms facing down) at shoulder width.', 'Standing upright with the torso straight and a very small inclination forward, bring the upper arms close to your body and perpendicular to the floor. The forearms should be pointing up towards the pulley as they hold the bar. This is your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Triceps_Pushdown/0.jpg'),
  ('00000000-0000-0000-0000-000000000825', 'Triceps Pushdown - Rope Attachment', 'Arms', 'S', 'Strength', 'Attach a rope attachment to a high pulley and grab with a neutral grip (palms facing each other).', 'Standing upright with the torso straight and a very small inclination forward, bring the upper arms close to your body and perpendicular to the floor. The forearms should be pointing up towards the pulley as they hold the rope with the palms facing each other. This is your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Triceps_Pushdown_-_Rope_Attachment/0.jpg'),
  ('00000000-0000-0000-0000-000000000826', 'Triceps Pushdown - V-Bar Attachment', 'Arms', 'B', 'Strength', 'Attach a V-Bar to a high pulley and grab with an overhand grip (palms facing down) at shoulder width.', 'Standing upright with the torso straight and a very small inclination forward, bring the upper arms close to your body and perpendicular to the floor. The forearms should be pointing up towards the pulley as they hold the bar. The thumbs should be higher than the small finger. This is your starting position.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Triceps_Pushdown_-_V-Bar_Attachment/0.jpg'),
  ('00000000-0000-0000-0000-000000000827', 'Triceps Stretch', 'Arms', 'B', 'Stretching', 'Reach your hand behind your head, grasp your elbow and gently pull. Hold for 10 to 20 seconds, then switch sides.', 'Targets triceps.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Triceps_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000828', 'Tuck Crunch', 'Core', 'A', 'Strength', 'To begin, lie down on the floor or an exercise mat with your back pressed against the floor. Your arms should be lying across your sides with the palms facing down.', 'Your legs should be crossed by wrapping one ankle around the other. Slowly elevate your legs up in the air until your thighs are perpendicular to the floor with a slight bend at the knees. Note: Your knees and toes should be parallel to the floor as opposed to the thighs.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Tuck_Crunch/0.jpg'),
  ('00000000-0000-0000-0000-000000000829', 'Two-Arm Dumbbell Preacher Curl', 'Arms', 'B', 'Strength', 'Grab a dumbbell with each arm and place the upper arms on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.', 'As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Two-Arm_Dumbbell_Preacher_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000830', 'Two-Arm Kettlebell Clean', 'Shoulders', 'S', 'Strength', 'Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.', 'Clean the kettlebells to your shoulders by extending through the legs and hips as you raise the kettlebells towards your shoulders. Rotate your wrists as you do so.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Two-Arm_Kettlebell_Clean/0.jpg'),
  ('00000000-0000-0000-0000-000000000831', 'Two-Arm Kettlebell Jerk', 'Shoulders', 'A', 'Strength', 'Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you swing the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. Squat down a few inches and reverse the motion rapidly driving both kettlebells overhead. Immediately after the initial push, squat down again and get under the kettlebells. Once the kettlebells are locked out, stand upright to complete the exercise.', 'Targets shoulders.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Two-Arm_Kettlebell_Jerk/0.jpg'),
  ('00000000-0000-0000-0000-000000000832', 'Two-Arm Kettlebell Military Press', 'Shoulders', 'B', 'Strength', 'Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you swing the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward.', 'Press the kettlebells up and out. As the kettlebells pass your head, lean into the weights so that the kettlebells are racked behind your head. Make sure to contract your lats, butt, and stomach for added stability.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Two-Arm_Kettlebell_Military_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000833', 'Two-Arm Kettlebell Row', 'Back', 'B', 'Strength', 'Place two kettlebells in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position.', 'Grab both kettlebells and pull them to your stomach, retracting your shoulder blades and flexing the elbows. Keep your back straight. Lower and repeat.', 'Kettlebells', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Two-Arm_Kettlebell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000834', 'Underhand Cable Pulldowns', 'Back', 'A', 'Strength', 'Sit down on a pull-down machine with a wide bar attached to the top pulley. Adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.', 'Grab the pull-down bar with the palms facing your torso (a supinated grip). Make sure that the hands are placed closer than the shoulder width.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Underhand_Cable_Pulldowns/0.jpg'),
  ('00000000-0000-0000-0000-000000000835', 'Upper Back-Leg Grab', 'Legs', 'S', 'Stretching', 'While seated, bend forward to hug your thighs from underneath with both arms.', 'Keep your knees together and your legs extended out as you bring your chest down to your knees. You can also stretch your middle back by pulling your back away from your knees as your hugging them.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Upper_Back-Leg_Grab/0.jpg'),
  ('00000000-0000-0000-0000-000000000836', 'Upper Back Stretch', 'Back', 'B', 'Stretching', 'Clasp fingers together with your thumbs pointing down, round your shoulders as you reach your hands forward.', 'Targets middle back.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Upper_Back_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000837', 'Upright Barbell Row', 'Shoulders', 'A', 'Strength', 'Grasp a barbell with an overhand grip that is slightly less than shoulder width. The bar should be resting on the top of your thighs with your arms extended and a slight bend in your elbows. Your back should also be straight. This will be your starting position.', 'Now exhale and use the sides of your shoulders to lift the bar, raising your elbows up and to the side. Keep the bar close to your body as you raise it. Continue to lift the bar until it nearly touches your chin. Tip: Your elbows should drive the motion, and should always be higher than your forearms. Remember to keep your torso stationary and pause for a second at the top of the movement.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Upright_Barbell_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000838', 'Upright Cable Row', 'Other', 'B', 'Strength', 'Grasp a straight bar cable attachment that is attached to a low pulley with a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The bar should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.', 'Use your side shoulders to lift the cable bar as you exhale. The bar should be close to the body as you move it up. Continue to lift it until it nearly touches your chin. Tip: Your elbows should drive the motion. As you lift the bar, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Upright_Cable_Row/0.jpg'),
  ('00000000-0000-0000-0000-000000000839', 'Upright Row - With Bands', 'Other', 'B', 'Strength', 'To begin, stand on an exercise band so that tension begins at arm''s length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.', 'Use your side shoulders to lift the handles as you exhale. The handles should be close to the body as you move them up. Continue to lift the handles until they nearly touches your chin. Tip: Your elbows should drive the motion. As you lift the handles, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.', 'Bands', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Upright_Row_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000840', 'Upward Stretch', 'Shoulders', 'S', 'Stretching', 'Extend both hands straight above your head, palms touching.', 'Slowly push your hands up and back, keeping your back straight.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Upward_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000841', 'V-Bar Pulldown', 'Back', 'B', 'Strength', 'Sit down on a pull-down machine with a V-Bar attached to the top pulley.', 'Adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/V-Bar_Pulldown/0.jpg'),
  ('00000000-0000-0000-0000-000000000842', 'V-Bar Pullup', 'Back', 'B', 'Strength', 'Start by placing the middle of the V-bar in the middle of the pull-up bar (assuming that the pull-up station you are using does not have neutral grip handles). The V-Bar handles will be facing down so that you can hang from the pull-up bar through the use of the handles.', 'Once you securely place the V-bar, take a hold of the bar from each side and hang from it. Stick your chest out and lean yourself back slightly in order to better engage the lats. This will be your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/V-Bar_Pullup/0.jpg'),
  ('00000000-0000-0000-0000-000000000843', 'Vertical Swing', 'Legs', 'A', 'Plyometrics', 'Allow the dumbbell to hang at arms length between your legs, holding it with both hands. Keep your back straight and your head up.', 'Swing the dumbbell between your legs, flexing at the hips and bending the knees slightly.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Vertical_Swing/0.jpg'),
  ('00000000-0000-0000-0000-000000000844', 'Walking, Treadmill', 'Legs', 'B', 'Cardio', 'To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.', 'Treadmills offer convenience, cardiovascular benefits, and usually have less impact than walking outside. When walking, you should move at a moderate to fast pace, not a leisurely one. Being an activity of lower intensity, walking doesn''t burn as many calories as some other activities, but still provides great benefit. A 150 lb person will burn about 175 calories walking 4 miles per hour for 30 minutes, compared to 450 calories running twice as fast. Maintain proper posture as you walk, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.', 'Machine', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Walking_Treadmill/0.jpg'),
  ('00000000-0000-0000-0000-000000000845', 'Weighted Ball Hyperextension', 'Back', 'S', 'Strength', 'To begin, lie down on an exercise ball with your torso pressing against the ball and parallel to the floor. The ball of your feet should be pressed against the floor to help keep you balanced. Place a weighted plate under your chin or behind your neck. This is the starting position.', 'Slowly raise your torso up by bending at the waist and lower back. Remember to exhale during this movement.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Ball_Hyperextension/0.jpg'),
  ('00000000-0000-0000-0000-000000000846', 'Weighted Ball Side Bend', 'Core', 'A', 'Strength', 'To begin, lie down on an exercise ball with your left side of the torso (waist, hips and shoulder) pressed against the ball.', 'Your feet should be on the floor while your legs are crossed and hanging from the ball. Hold a weighted plate with your right hand directly to the right side of your head. Tip: Make sure the smooth side of the plate is resting against your head.', 'Exercise ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Ball_Side_Bend/0.jpg'),
  ('00000000-0000-0000-0000-000000000847', 'Weighted Bench Dip', 'Arms', 'B', 'Strength', 'For this exercise you will need to place a bench behind your back and another one in front of you. With the benches perpendicular to your body, hold on to one bench on its edge with the hands close to your body, separated at shoulder width. Your arms should be fully extended.', 'The legs will be extended forward on top of the other bench. Your legs should be parallel to the floor while your torso is to be perpendicular to the floor. Have your partner place the dumbbell on your lap. Note: This exercise is best performed with a partner as placing the weight on your lap can be challenging and cause injury without assistance. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Bench_Dip/0.jpg'),
  ('00000000-0000-0000-0000-000000000848', 'Weighted Crunches', 'Core', 'B', 'Strength', 'Lie flat on your back with your feet flat on the ground or resting on a bench with your knees bent at a 90 degree angle.', 'Hold a weight to your chest, or you may hold it extended above your torso. This will be your starting position.', 'Medicine ball', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Crunches/0.jpg'),
  ('00000000-0000-0000-0000-000000000849', 'Weighted Jump Squat', 'Legs', 'A', 'Strength', 'Position a lightly loaded barbell across the back of your shoulders. You could also use a weighted vest, sandbag, or other type of resistance for this exercise.', 'The weight should be light enough that it doesn''t slow you down significantly. Your feet should be just outside of shoulder width with your head and chest up. This will be your starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Jump_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000850', 'Weighted Pull Ups', 'Back', 'S', 'Strength', 'Attach a weight to a dip belt and secure it around your waist. Grab the pull-up bar with the palms of your hands facing forward. For a medium grip, your hands should be spaced at shoulder width. Both arms should be extended in front of you holding the bar at the chosen grip.', 'You''ll want to bring your torso back about 30 degrees while creating a curvature in your lower back and sticking your chest out. This will be your starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Pull_Ups/0.jpg'),
  ('00000000-0000-0000-0000-000000000851', 'Weighted Sissy Squat', 'Legs', 'B', 'Strength', 'Standing upright, with feet at shoulder width and toes raised, use one hand to hold onto the beams of a squat rack and the opposite arm to hold a plate on top of your chest. This is your starting position.', 'As you use one arm to hold yourself, bend at the knees and slowly lower your torso toward the ground by bringing your pelvis and knees forward. Inhale as you go down and stop when your upper and lower legs almost create a 90-degree angle. Hold the stretch position for a second.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Sissy_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000852', 'Weighted Sit-Ups - With Bands', 'Core', 'A', 'Strength', 'Start out by strapping the bands around the base of the decline bench. Place the handles towards the inside of the decline bench so that when lying down, you can reach for both of them.', 'Position your legs through the decline machine until they are secured. Now reach for the exercise bands with both hands. Use a pronated (palms forward) grip to grasp the handles. Position them near your collar bone and rotate your wrist to a neutral grip (palms facing the torso). Note: Your arms should remain stationary throughout the exercise. This is the starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Sit-Ups_-_With_Bands/0.jpg'),
  ('00000000-0000-0000-0000-000000000853', 'Weighted Squat', 'Legs', 'B', 'Strength', 'Start by positioning two flat benches shoulder width apart from each other. Stand on top of them and wrap the weighted belt around your waist with the amount of weight you feel comfortable with. Make sure your toes are facing out.', 'Once you are standing straight up with the weight hanging in between your legs, position your arms so that they are fully extended to the side of your body. This is the starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000854', 'Wide-Grip Barbell Bench Press', 'Chest', 'B', 'Strength', 'Lie back on a flat bench with feet firm on the floor. Using a wide, pronated (palms forward) grip that is around 3 inches away from shoulder width (for each hand), lift the bar from the rack and hold it straight over you with your arms locked. The bar will be perpendicular to the torso and the floor. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your middle chest.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Barbell_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000855', 'Wide-Grip Decline Barbell Bench Press', 'Chest', 'S', 'Strength', 'Lie back on a decline bench with the feet securely locked at the front of the bench. Using a wide, pronated (palms forward) grip that is around 3 inches away from shoulder width (for each hand), lift the bar from the rack and hold it straight over you with your arms locked. The bar will be perpendicular to the torso and the floor. This will be your starting position.', 'As you breathe in, come down slowly until you feel the bar on your lower chest.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Decline_Barbell_Bench_Press/0.jpg'),
  ('00000000-0000-0000-0000-000000000856', 'Wide-Grip Decline Barbell Pullover', 'Chest', 'B', 'Strength', 'Lie down on a decline bench with both legs securely locked in position. Reach for the barbell behind the head using a pronated grip (palms facing out). Make sure to grab the barbell wider than shoulder width apart for this exercise. Slowly lift the barbell up from the floor by using your arms.', 'When positioned properly, your arms should be fully extended and perpendicular to the floor. This is the starting position.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Decline_Barbell_Pullover/0.jpg'),
  ('00000000-0000-0000-0000-000000000857', 'Wide-Grip Lat Pulldown', 'Back', 'B', 'Strength', 'Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.', 'Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Lat_Pulldown/0.jpg'),
  ('00000000-0000-0000-0000-000000000858', 'Wide-Grip Pulldown Behind The Neck', 'Back', 'A', 'Strength', 'Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.', 'Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.', 'Cable', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Pulldown_Behind_The_Neck/0.jpg'),
  ('00000000-0000-0000-0000-000000000859', 'Wide-Grip Rear Pull-Up', 'Back', 'B', 'Strength', 'Grab the pull-up bar with the palms facing forward using a wide grip.', 'As you have both arms extended in front of you holding the bar, bring your torso forward and head so that there is an imaginary line from the pull-up bar to the back of your neck. This is your starting position.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Rear_Pull-Up/0.jpg'),
  ('00000000-0000-0000-0000-000000000860', 'Wide-Grip Standing Barbell Curl', 'Arms', 'S', 'Strength', 'Stand up with your torso upright while holding a barbell at the wide outer handle. The palm of your hands should be facing forward. The elbows should be close to the torso. This will be your starting position.', 'While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide-Grip_Standing_Barbell_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000861', 'Wide Stance Barbell Squat', 'Legs', 'A', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.', 'Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide_Stance_Barbell_Squat/0.jpg'),
  ('00000000-0000-0000-0000-000000000862', 'Wide Stance Stiff Legs', 'Legs', 'B', 'Olympic weightlifting', 'Begin with a barbell loaded on the floor. Adopt a wide stance, and then bend at the hips to grab the bar. Your hips should be as far back as possible, and your legs nearly straight. Keep your back straight, and your head and chest up. This will be your starting position.', 'Begin the movement be engaging the hips, driving them forward as you allow the arms to hang straight. Continue until you are standing straight up, and then slowly return the weight to the starting position. For successive reps, the weight need not touch the floor.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wide_Stance_Stiff_Legs/0.jpg'),
  ('00000000-0000-0000-0000-000000000863', 'Wind Sprints', 'Core', 'B', 'Strength', 'Hang from a pull-up bar using a pronated grip. Your arms and legs should be extended. This will be your starting position.', 'Begin by quickly raising one knee as high as you can. Do not swing your body or your legs. 3', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wind_Sprints/0.jpg'),
  ('00000000-0000-0000-0000-000000000864', 'Windmills', 'Legs', 'A', 'Stretching', 'Lie on your back with your arms extended out to the sides and your legs straight. This will be your starting position.', 'Lift one leg and quickly cross it over your body, attempting to touch the ground near the opposite hand.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Windmills/0.jpg'),
  ('00000000-0000-0000-0000-000000000865', 'World''s Greatest Stretch', 'Legs', 'S', 'Stretching', 'This is a three-part stretch. Begin by lunging forward, with your front foot flat on the ground and on the toes of your back foot. With your knees bent, squat down until your knee is almost touching the ground. Keep your torso erect, and hold this position for 10-20 seconds.', 'Now, place the arm on the same side as your front leg on the ground, with the elbow next to the foot. Your other hand should be placed on the ground, parallel to your lead leg, to help support you during this portion of the stretch.', 'Bodyweight', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Worlds_Greatest_Stretch/0.jpg'),
  ('00000000-0000-0000-0000-000000000866', 'Wrist Circles', 'Arms', 'B', 'Stretching', 'Start by standing straight with your feet being shoulder width apart from each other. Elevate your arms to the side of you until they are fully extended and parallel to the floor at a height that is evenly aligned with your shoulders. Tip: Your torso and arms should form the letter "T: Your palms should be facing down. This is the starting position.', 'Keeping your entire body stationary except for the wrists, begin to rotate both wrists forward in a circular motion. Tip: Pretend that you are trying to draw circles by using your hands as the brush. Breathe normally as you perform this exercise.', 'Body only', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wrist_Circles/0.jpg'),
  ('00000000-0000-0000-0000-000000000867', 'Wrist Roller', 'Arms', 'A', 'Strength', 'To begin, stand straight up grabbing a wrist roller using a pronated grip (palms facing down). Your feet should be shoulder width apart.', 'Slowly lift both arms until they are fully extended and parallel to the floor in front of you. Note: Make sure the rope is not wrapped around the roller. Your entire body should be stationary except for the forearms. This is the starting position.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wrist_Roller/0.jpg'),
  ('00000000-0000-0000-0000-000000000868', 'Wrist Rotations with Straight Bar', 'Arms', 'B', 'Strength', 'Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width. This will be your starting position.', 'Alternating between each of your hands, perform the movement by extending the wrist as though you were rolling up a newspaper. Continue alternating back and forth until failure.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Wrist_Rotations_with_Straight_Bar/0.jpg'),
  ('00000000-0000-0000-0000-000000000869', 'Yoke Walk', 'Legs', 'B', 'Strongman', 'The yoke is usually done with a yoke apparatus, but is sometimes seen with refrigerators or other heavy objects.', 'Begin by racking the apparatus across the back of the shoulders. With your head looking forward and back arched, lift the yoke by driving through the heels.', 'Other', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Yoke_Walk/0.jpg'),
  ('00000000-0000-0000-0000-000000000870', 'Zercher Squats', 'Legs', 'S', 'Strength', 'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. The correct height should be anywhere above the waist but below the chest. Once the correct height is chosen and the bar is loaded, lock your hands together and place the bar on top of your arms in between the forearm and upper arm.', 'Lift the bar up so that it is resting on top of your forearms. If you are holding the bar properly, it should look as if you have your arms crossed but with a bar running across them.', 'Barbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Zercher_Squats/0.jpg'),
  ('00000000-0000-0000-0000-000000000871', 'Zottman Curl', 'Arms', 'B', 'Strength', 'Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.', 'Make sure the palms of the hands are facing each other. This will be your starting position.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Zottman_Curl/0.jpg'),
  ('00000000-0000-0000-0000-000000000872', 'Zottman Preacher Curl', 'Arms', 'B', 'Strength', 'Grab a dumbbell in each hand and place your upper arms on top of the preacher bench or the incline bench. The dumbbells should be held at shoulder height and the elbows should be flexed. Hold the dumbbells with the palms of your hands facing down. This will be your starting position.', 'As you breathe in, slowly lower the dumbbells keeping the palms down until your upper arm is extended and your biceps are fully stretched.', 'Dumbbell', 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Zottman_Preacher_Curl/0.jpg');
